def h(val) -> str:
    """HTML escape helper вҖ” йҳІжӯў XSSпјҲеҗ«еј•иҷҹпјү

    дҝ®еҫ© Bug 4пјҡеҠ  quote=TrueпјҢescape е–®еј•иҷҹе’Ңйӣҷеј•иҷҹпјҢйҳІжӯў inline JS/HTML attribute жіЁе…Ҙ
    дҝ®еҫ© Bug 13пјҡз”Ё is None еҲӨж–·пјҢйҒҝе…Қ 0/False иў«з•¶з©әеҖј
    """
    if val is None:
        return ""
    return _html_escape(str(val), quote=True)

