def _calc_age_from_birth(birth_str):
    """еҫһ birth_date з®—е№ҙйҪЎгҖӮж”ҜжҸҙ 086/12/15пјҲж°‘еңӢпјүжҲ– 1985-12-15"""
    if not birth_str:
        return None
    try:
        # ж°‘еңӢе№ҙ 086/12/15
        m = re.match(r"^(\d{2,3})/(\d{1,2})/(\d{1,2})$", birth_str.strip())
        if m:
            year = int(m.group(1))
            if year < 200:
                year += 1911
            return now_tw().year - year
        # иҘҝе…ғ 1985-12-15 жҲ– 1985/12/15
        m = re.match(r"^(\d{4})[-/](\d{1,2})[-/](\d{1,2})$", birth_str.strip())
        if m:
            return now_tw().year - int(m.group(1))
    except Exception:
        pass
    return None


def _calc_vehicle_age(year_str):
    """еҫһи»ҠијӣеҮәе» е№ҙд»Ҫз®—и»ҠйҪЎгҖӮж”ҜжҸҙ 2019гҖҒ108пјҲж°‘еңӢпјүгҖҒ2019/05гҖҒ108/12 зӯүж јејҸ"""
    if not year_str:
        return None
    try:
        s = str(year_str).strip()
        # жҺҘеҸ—гҖҢ2019гҖҚгҖҢ108гҖҚгҖҢ2019/05гҖҚгҖҢ108/12гҖҚзӯүж јејҸгҖҒеҸӘеҸ–еүҚж®өе№ҙд»Ҫ
        m = re.match(r"^(\d+)", s)
        if m:
            year = int(m.group(1))
            if year < 200:
                year += 1911
            return now_tw().year - year
    except Exception:
        pass
    return None


def _customer_best_vehicle_age(customer):
    """жүҫе®ўжҲ¶жңҖе№ҙиј•и»Ҡзҡ„и»ҠйҪЎпјҲеҸ–е№ҙд»ҪжңҖеӨ§гҖҒи»ҠйҪЎжңҖе°Ҹпјү
    дҫҶжәҗе„Әе…Ҳй ҶеәҸпјҡcustomer.vehicle_year вҶ’ debt_list[*].yr вҶ’ unloan_vehicles[*].year
    еӣһеӮі: int и»ҠйҪЎ or NoneпјҲйғҪжІ’еЎ«пјү
    """
    candidates = []
    main_age = _calc_vehicle_age(customer.get("vehicle_year") or "")
    if main_age is not None:
        candidates.append(main_age)
    try:
        debt_list = json.loads(customer.get("debt_list") or "[]")
        for d in debt_list:
            age = _calc_vehicle_age(d.get("yr") or "")
            if age is not None:
                candidates.append(age)
    except Exception:
        pass
    try:
        unloans = json.loads(customer.get("unloan_vehicles") or "[]")
        for u in unloans:
            age = _calc_vehicle_age(u.get("year") or "")
            if age is not None:
                candidates.append(age)
    except Exception:
        pass
    return min(candidates) if candidates else None


