def _is_legit_lender_name(co):
    """е…¬еҸёеҗҚжҳҜдёҚжҳҜеҗҲжі•иіҮиһҚе…¬еҸёпјҲеҗ« LEGIT_LENDERS жҲ–еҗ«гҖҢйҠҖиЎҢгҖҚеӯ—зңјпјү"""
    if not co:
        return False
    for keyword in LEGIT_LENDERS:
        if keyword in co:
            return True
    if "йҠҖиЎҢ" in co:
        return True
    return False


def _is_private_lender_name(co):
    """е…¬еҸёеҗҚжҳҜдёҚжҳҜз§ҒиЁӯе…¬еҸё
    еҲӨж–·иҰҸеүҮпјҲжҘӯеӢҷж•ҷжі•пјүпјҡ
    1. еңЁ PRIVATE_LENDERS жё…е–®иЈЎ вҶ’ з§ҒиЁӯ
    2. еҗҚеӯ—жҳҜз•¶йӢӘ вҶ’ з§ҒиЁӯ
    3. дёҚеңЁеҗҲжі•иіҮиһҚжё…е–®иЈЎгҖҒеҸҲдёҚжҳҜйҠҖиЎҢгҖҒзңӢдёҚеҮәе…¬еҸёжҖ§иіӘ вҶ’ иҰ–зӮәз§ҒиЁӯпјҲдҝқе®ҲеҲӨе®ҡпјү
    """
    if not co:
        return False
    for keyword in PRIVATE_LENDERS:
        if keyword in co:
            return True
    if "з•¶йӢӘ" in co or "з•¶иҲ–" in co:
        return True
    return False


def _customer_has_private_loan(customer):
    """жӘўжҹҘе®ўжҲ¶ debt_list жҳҜеҗҰжңүгҖҢзўәиӘҚз§ҒиЁӯгҖҚзҡ„еӢ•дҝқ
    й»‘еҗҚе–®жЁЎејҸпјҡеҸӘиӘҚ PRIVATE_LENDERS жё…е–®иЈЎзҡ„е…¬еҸёгҖҒе…¶д»–дёҚз®—
    еӣһеӮі True = зўәиӘҚжңүз§ҒиЁӯеӢ•дҝқпјҲиҮӘеӢ•жЁҷгҖҒиһҚиіҮе…¬еҸёдёҚеҸҜйҖҒгҖҒеҸӘиғҪйҖҒ PRIVATE_OK_PLANSпјү
    """
    try:
        debt_list = json.loads(customer.get("debt_list") or "[]") if customer.get("debt_list") else []
        for d in debt_list:
            dy = (d.get("dy", "") or "")
            if "еӢ•дҝқ" not in dy:
                continue
            co = (d.get("co", "") or "")
            if _is_private_lender_name(co):
                return True
    except Exception:
        pass
    return False


