def _customer_unknown_dynbao_companies(customer):
    """жүҫеҮәе®ўжҲ¶ debt_list дёӯгҖҢжІ’иҰӢйҒҺгҖҚзҡ„еӢ•дҝқе…¬еҸёпјҲдёҚеңЁ PRIVATE_LENDERS д№ҹдёҚеңЁ LEGIT_LENDERSгҖҒд№ҹдёҚжҳҜйҠҖиЎҢпјү
    еӣһеӮі list[str] = жІ’иҰӢйҒҺзҡ„е…¬еҸёеҗҚжё…е–®гҖҒз©ә list иЎЁзӨәжІ’жңүжңӘзҹҘе…¬еҸё
    з”ЁйҖ”пјҡUI йЎҜзӨәгҖҢвҡ пёҸ еӢ•дҝқдҫҶиҮӘ XXгҖҒи«Ӣдәәе·ҘзўәиӘҚжҳҜеҗҰз§ҒиЁӯгҖҚ
    """
    unknown = []
    try:
        debt_list = json.loads(customer.get("debt_list") or "[]") if customer.get("debt_list") else []
        for d in debt_list:
            dy = (d.get("dy", "") or "")
            if "еӢ•дҝқ" not in dy:
                continue
            co = (d.get("co", "") or "").strip()
            if not co:
                continue
            # еңЁз§ҒиЁӯжё…е–® вҶ’ и·ійҒҺпјҲе·ІзҹҘпјү
            if _is_private_lender_name(co):
                continue
            # еңЁеҗҲжі•жё…е–®/еҗ«йҠҖиЎҢ вҶ’ и·ійҒҺпјҲе·ІзҹҘпјү
            if _is_legit_lender_name(co):
                continue
            # йғҪдёҚеңЁ вҶ’ жңӘзҹҘгҖҒеҠ йҖІжё…е–®
            if co not in unknown:
                unknown.append(co)
    except Exception:
        pass
    return unknown


def _customer_has_motorcycle_with_space(customer):
    """жӘўжҹҘе®ўжҲ¶жңүжІ’жңүеҸҜз”Ёж©ҹи»ҠпјҲиғҪз”ЁеҒҡж–°иІёжҠөжҠјпјү
    True жўқд»¶пјҲд»»дёҖпјүпјҡ
    1. unloan_vehicles жңүгҖҢж©ҹи»ҠгҖҚ
    2. debt_list дёӯжңүж©ҹи»Ҡдё” sp="жңү"
    3. debt_list дёӯжңүж©ҹи»ҠдҪҶ dy="з„Ў" жҲ–з„ЎеӢ•дҝқ/е…¬и·ҜпјҲйҠҖиЎҢжҹҘдёҚеҲ°гҖҒеҸҜз•¶жІ’иІёж¬ҫпјү
    """
    try:
        uv = json.loads(customer.get("unloan_vehicles") or "[]") if customer.get("unloan_vehicles") else []
        for v in uv:
            if (v.get("type") or "") == "ж©ҹи»Ҡ":
                return True
    except Exception:
        pass
    try:
        debts = json.loads(customer.get("debt_list") or "[]") if customer.get("debt_list") else []
        for d in debts:
            co = (d.get("co", "") or "")
            if "ж©ҹи»Ҡ" not in co: continue
            sp = (d.get("sp", "") or "").strip()
            dy = (d.get("dy", "") or "").strip()
            if sp == "жңү": return True
            if "еӢ•дҝқ" not in dy and "е…¬и·Ҝ" not in dy: return True
    except Exception:
        pass
    return False


