def _customer_motorcycle_loan_remaining(customer):
    """еҫһ debt_list иЁҲз®—ж©ҹи»ҠеүҚиІёеү©йӨҳзёҪйЎҚпјҲе…ғпјү
    иӯҳеҲҘпјҡco еҗ«гҖҢж©ҹи»ҠгҖҚеӯ—зңј + dy еҗ«гҖҢеӢ•дҝқгҖҚжҲ–гҖҢе…¬и·ҜгҖҚпјҲзі»зөұ/йҠҖиЎҢжҹҘеҫ—еҲ°пјү
    йҮҚиҰҒпјҡdy="з„Ў"/з©ә вҶ’ йҠҖиЎҢжҹҘдёҚеҲ°гҖҒеҸҜз•¶жІ’иІёж¬ҫйҖҒд»¶гҖҒдёҚиЁҲе…ҘеүҚиІё
    з”ЁйҖ”пјҡе’ҢиЈ•ж©ҹи»Ҡзӯүж–№жЎҲиҰҒзңӢгҖҢжүЈе®ҢеүҚиІёеҫҢйӮ„еҸҜиІё > N иҗ¬гҖҚ
    """
    import re as _re
    total = 0
    try:
        debt_list = json.loads(customer.get("debt_list") or "[]") if customer.get("debt_list") else []
        for d in debt_list:
            co = (d.get("co", "") or "")
            if "ж©ҹи»Ҡ" not in co:
                continue
            dy = (d.get("dy", "") or "").strip()
            # еҸӘз®—жңүеӢ•дҝқ/е…¬и·ҜиЁӯе®ҡзҡ„пјҲйҠҖиЎҢжҹҘеҫ—еҲ°зҡ„пјү
            # жІ’еӢ•дҝқд№ҹжІ’е…¬и·Ҝ вҶ’ йҠҖиЎҢжҹҘдёҚеҲ°гҖҒеҸҜз•¶жІ’иІёж¬ҫйҖҒд»¶
            if "еӢ•дҝқ" not in dy and "е…¬и·Ҝ" not in dy:
                continue
            re_str = (d.get("re", "") or "").strip()
            cleaned = _re.sub(r'[^\d]', '', re_str)
            if cleaned:
                total += int(cleaned)
    except Exception:
        pass
    return total


