def _customer_has_bank_loan(customer):
    """жӘўжҹҘе®ўжҲ¶ debt_list жҳҜеҗҰжңүд»»дҪ•йҠҖиЎҢзҡ„иІ еӮөзҙҖйҢ„
    еҲӨе®ҡпјҡdebt_list дёӯ co ж¬„дҪҚеҗ«гҖҢйҠҖиЎҢгҖҚеӯ—зңј
    з”ЁйҖ”пјҡз¬¬дёҖдҝЎиІёиҰҒжұӮгҖҢиҝ‘дёҖеҖӢжңҲе…§йҠҖиЎҢдҝЎиІёж’Ҙж¬ҫгҖҚгҖҒжІ’йҠҖиЎҢиІёж¬ҫзҙҖйҢ„ вҶ’ дёҚиғҪйҖҒ
    """
    try:
        debt_list = json.loads(customer.get("debt_list") or "[]") if customer.get("debt_list") else []
        for d in debt_list:
            co = (d.get("co", "") or "")
            if "йҠҖиЎҢ" in co:
                return True
    except Exception:
        pass
    return False


def _customer_has_known_contact(customer):
    """жӘўжҹҘе®ўжҲ¶иҒҜзөЎдәәжҳҜеҗҰиҮіе°‘жңү 1 дҪҚгҖҢзҹҘжғ…гҖҚ
    еҲӨе®ҡпјҡcontact1_known жҲ– contact2_known еҗ«гҖҢзҹҘжғ…гҖҚгҖҒдёҚеҗ«гҖҢдҝқеҜҶгҖҚгҖҢдёҚзҹҘгҖҚ
    """
    try:
        for k in ["contact1_known", "contact2_known"]:
            v = (customer.get(k, "") or "").strip()
            if not v:
                continue
            if ("дёҚзҹҘ" in v) or ("дҝқеҜҶ" in v):
                continue
            if "зҹҘжғ…" in v or v in ["жҳҜ", "жңү"]:
                return True
    except Exception:
        pass
    return False


def _customer_has_house_private(customer):
    """жӘўжҹҘе®ўжҲ¶жҳҜеҗҰжңүгҖҢжҲҝеұӢз§ҒиЁӯгҖҚ
    еҲӨе®ҡпјҡeval_alert еҗ«гҖҢжңүгҖҚ+ eval_property еҗ«гҖҢдёҚеӢ•з”ўгҖҚ
    пјҲeval_alert гҖҢз•¶йӢӘ/з§ҒиЁӯгҖҚжЁҷиЁҳеңЁгҖҢжңүгҖҚгҖҒдё”еҗҚдёӢжңүдёҚеӢ•з”ўпјү
    """
    try:
        alert = (customer.get("eval_alert", "") or "").strip()
        prop = (customer.get("eval_property", "") or "").strip()
        return ("жңү" in alert) and ("дёҚеӢ•з”ў" in prop)
    except Exception:
        return False


