def _customer_has_road_setting_no_dynbao(customer):
    """жӘўжҹҘе®ўжҲ¶жңүгҖҢе…¬и·ҜиЁӯе®ҡгҖҚдҪҶз„ЎгҖҢеӢ•дҝқиЁӯе®ҡгҖҚ
    жҘӯеӢҷжғ…еўғпјҡе®ўжҲ¶еүӣиІёж¬ҫпјҲеӢ•дҝқйӮ„жІ’зҷ»пјүжҲ– з•¶йӢӘеҖҹж¬ҫпјҲдёҚжңғзҷ»еӢ•дҝқпјү
    иҷ•зҗҶпјҡдәәе·Ҙе•Ҹжё…жҘҡгҖҒиӢҘжҳҜз•¶йӢӘз§ҒиЁӯжҲ–еүӣиІёж¬ҫ вҶ’ дёҚиғҪйҖҒйҖҷеҸ°и»ҠгҖҒдҪҶе…¶д»–ж–№жЎҲеҸҜйҖҒ
    иЁ»пјҡе…¬и·ҜиЁӯе®ҡжҹҘи©ўйңҖи»ҠзүҢ+иә«еҲҶиӯүгҖҒз„Ўжі•зңӢе…Ёи»ҠгҖҒе№іеёёдёҚеҪұйҹҝеҲӨж–·йӮҸијҜ
    """
    try:
        debt_list = json.loads(customer.get("debt_list") or "[]") if customer.get("debt_list") else []
        has_road = False
        has_dynbao = False
        for d in debt_list:
            dy = (d.get("dy", "") or "")
            if "е…¬и·Ҝ" in dy:
                has_road = True
            if "еӢ•дҝқ" in dy:
                has_dynbao = True
        return has_road and not has_dynbao
    except Exception:
        return False


def _is_2nd_kin(rel_text):
    """еҲӨеҲҘй—ңдҝӮж–Үеӯ—жҳҜеҗҰзӮәдәҢзӯүиҰӘеұ¬
    дәҢзӯүиҰӘеұ¬пјҡзҲ¶жҜҚгҖҒй…ҚеҒ¶гҖҒеӯҗеҘігҖҒе…„ејҹе§җеҰ№гҖҒзҘ–зҲ¶жҜҚгҖҒеӯ«еӯҗеҘі
    """
    if not rel_text:
        return False
    t = rel_text.strip()
    if not t:
        return False
    # дәҢзӯүиҰӘй—ңйҚөеӯ—пјҲж¶өи“ӢеёёиҰӢеҜ«жі•пјү
    kin_keywords = [
        # зҲ¶жҜҚ
        "зҲ¶", "жҜҚ", "зҲё", "еӘҪ", "йӣҷиҰӘ",
        # й…ҚеҒ¶
        "еӨ«", "еҰ»", "иҖҒе…¬", "иҖҒе©Ҷ", "еӨӘеӨӘ", "е…Ҳз”ҹ", "й…ҚеҒ¶", "дёҲеӨ«", "еҰ»еӯҗ",
        # еӯҗеҘі
        "е…’", "еҘі", "еӯҗ", "еҘіе…’", "е…’еӯҗ", "еӯҗеҘі",
        # е…„ејҹе§җеҰ№
        "е…„", "ејҹ", "е§Ҡ", "е§җ", "еҰ№", "е…„ејҹ", "е§ҠеҰ№", "е§җеҰ№",
        # зҘ–зҲ¶жҜҚ
        "зҘ–зҲ¶", "зҘ–жҜҚ", "зҲәзҲә", "еҘ¶еҘ¶", "еӨ–е…¬", "еӨ–е©Ҷ", "еӨ–зҘ–зҲ¶", "еӨ–зҘ–жҜҚ",
        # еӯ«еӯҗеҘі
        "еӯ«",
    ]
    # з”·еҘіжңӢеҸӢ/жңӢеҸӢ/еҗҢдәӢ дёҚз®—дәҢзӯүиҰӘ
    not_kin_kw = ["з”·еҸӢ", "еҘіеҸӢ", "жңӢеҸӢ", "еҗҢдәӢ", "еҗҢеӯё", "й„°еұ…", "иӘҚиӯҳ"]
    for kw in not_kin_kw:
        if kw in t:
            return False
    for kw in kin_keywords:
        if kw in t:
            return True
    return False


def _21group_remaining(customer):
    """иЁҲз®—е®ўжҲ¶ debt_list иЈЎ 21 й«”зі»пјҲйә»еҗүPAY/21/еҲҶиІқ/жЁӮеҲҶжңҹ/еҲҶжңҹи¶Ј/ж…ўй»һд»ҳпјүеү©йӨҳйҮ‘йЎҚеҠ зёҪ
    еӣһеӮіпјҡ(зёҪйҮ‘йЎҚе…ғ, е°ҚжҮүе» е•ҶеҲ—иЎЁ)
    """
    group_keywords = ["йә»еҗү", "21", "дәҢдёҖ", "е»ҝдёҖ", "еҲҶиІқ", "еҲҶе”„", "жЁӮеҲҶжңҹ", "еҲҶжңҹи¶Ј", "ж…ўй»һд»ҳ"]
    total = 0.0
    matched = []
    try:
        debt_list = json.loads(customer.get("debt_list") or "[]") if customer.get("debt_list") else []
        for d in debt_list:
            co = (d.get("co", "") or "")
            if not any(kw in co for kw in group_keywords):
                continue
            # еү©йӨҳйҮ‘йЎҚпјҡгҖҢreгҖҚж¬„дҪҚжҲ–еҫһ mo*pe-mo*pa з®—
            try:
                re_str = (d.get("re", "") or "").replace("$", "").replace(",", "").strip()
                if re_str and re_str.isdigit():
                    total += float(re_str)
                    matched.append(co)
                    continue
                mo = float(d.get("mo", "") or 0)
                pe_pa = (d.get("pe", "") or "").split("/")
                pe = float(pe_pa[0]) if pe_pa[0] else 0
                pa = float(pe_pa[1]) if len(pe_pa) > 1 and pe_pa[1] else 0
                rem = mo * (pe - pa)
                if rem > 0:
                    total += rem
                    matched.append(co)
            except Exception:
                pass
    except Exception:
        pass
    return total, matched


def _customer_has_car_loan(customer):
    """жӘўжҹҘ debt_list иЈЎжҳҜеҗҰжңүжұҪи»ҠиІёж¬ҫпјҲdy еҗ«гҖҢеӢ•дҝқгҖҚжҲ–гҖҢе…¬и·ҜгҖҚ+ е•Ҷе®¶еҗҚеҗ«гҖҢи»ҠгҖҚпјү
    жҲ–еҫһ dy еӢ•дҝқжЁҷиЁҳз°ЎеҢ–еҲӨеҲҘпјҲи»ҠиІёйҖҡеёёжңүеӢ•дҝқпјү
    """
    try:
        debt_list = json.loads(customer.get("debt_list") or "[]") if customer.get("debt_list") else []
        for d in debt_list:
            dy = (d.get("dy", "") or "")
            if "еӢ•дҝқ" in dy or "е…¬и·Ҝ" in dy:
                return True
    except Exception:
        pass
    return False


def _check_creditcard_status(customer):
    """жӘўжҹҘе®ўжҲ¶еҗҚдёӢдҝЎз”ЁеҚЎзӢҖжіҒ
    еӣһеӮі (status, detail)
    - "good": жңүдҝЎз”ЁеҚЎгҖҒз„Ўе•ҸйЎҢпјҲеҸҜдҪңиІЎеҠӣпјү
    - "bad": жңүе•ҸйЎҢпјҲеҚЎеҫӘ/йҒІз№і/еј·еҲ¶еҒңеҚЎ/еҚ”е•ҶпјүвҶ’ зҙ…з·ҡ
    - "none": жІ’еЎ«жҲ–жІ’еҚЎ
    """
    text = (customer.get("eval_credit_card", "") or "").strip()
    if not text:
        return ("none", "жңӘеЎ«")
    # зҙ…з·ҡй—ңйҚөеӯ—пјҡиЎЁзӨәдҝЎз”Ёжңүе•ҸйЎҢ
    bad_keywords = ["еҚЎеҫӘ", "еҫӘз’°", "йҒІз№і", "еј·еҲ¶еҒңеҚЎ", "еҒңеҚЎ", "еҚ”е•Ҷ", "е‘Ҷеёі"]
    for kw in bad_keywords:
        if kw in text:
            return ("bad", f"жңүгҖҢ{kw}гҖҚзӢҖжіҒпјҡ{text}")
    # гҖҢз„ЎгҖҚгҖҢжІ’жңүгҖҚиЎЁзӨәжІ’еҚЎ
    if text in ("з„Ў", "жІ’жңү", "0", "з„ЎеҚЎ"):
        return ("none", "жІ’дҝЎз”ЁеҚЎ")
    # е…¶д»–ж–Үеӯ—пјҲйҠҖиЎҢеҗҚзӯүпјүвҶ’ иҰ–зӮәжңүеҚЎдё”з„Ўе•ҸйЎҢ
    return ("good", text)


def _ensure_4tuple(fn):
    """иЈқйЈҫеҷЁпјҡжҠҠ _check_rule зҡ„ 3-tuple return иЈңжҲҗ 4-tupleгҖҒз¬¬ 4 й …жҳҜ sub listпјҲй җиЁӯз©әпјүгҖӮ
    Oneof иҮӘе·ұеӣһ 4-tupleгҖҒе…¶д»– return дёҚз”Ёж”№гҖҒз”ұжӯӨиЈңгҖӮ"""
    def wrapper(*args, **kwargs):
        result = fn(*args, **kwargs)
        if isinstance(result, tuple) and len(result) == 3:
            return result + ([],)
        return result
    return wrapper


@_ensure_4tuple
def _check_rule(rule, customer):
    """е–®жўқиҰҸеүҮжҜ”е°ҚгҖҒеӣһ (status, label, actual_str, sub) 4-tuple
    status: 'pass' / 'fail' / 'manual' / 'unknown'
    sub: oneof жүҚжңүеҖјпјҲlist of {status, label, actual} dictпјүгҖҒе…¶д»–з©ә list"""
    rt = rule.get("type", "simple")
    label = rule.get("label", "")
    if rt == "manual":
        return ("manual", label + (f" вҖ” {rule['hint']}" if rule.get("hint") else ""), "йңҖдәәе·ҘзўәиӘҚ")
    if rt == "oneof":
        sub_results = []
        any_pass = False
        any_manual = False  # зңҹеҜҰгҖҢauto вң“ + manual_checkгҖҚжүҚз®—
        any_unknown = False  # жІ’еЎ«иіҮж–ҷ вҶ’ еҚҮзҙҡжҲҗ manualпјҲжҘӯеӢҷжІ’еЎ« вү  е®ўжҲ¶жІ’жңүпјү
        for opt in rule.get("options", []):
            s, l, a, _ = _check_rule(opt, customer)
            sub_results.append({"status": s, "label": l, "actual": a})
            if s == "pass":
                any_pass = True
                break
            elif s == "manual":
                any_manual = True
            elif s == "unknown":
                any_unknown = True
        if any_pass:
            return ("pass", label + " вҖ” иҮіе°‘дёҖй …з¬ҰеҗҲ", "", sub_results)
        if any_manual:
            return ("manual", label + " вҖ” иҮіе°‘дёҖй …еҸҜиғҪз¬ҰеҗҲпјҲйңҖдәәе·ҘзўәиӘҚпјү", "", sub_results)
        if any_unknown:
            return ("manual", label + " вҖ” жңүжңӘеЎ«иіҮж–ҷгҖҒйңҖдәәе·ҘзўәиӘҚ", "", sub_results)
        return ("fail", label + " вҖ” еҗ„й …йғҪдёҚз¬ҰеҗҲ", "", sub_results)
    if rt == "simple":
        field = rule.get("field", "")
        op = rule.get("op", "")
        value = rule.get("value")
        # зү№ж®Ҡ opпјҡhas_dynbao / not_has_dynbaoпјҲдёҚйңҖиҰҒ fieldгҖҒзӣҙжҺҘжӘўжҹҘ debt_listпјү
        if op in ("has_dynbao", "not_has_dynbao"):
            has = _customer_has_dynbao(customer)
            ok = has if op == "has_dynbao" else (not has)
            actual_str = "жңүеӢ•дҝқ" if has else "з„ЎеӢ•дҝқ"
            return ("pass" if ok else "fail", label, actual_str)
        # зү№ж®Ҡ opпјҡ21 й«”зі»еү©йӨҳйЎҚеәҰпјҲ< value е…ғ = passпјү
        if op == "group21_remain_lt":
            total, matched = _21group_remaining(customer)
            if total < float(value):
                return ("pass", label, f"21 й«”зі»еү©йӨҳ {int(total):,} е…ғпјҲ{', '.join(matched) or 'з„Ў'}пјү")
            return ("fail", label, f"21 й«”зі»еү©йӨҳ {int(total):,} е…ғпјҲе·ІйҒ” {int(value):,} дёҠйҷҗпјү")
        # зү№ж®Ҡ opпјҡе®ўжҲ¶жңүжұҪи»ҠиІёж¬ҫ
        if op == "has_car_loan":
            ok = _customer_has_car_loan(customer)
            return ("pass" if ok else "fail", label, "жңүи»ҠиІё" if ok else "з„Ўи»ҠиІё")
        # зү№ж®Ҡ opпјҡе®ўжҲ¶жңүйҠҖиЎҢиІёж¬ҫпјҲdebt_list жңүйҠҖиЎҢеӯ—зңјпјү
        if op == "has_bank_loan":
            ok = _customer_has_bank_loan(customer)
            return ("pass" if ok else "fail", label, "жңүйҠҖиЎҢиІёж¬ҫ" if ok else "з„ЎйҠҖиЎҢиІёж¬ҫзҙҖйҢ„")
        # зү№ж®Ҡ opпјҡе®ўжҲ¶жңүжұҪи»Ҡ
        if op == "has_car":
            ok = _customer_has_car(customer)
            return ("pass" if ok else "fail", label, "жңүжұҪи»Ҡ" if ok else "з„ЎжұҪи»Ҡ")
        # зү№ж®Ҡ opпјҡе®ўжҲ¶жңүйҮҚж©ҹ
        if op == "has_heavy_bike":
            ok = _customer_has_heavy_bike(customer)
            return ("pass" if ok else "fail", label, "жңүйҮҚж©ҹ" if ok else "з„ЎйҮҚж©ҹ")
        # зү№ж®Ҡ opпјҡж©ҹи»ҠеүҚиІёеү©йӨҳ < value е…ғпјҲз”Ёж–је’ҢиЈ•ж©ҹи»ҠгҖҢжүЈе®ҢеүҚиІёйӮ„еҸҜиІё>10иҗ¬гҖҚпјү
        if op == "motorcycle_loan_remaining_lt":
            remain = _customer_motorcycle_loan_remaining(customer)
            threshold = float(value)
            if remain < threshold:
                return ("pass", label, f"ж©ҹи»ҠеүҚиІёеү© {remain:,} е…ғ")
            return ("fail", label, f"ж©ҹи»ҠеүҚиІёеү© {remain:,} е…ғпјҲвүҘ {int(threshold):,}гҖҒжүЈе®ҢеүҚиІёдёҚеӨ  10 иҗ¬пјү")
        # иӯҰзӨәжҲ¶дёҚеҒҡпјҲeval_alert_warning="жҳҜ" вҶ’ failпјү
        if op == "no_warning_account":
            if _customer_is_warning_account(customer):
                return ("fail", label, "е®ўжҲ¶зӮәиӯҰзӨәжҲ¶")
            return ("pass", label, "йқһиӯҰзӨәжҲ¶")
        # з„Ўй…’й§•/жҜ’й§•зҙҖйҢ„
        if op == "no_drunk_drug":
            if _customer_has_drunk_drug_record(customer):
                return ("fail", label, "жі•еӯё/еӮҷиЁ»еҗ«й…’й§•жҲ–жҜ’й§•зҙҖйҢ„")
            return ("pass", label, "з„Ўй…’й§•/жҜ’й§•зҙҖйҢ„")
        # иҝ‘жңҲйҠҖиЎҢж’Ҙж¬ҫпјҲйҠҖиЎҢиІёж¬ҫ pa вүӨ 1пјү
        if op == "recent_bank_loan":
            if _customer_recent_bank_loan(customer):
                return ("pass", label, "жңүиҝ‘жңҲйҠҖиЎҢж’Ҙж¬ҫпјҲpaвүӨ1пјү")
            return ("fail", label, "з„Ўиҝ‘жңҲйҠҖиЎҢж’Ҙж¬ҫзҙҖйҢ„")
        # иҝ‘жңҲеҫһжҢҮе®ҡе…¬еҸёж’Ҙж¬ҫпјҲpa вүӨ 1пјүвҖ” value=е…¬еҸёжё…е–®
        if op == "recent_loan_from":
            cos = value if isinstance(value, list) else [value]
            if _customer_recent_loan_from(customer, cos):
                return ("pass", label, f"жңүиҝ‘жңҲеҫһ {'/'.join(cos)} ж’Ҙж¬ҫ")
            return ("fail", label, f"з„Ўиҝ‘жңҲеҫһ {'/'.join(cos)} ж’Ҙж¬ҫ")
        # ж©ҹи»Ҡжңүз©әй–“пјҲdebt_list ж©ҹи»Ҡ sp=жңү or з„ЎеӢ•дҝқ / unloan_vehicles жңүж©ҹи»Ҡпјү
        if op == "motorcycle_has_space":
            if _customer_has_motorcycle_with_space(customer):
                return ("pass", label, "еҗҚдёӢжңүеҸҜз”Ёж©ҹи»Ҡ")
            return ("fail", label, "еҗҚдёӢж©ҹи»Ҡж»ҝиІё/з„Ўз©әй–“гҖҒдёҚиғҪйҖҒж©ҹи»ҠйЎһ")
        # жңүдёҚеӢ•з”ўпјҡeval_property еҗ«гҖҢдёҚеӢ•з”ўгҖҚ OR еұ…дҪҸзӢҖжіҒгҖҢиҮӘжңүгҖҚ
        if op == "has_real_estate":
            prop = (customer.get("eval_property", "") or "").strip()
            live = (customer.get("live_status", "") or "").strip()
            alert = (customer.get("eval_alert", "") or "").strip()
            # з§ҒиЁӯз•¶йӢӘжҺ’йҷӨ
            if "жңү" in alert:
                return ("fail", label, f"з•¶йӢӘз§ҒиЁӯ=жңүгҖҒдёҚз®—дёҚеӢ•з”ў")
            if "дёҚеӢ•з”ў" in prop:
                return ("pass", label, f"eval_property: {prop}")
            if live == "иҮӘжңү":
                return ("pass", label, "еұ…дҪҸзӢҖжіҒпјҡиҮӘжңүпјҲиҰ–зӮәжңүдёҚеӢ•з”ўпјү")
            return ("fail", label, f"eval_property={prop or 'жңӘеЎ«'}гҖҒеұ…дҪҸ={live or 'жңӘеЎ«'}")
        # жұҪи»Ҡжңүз©әй–“
        if op == "car_has_space":
            if _customer_has_car_with_space(customer):
                return ("pass", label, "еҗҚдёӢжңүеҸҜз”ЁжұҪи»Ҡ")
            return ("fail", label, "еҗҚдёӢжұҪи»Ҡж»ҝиІё/з„Ўз©әй–“гҖҒдёҚиғҪйҖҒжұҪи»ҠйЎһ")
        # 21 й«”зі»ж—ўжңүе®ўжҲ¶з№і N жңҹ+
        if op == "group21_paid_ge":
            paid = _customer_21group_max_paid(customer)
            threshold = int(value)
            if paid >= threshold:
                return ("pass", label, f"21 й«”зі»жңҖеӨ§з№і {paid} жңҹ")
            return ("fail", label, f"21 й«”зі»жңҖеӨ§з№і {paid} жңҹпјҲ< {threshold}пјү")
        # дәһеӨӘд»Је„ҹе°ҲжЎҲпјҡеӢ•дҝқеүҚиІёдҫҶиҮӘдёӯз§ҹ/еҗҲиҝӘ/е’ҢжҪӨ/иЈ•иһҚ
        if op == "dynbao_from_apt_legit":
            if _customer_dynbao_from_apt_legit(customer):
                return ("pass", label, "еӢ•дҝқеүҚиІёдҫҶиҮӘеҗҲжі•иіҮиһҚ")
            # жІ’еӢ•дҝқ = дёҚеңЁд»Је„ҹжғ…еўғгҖҒдёҚж“Ӣ
            if not _customer_has_dynbao(customer):
                return ("pass", label, "з„ЎеӢ•дҝқпјҲйқһд»Је„ҹжғ…еўғпјү")
            return ("fail", label, "еӢ•дҝқеүҚиІёйқһдёӯз§ҹ/е’ҢжҪӨ/иЈ•иһҚгҖҒдёҚиғҪд»Је„ҹ")
        # жңүдёҚеӢ•з”ў + з„ЎжҲҝеұӢз§ҒиЁӯ
        if op == "has_property_no_private":
            if _customer_has_property_no_private(customer):
                return ("pass", label, "жңүдёҚеӢ•з”ўдё”з„Ўз§ҒиЁӯ")
            prop = (customer.get("eval_property", "") or "").strip()
            hp = (customer.get("eval_house_private", "") or "").strip()
            if "дёҚеӢ•з”ў" not in prop:
                return ("fail", label, "жңӘжҢҒжңүдёҚеӢ•з”ў")
            return ("fail", label, f"дёҚеӢ•з”ўжңүз§ҒиЁӯпјҲ{hp}пјү")
        # зү№ж®Ҡ opпјҡиҒҜзөЎдәәиҮіе°‘ 1 дҪҚзҹҘжғ…
        if op == "any_contact_known":
            ok = _customer_has_known_contact(customer)
            c1 = (customer.get("contact1_known", "") or "").strip() or "жңӘеЎ«"
            c2 = (customer.get("contact2_known", "") or "").strip() or "жңӘеЎ«"
            return ("pass" if ok else "fail", label, f"иҒҜзөЎдәә1пјҡ{c1}гҖҒиҒҜзөЎдәә2пјҡ{c2}")
        # зү№ж®Ҡ opпјҡиҒҜзөЎдәә 1 / иҒҜзөЎдәә 2 жҳҜеҗҰзӮәдәҢзӯүиҰӘ
        if op in ("contact1_2nd_kin", "contact2_2nd_kin", "any_contact_2nd_kin"):
            c1 = (customer.get("contact1_relation", "") or "").strip()
            c2 = (customer.get("contact2_relation", "") or "").strip()
            c1_ok = _is_2nd_kin(c1)
            c2_ok = _is_2nd_kin(c2)
            if op == "contact1_2nd_kin":
                ok = c1_ok
                actual_str = f"иҒҜзөЎдәә1пјҡ{c1 or 'жңӘеЎ«'}"
            elif op == "contact2_2nd_kin":
                ok = c2_ok
                actual_str = f"иҒҜзөЎдәә2пјҡ{c2 or 'жңӘеЎ«'}"
            else:  # any_contact_2nd_kin
                ok = c1_ok or c2_ok
                actual_str = f"иҒҜзөЎдәә1пјҡ{c1 or 'жңӘеЎ«'}гҖҒиҒҜзөЎдәә2пјҡ{c2 or 'жңӘеЎ«'}"
            return ("pass" if ok else "fail", label, actual_str)
        # зү№ж®Ҡ opпјҡзёҪжҳҜйҖҡйҒҺпјҲиЎЁйҒ”гҖҢз„ЎйҷҗеҲ¶гҖҚгҖҒзҙ”жЁҷзұӨз”ЁгҖҒдёҚжү“ manualпјү
        if op == "always_pass":
            return ("pass", label, "")
        # зү№ж®Ҡ opпјҡиӯҰзӨәжҲ¶иҷ•зҗҶпјҲиӯҰзӨәжҲ¶ вҶ’ manual жҸҗзӨәж’Ҙж¬ҫж–№ејҸгҖҒйқһиӯҰзӨәжҲ¶ вҶ’ passгҖҒжңӘеЎ« вҶ’ unknownпјү
        if op == "alert_warning_handler":
            aw = (customer.get("eval_alert_warning", "") or "").strip()
            if aw == "жҳҜ":
                method = (customer.get("eval_alert_warning_method", "") or "").strip()
                if method:
                    return ("manual", label + f"пјҲиӯҰзӨәжҲ¶гҖҒж’Ҙж¬ҫж–№ејҸпјҡ{method}пјү", "жҳҜ")
                return ("manual", label + "пјҲиӯҰзӨәжҲ¶гҖҒйңҖзўәиӘҚж’Ҙж¬ҫж–№ејҸ = ж’ҘдәҢзӯүиҰӘпјү", "жҳҜ")
            elif aw == "еҗҰ":
                return ("pass", label + "пјҲйқһиӯҰзӨәжҲ¶пјү", "еҗҰ")
            else:
                return ("unknown", label, "жңӘеЎ«иӯҰзӨәжҲ¶ж¬„дҪҚ")
        # зү№ж®Ҡ opпјҡдҝЎз”ЁеҚЎзӢҖжіҒпјҲзӣҙжҺҘеҫһ eval_credit_card ж–Үеӯ—еҲӨпјү
        if op == "creditcard_good":
            status, detail = _check_creditcard_status(customer)
            if status == "good":
                return ("pass", label, detail)
            elif status == "bad":
                return ("fail", label, detail)
            else:
                return ("unknown", label, "жңӘеЎ«жҲ–з„ЎеҚЎ")
        if op == "creditcard_no_bad":
            # еҸӘиҰҒз„Ўзҙ…з·ҡпјҲеҚЎеҫӘ/йҒІз№і/еҒңеҚЎ/еҚ”е•Ҷпјүе°ұ passгҖҒеҸҜд»Ҙз„ЎеҚЎ
            status, detail = _check_creditcard_status(customer)
            if status == "bad":
                return ("fail", label, detail)
            return ("pass", label, detail if status == "good" else "з„Ўзҙ…з·ҡ")
        # еҸ–еҖј
        if field == "age":
            actual = _calc_age_from_birth(customer.get("birth_date", "") or "")
        elif field == "vehicle_year":
            # е„Әе…Ҳз”Ё customer.vehicle_yearгҖҒеҗҰеүҮ fallback еҲ° debt_list / unloan_vehicles еҸ–жңҖе№ҙиј•и»Ҡ
            actual = _customer_best_vehicle_age(customer)
        else:
            actual = (customer.get(field, "") or "").strip()
        # з©әеҖјиҷ•зҗҶпјҡж•ёеӯ—йЎһжҜ”е°ҚпјҲ<= / >=пјүиҰ–зӮә 0гҖҒnot_contains з©әзҷҪ = жІ’йҖҒйҒҺ = passгҖҒе…¶д»–йЎһеһӢиҰ–зӮәгҖҢиіҮж–ҷдёҚйҪҠгҖҚ
        if actual is None or actual == "":
            if op in ("<=", ">="):
                actual = "0"
            elif op == "not_contains":
                # з©әзҷҪ = жІ’йҖҒйҒҺд»»дҪ•е®¶ = not_contains еҝ… passпјҲдҫӢпјҡгҖҢиҝ‘дёүжңҲжІ’йҖҒйҒҺдәһеӨӘгҖҚжңӘеЎ« = жІ’йҖҒйҒҺпјү
                return ("pass", label, "жңӘйҖҒйҒҺ")
            else:
                return ("unknown", label, "иіҮж–ҷдёҚйҪҠ")
        # жҜ”е°Қ
        try:
            if op == "between":
                lo, hi = value
                if lo <= int(actual) <= hi:
                    ok = True
                else:
                    ok = False
                actual_str = f"{actual}"
            elif op == "tw_id":
                ok = bool(re.match(r"^[A-Z][12]\d{8}$", str(actual)))
                actual_str = str(actual)
            elif op == "year_age_le":
                if int(actual) <= int(value):
                    ok = True
                else:
                    ok = False
                actual_str = f"и»ҠйҪЎ {actual} е№ҙ"
            elif op == "in":
                ok = actual in value
                actual_str = str(actual)
            elif op == "contains":
                ok = value in str(actual)
                actual_str = str(actual)
                # жҺ’йҷӨжўқд»¶
                if ok and rule.get("exclude_field"):
                    ex_actual = (customer.get(rule["exclude_field"], "") or "").strip()
                    if rule.get("exclude_value") in ex_actual:
                        ok = False
                        actual_str += f"пјҲдҪҶ {rule['exclude_field']}={ex_actual}пјү"
            elif op == "not_contains":
                # value еҸҜд»ҘжҳҜеӯ—дёІжҲ–еӯ—дёІеҲ—иЎЁпјҲд»»дёҖеҗ«еҲ°е°ұ failпјү
                if isinstance(value, list):
                    found = next((v for v in value if v in str(actual)), None)
                    ok = found is None
                    actual_str = f"{actual}пјҲеҗ«гҖҢ{found}гҖҚпјү" if found else (str(actual) or "жңӘеЎ«")
                else:
                    ok = value not in str(actual)
                    actual_str = str(actual) or "жңӘеЎ«"
            elif op == "=":
                ok = str(actual) == str(value)
                actual_str = str(actual)
            elif op == ">=":
                # ж•ёеӯ—жҜ”ијғгҖҒз©әеҖјиҰ–зӮә 0
                try:
                    ok = float(actual or 0) >= float(value)
                except Exception:
                    ok = False
                actual_str = str(actual)
            elif op == "<=":
                # ж•ёеӯ—жҜ”ијғгҖҒз©әеҖјиҰ–зӮә 0
                try:
                    ok = float(actual or 0) <= float(value)
                except Exception:
                    ok = False
                actual_str = str(actual or "0")
            else:
                return ("unknown", label, f"жңӘзҹҘ op: {op}")
        except Exception as e:
            return ("unknown", label, f"жҜ”е°ҚеӨұж•—пјҡ{e}")
        # еҠ еҲҶжҸҗзӨәпјҡmanual_check иЎЁзӨәиҮӘеӢ•жҜ”е°ҚйҖҡйҒҺгҖҒдҪҶд»ҚйңҖдәәе·ҘзўәиӘҚ
        if ok and rule.get("manual_check"):
            return ("manual", label + f"пјҲиҮӘеӢ• вң“гҖҒ{rule['manual_check']}пјү", actual_str)
        return ("pass" if ok else "fail", label, actual_str)
    return ("unknown", label, "жңӘзҹҘиҰҸеүҮйЎһеһӢ")


def evaluate_case(customer):
    """и·‘жүҖжңүиҰҸеүҮгҖҒеӣһжҺ’еәҸеҘҪзҡ„ж–№жЎҲжё…е–® + з§ҒиЁӯзӢҖж…Ӣ

    еӣһеӮіж јејҸпјҡ{
      "results": [...],            # жҜҸе®¶ж–№жЎҲзҡ„еҲӨеҲҘзөҗжһң
      "private_status": "confirmed"|None,  # confirmed = зўәиӘҚз§ҒиЁӯгҖҒNone = жІ’е•ҸйЎҢ
      "unknown_dynbao": [...],     # жІ’иҰӢйҒҺзҡ„еӢ•дҝқе…¬еҸёжё…е–®пјҲиҰҒдәәе·ҘзўәиӘҚпјү
      "house_private": True/False, # жҲҝеұӢз§ҒиЁӯжЁҷиЁҳпјҲйҖҒиһҚиіҮ/йҠҖиЎҢи©ұиЎ“жҸҗзӨәпјү
    }
    """
    # еҒөжё¬з§ҒиЁӯзӢҖж…Ӣ
    has_private = _customer_has_private_loan(customer)
    unknown_dynbao = _customer_unknown_dynbao_companies(customer)
    has_house_private = _customer_has_house_private(customer)
    # ж©ҹи»ҠеүҚиІёеү©йӨҳпјҲе–®дҪҚпјҡе…ғпјүвҖ” е…Ёж©ҹи»Ҡж–№жЎҲеҘ—пјҡmax_amount - еүҚиІё < 10иҗ¬ вҶ’ иҮӘеӢ• fail
    moto_remain = _customer_motorcycle_loan_remaining(customer)

    results = []
    for plan in PLAN_ELIGIBILITY_RULES:
        checks = []
        has_simple_fail = False  # зЎ¬жўқд»¶еӨұж•—пјҲе№ҙйҪЎ/иә«еҲҶиӯү/жңүжұҪи»Ҡ зӯүпјү
        has_oneof_fail = False   # ж“ҮдёҖжўқд»¶еӨұж•—
        manual_count = 0
        for rule in plan["rules"]:
            status, label, actual, sub = _check_rule(rule, customer)
            checks.append({"status": status, "label": label, "actual": actual, "sub": sub})
            if status == "fail":
                rt = rule.get("type", "")
                if rt == "simple":
                    has_simple_fail = True
                elif rt == "oneof":
                    has_oneof_fail = True
                else:
                    has_simple_fail = True  # е…¶д»–йЎһеһӢ fail иҰ–зӮәзЎ¬жўқд»¶
            elif status in ("manual", "unknown"):
                manual_count += 1

        # з§ҒиЁӯиҷ•зҗҶпјҡзўәиӘҚз§ҒиЁӯ + дёҚеңЁ PRIVATE_OK_PLANS вҶ’ еј·еҲ¶жЁҷ fail
        private_blocked = False
        if has_private and plan["company"] not in PRIVATE_OK_PLANS:
            private_blocked = True
            checks.append({
                "status": "fail",
                "label": "рҹҡ« е®ўжҲ¶жңүзўәиӘҚз§ҒиЁӯеӢ•дҝқгҖҒжң¬ж–№жЎҲдёҚеҸҜйҖҒ",
                "actual": "з§ҒиЁӯеӢ•дҝқ",
            })
            has_simple_fail = True

        # ж©ҹи»ҠеүҚиІёйЎҚеәҰжӘўжҹҘпјҲйҒ©з”ЁжүҖжңүеҗҚзЁұеҗ«гҖҢж©ҹи»ҠгҖҚзҡ„ж–№жЎҲпјү
        # иҰҸеүҮпјҡmax_amount - ж©ҹи»ҠеүҚиІёеү©йӨҳ еҝ…й Ҳ > 10 иҗ¬пјҲжҘӯеӢҷйҗөеүҮпјү
        if moto_remain > 0 and "ж©ҹи»Ҡ" in plan["company"]:
            margin = plan["max_amount"] * 10000 - moto_remain
            if margin < 100000:
                checks.append({
                    "status": "fail",
                    "label": f"рҹҡ« ж©ҹи»ҠеүҚиІёеү© {moto_remain:,} е…ғгҖҒжүЈе®ҢеҫҢеҸҜиІё {margin:,} е…ғ < 10 иҗ¬",
                    "actual": "еүҚиІёйҒҺй«ҳгҖҒз„Ўжі•йҖҒж©ҹи»Ҡж–№жЎҲ",
                })
                has_simple_fail = True

        # жҲҝеұӢз§ҒиЁӯи©ұиЎ“жҸҗзӨәпјҲиһҚиіҮ/йҠҖиЎҢйЎһпјү
        if has_house_private and plan["company"] in PRIVATE_OK_PLANS:
            if plan["company"] in ["йҠҖиЎҢ", "й„үж°‘"]:
                checks.append({
                    "status": "manual",
                    "label": "рҹ’Ў е®ўжҲ¶жңүжҲҝеұӢз§ҒиЁӯгҖҒи©ұиЎ“иӘӘгҖҢзҲ¶жҜҚеҗҚдёӢгҖҚ",
                    "actual": "йңҖи©ұиЎ“",
                })
                manual_count += 1

        # еҲӨе®ҡ eligible
        if has_simple_fail:
            eligible = False
            if private_blocked:
                summary = "рҹҡ« з§ҒиЁӯдёҚеҸҜйҖҒ"
            else:
                summary = "вқҢ дёҚз¬ҰеҗҲпјҲзңӢ вқҢ й …зӣ®пјү"
        elif plan.get("always_eligible"):
            # еӣәе®ҡжҺ’зҡ„ж–№жЎҲпјҲй„үж°‘/ж°‘й–“ 4 е®¶пјүпјҡsimple йҖҡйҒҺе°ұжЁҷ вң…гҖҒoneof/manual дёҚж“Ӣ
            eligible = True
            summary = "вң… еӣәе®ҡжҺ’пјҲжҜҸеҖӢе®ўжҲ¶йғҪжңғйҖҒпјү"
        elif has_oneof_fail:
            eligible = False
            summary = "вқҢ ж“ҮдёҖжўқд»¶е…ЁдёҚз¬Ұ"
        elif manual_count > 0:
            eligible = "manual"
            summary = f"вҡ пёҸ иҮӘеӢ• OKгҖҒйңҖдәәе·ҘзўәиӘҚ {manual_count} й …"
        else:
            eligible = True
            summary = "вң… е…ЁйғЁйҒ”жЁҷ"
        results.append({
            "company": plan["company"],
            "max_amount": plan["max_amount"],
            "priority": plan.get("priority", 0),
            "eligible": eligible,
            "checks": checks,
            "summary": summary,
            "required_docs": plan.get("required_docs", []),
            "bonus_items": plan.get("bonus_items", COMMON_BONUS_ITEMS),
            "private_blocked": private_blocked,
        })
    # 21 vs йә»еҗүпјҡ21 зі»еҲ—д»»дёҖеҸҜйҖҒ вҶ’ йә»еҗүзі»еҲ—йҷҚзҙҡпјҲCLAUDE.md иҰҸеүҮ #3пјү
    has_21_passed = any(
        r["eligible"] is True and r["company"].startswith("21")
        for r in results
    )
    if has_21_passed:
        for r in results:
            if r["company"].startswith("йә»еҗү") and r["eligible"] is True:
                r["eligible"] = "demoted"
                r["summary"] = "21 е·ІеҸҜйҖҒгҖҒйә»еҗүеӮҷжЎҲдёҚжҺ’"
    # жҺ’еәҸпјҡеҸҜйҖҒпјҲеҗ« manualпјүвҶ’ дёҚеҸҜйҖҒгҖҒйҮ‘йЎҚеӨ§е„Әе…ҲгҖҒpriority й«ҳе„Әе…Ҳ
    def sort_key(r):
        eligible_score = {True: 0, "manual": 1, "demoted": 2, False: 3}[r["eligible"]]
        return (eligible_score, -r["max_amount"], -r["priority"])
    results.sort(key=sort_key)
    return {
        "results": results,
        "private_status": "confirmed" if has_private else None,
        "unknown_dynbao": unknown_dynbao,
        "house_private": has_house_private,
    }


