CHINESE_NAME_RE = re.compile(r"[\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12}")
ID_RE = re.compile(r"[A-Z][A-Z0-9]\d{8}")

# ж”ҜжҸҙжңүз„Ў - зҡ„ж—Ҙжңҹж јејҸпјҢеҰӮ 115/3/2е»–дҝҠе®Ҹ жҲ– 115/3/2-е»–дҝҠе®Ҹ
DATE_NAME_ID_INLINE_RE = re.compile(
    r"^\s*(\d{2,6}/\d{1,2}/\d{1,2})\s*[-пјҚ]?\s*([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*([A-Z][A-Z0-9]\d{8})",
    re.IGNORECASE,
)
DATE_NAME_ONLY_RE = re.compile(
    r"^\s*(\d{2,6}/\d{1,2}/\d{1,2})\s*[-пјҚ]?\s*([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})(?:\s*$|\s*[-пјҚ/\u3400-\u9fff\uf900-\ufaff])",
    re.IGNORECASE,
)
# зҹӯж—Ҙжңҹпјҡ3/2е»–дҝҠе®Ҹ жҲ– 3/2-е»–дҝҠе®ҸпјҲжңүз„Ў-йғҪж”ҜжҸҙпјү
SHORT_DATE_NAME_RE = re.compile(
    r"^\s*(\d{1,2}/\d{1,2})\s*[-пјҚ]?\s*([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})"
)
# йҖҒд»¶й ҶеәҸж јејҸпјҡ4/1-й«ҳйғЎжғ -е–¬зҫҺ/дәһеӨӘ/е’ҢиЈ•
ROUTE_ORDER_RE = re.compile(
    r"^\s*(\d{1,4}/\d{1,2}(?:/\d{1,2})?)\s*[-пјҚ]\s*([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*[-пјҚ]\s*((?:[^\s/\n]+/)*[^\s/\n@]+)(?:\s*@AI)?\s*$",
    re.IGNORECASE,
)
# е–®е…¬еҸёж ёеҮҶ/е©үжӢ’ж јејҸпјҡ03/04-й»ғеЁ«жҹ”-жҲҝең°ж ёеҮҶ20иҗ¬ / 03/04-й»ғеЁ«жҹ”-ж–°й‘«ж ёеҮҶ20иҗ¬
# з”Ё negative lookbehind жҺ’йҷӨгҖҢеҫ…ж ёеҮҶгҖҚгҖҢеҫ…ж ёжә–гҖҚиӘӨеҲӨзӮәж ёеҮҶ
SINGLE_APPROVAL_RE = re.compile(
    r"^\s*(\d{1,4}/\d{1,2}(?:/\d{1,2})?)\s*[-пјҚ]\s*([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*[-пјҚ]\s*([^\s/\n@-]+?)(?<!еҫ…)(ж ёеҮҶ|ж ёжә–|е©үжӢ’)(\d+(?:\.\d+)?иҗ¬)?(?:\s*@AI)?\s*$",
    re.IGNORECASE,
)

# вӯҗ з…§жңғжіЁж„ҸдәӢй …еҒөжё¬пјҲзӯүеҗҢе·ІйҖҒд»¶пјү
NOTIFICATION_TRIGGER_RE = re.compile(r"з…§жңғжіЁж„ҸдәӢй …")
EXTRA_COMPANY_RE = re.compile(r"[+пјӢ]\s*([\u3400-\u9fff\uf900-\ufaff0-9]{1,8}?)\s*дёҖиө·")
# иҪүйҖҒж јејҸпјҡ8/5-жҲҙеҗӣе“І-иҪү21 жҲ– 8/11-жһ—жӣүи–Ү-иҪүйә»еҗү 6/18
TRANSFER_RE = re.compile(
    r"^\s*(\d{1,4}/\d{1,2}(?:/\d{1,2})?)\s*[-пјҚ]\s*([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*[-пјҚ]\s*иҪү\s*([^\s@]+)(?:\s.*)?(?:\s*@AI)?\s*$",
    re.IGNORECASE,
)


def is_notification_briefing(text: str) -> bool:
    """жҳҜеҗҰзӮәз…§жңғжіЁж„ҸдәӢй …ж јејҸпјҡз¬¬дёҖиЎҢе§“еҗҚпјҲ2-4дёӯж–Үеӯ—пјү+ з¬¬дәҢиЎҢгҖҢз…§жңғжіЁж„ҸдәӢй …гҖҚ"""
    if not text:
        return False
    lines = [l.strip() for l in text.strip().splitlines() if l.strip()]
    if len(lines) < 2:
        return False
    # з¬¬дёҖиЎҢпјҡзҙ”дёӯж–Үе§“еҗҚ 2-4 еӯ—
    name = lines[0]
    if not re.fullmatch(r"[\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12}", name):
        return False
    # з¬¬дәҢиЎҢпјҡз…§жңғжіЁж„ҸдәӢй …
    if "з…§жңғжіЁж„ҸдәӢй …" not in lines[1]:
        return False
    return True


def extract_extra_company(text: str) -> str:
    """еҫһз…§жңғиЁҠжҒҜжң«е°ҫжҠ“гҖҢ+XXXдёҖиө·гҖҚзҡ„йЎҚеӨ–е…¬еҸёеҗҚпјҲеҺҹе§Ӣеӯ—дёІпјҢе‘јеҸ«иҷ•еҶҚжӯЈиҰҸеҢ–пјү"""
    if not text:
        return ""
    m = EXTRA_COMPANY_RE.search(text)
    return m.group(1).strip() if m else ""


def parse_notification_fields(text: str) -> dict:
    """еҫһз…§жңғжіЁж„ҸдәӢй …иЁҠжҒҜжҸҗеҸ–е®ўжҲ¶ж¬„дҪҚиіҮж–ҷ"""
    fields = {}
    # еұ…дҪҸе№ҙж•ёпјҡеұ…дҪҸ5е№ҙ
    m = re.search(r"еұ…дҪҸ\s*(\d+)\s*е№ҙ", text)
    if m:
        fields["live_years"] = m.group(1)
    # еұ…дҪҸзӢҖжіҒпјҡзҲ¶жҜҚеҗҚдёӢ/иҮӘжңү/з§ҹеұӢ/й…ҚеҒ¶
    for status in ["зҲ¶жҜҚ", "иҮӘжңү", "з§ҹеұӢ", "й…ҚеҒ¶", "иҰӘеұ¬", "е®ҝиҲҚ"]:
        if status in text:
            fields["live_status"] = status + ("еҗҚдёӢ" if "еҗҚдёӢ" in text else "")
            break
    # е№ҙиіҮпјҡе·ҘдҪңе№ҙиіҮ6е№ҙ / е№ҙиіҮ6е№ҙ
    m = re.search(r"(?:е·ҘдҪң)?е№ҙиіҮ\s*(\d+)\s*е№ҙ", text)
    if m:
        fields["company_years"] = m.group(1)
    # жңҲи–ӘпјҡжңҲи–Ә10иҗ¬ / жңҲи–Ә50000
    m = re.search(r"жңҲи–Ә\s*(\d+(?:\.\d+)?)\s*иҗ¬", text)
    if m:
        fields["company_salary"] = str(int(float(m.group(1)) * 10000))
    else:
        m = re.search(r"жңҲи–Ә\s*(\d{4,})", text)
        if m:
            fields["company_salary"] = m.group(1)
    # йҖҒд»¶йҮ‘йЎҚ/жңҹж•ёпјҡ14иҗ¬/30жңҹ жҲ– 10иҗ¬ 30жңҹпјҲжіЁж„ҸпјҡйҖҒд»¶йҮ‘йЎҚ вү  ж ёеҮҶйҮ‘йЎҚпјү
    m = re.search(r"(\d+(?:\.\d+)?)\s*иҗ¬\s*/?\s*(\d+)\s*жңҹ", text)
    if m:
        fields["notify_amount"] = m.group(1)
        fields["notify_period"] = m.group(2)
    # еӯёжӯ·пјҡеӨ§еӯёз•ў / й«ҳдёӯ / е°Ҳз§‘
    for edu, val in [("еӨ§еӯё", "е°Ҳз§‘/еӨ§еӯё"), ("е°Ҳз§‘", "е°Ҳз§‘/еӨ§еӯё"), ("й«ҳдёӯ", "й«ҳдёӯ/иҒ·"),
                     ("й«ҳиҒ·", "й«ҳдёӯ/иҒ·"), ("з ”з©¶жүҖ", "з ”з©¶жүҖд»ҘдёҠ"), ("зў©еЈ«", "з ”з©¶жүҖд»ҘдёҠ")]:
        if edu in text:
            fields["education"] = val
            break
    # иіҮйҮ‘з”ЁйҖ”пјҡиіҮйҮ‘з”ЁйҖ”пјҡе®¶з”Ё
    m = re.search(r"иіҮйҮ‘з”ЁйҖ”\s*[пјҡ:]\s*(\S+)", text)
    if m:
        fields["fund_use"] = m.group(1)
    return fields


def handle_notification_briefing(block_text: str, source_group_id: str, reply_token: str) -> Optional[str]:
    """иҷ•зҗҶз…§жңғжіЁж„ҸдәӢй … вҖ” зӯүеҗҢе·ІйҖҒд»¶пјҢжҸҗеҸ–ж¬„дҪҚиіҮж–ҷжӣҙж–°е®ўжҲ¶"""
    lines = block_text.strip().splitlines()
    if not lines:
        return None
    # з¬¬дёҖиЎҢжҳҜе®ўжҲ¶е§“еҗҚ
    name = lines[0].strip()
    if not name:
        return None
    rows = find_active_by_name(name)
    same = [r for r in rows if r["source_group_id"] == source_group_id]
    target = same[0] if same else (rows[0] if rows else None)
    if not target:
        return f"вҡ пёҸ з…§жңғжіЁж„ҸдәӢй …пјҡжүҫдёҚеҲ°е®ўжҲ¶гҖҢ{name}гҖҚ"

    # жҸҗеҸ–ж¬„дҪҚ
    fields = parse_notification_fields(block_text)

    # жӣҙж–°е®ўжҲ¶пјҡжЁҷиЁҳе·ІйҖҒд»¶ + еҜ«е…Ҙж¬„дҪҚ
    # з…§жңғжҳҜйҖҒд»¶еүҚзҡ„еӢ•дҪңпјҢйҮ‘йЎҚ вҶ’ notify_amountпјҲйҖҒд»¶йҮ‘йЎҚпјҢйқһж ёеҮҶйҮ‘йЎҚпјү
    # target жҳҜ sqlite3.RowпјҢз”Ё [] иЁӘе•Ҹ
    sec = target["current_company"] or target["company"] or "йҖҒд»¶"
    update_fields = {
        "text": block_text,
        "from_group_id": source_group_id,
        "report_section": sec,
    }
    if fields.get("notify_amount"):
        update_fields["notify_amount"] = fields["notify_amount"]
        if fields.get("notify_period"):
            update_fields["notify_period"] = fields["notify_period"]

    update_customer(target["case_id"], **update_fields)

    # жҠҠз…§жңғдёӯи§ЈжһҗеҮәзҡ„ж¬„дҪҚеҜ«е…Ҙ DBпјҲзӣҙжҺҘ SQL жӣҙж–°йқһж ёеҝғж¬„дҪҚпјү
    db_updates = {}
    if fields.get("live_years"):
        db_updates["live_years"] = fields["live_years"]
    if fields.get("live_status"):
        db_updates["live_status"] = fields["live_status"]
    if fields.get("company_years"):
        db_updates["company_years"] = fields["company_years"]
    if fields.get("company_salary"):
        db_updates["company_salary"] = fields["company_salary"]
    if fields.get("education"):
        db_updates["education"] = fields["education"]
    if db_updates:
        with db_conn(commit=True) as conn:
            cur = conn.cursor()
            set_clause = ", ".join(f"{k}=?" for k in db_updates)
            vals = list(db_updates.values()) + [target["case_id"]]
            cur.execute(f"UPDATE customers SET {set_clause} WHERE case_id=?", vals)

    # еӣһиҰҶ
    parsed_info = []
    if fields.get("live_years"):
        parsed_info.append(f"еұ…дҪҸ{fields['live_years']}е№ҙ")
    if fields.get("company_years"):
        parsed_info.append(f"е№ҙиіҮ{fields['company_years']}е№ҙ")
    if fields.get("company_salary"):
        parsed_info.append(f"жңҲи–Ә{fields['company_salary']}")
    if fields.get("notify_amount"):
        per = fields.get("notify_period", "")
        parsed_info.append(f"йҖҒд»¶йҮ‘йЎҚ{fields['notify_amount']}иҗ¬/{per}жңҹ" if per else f"йҖҒд»¶йҮ‘йЎҚ{fields['notify_amount']}иҗ¬")
    if fields.get("education"):
        parsed_info.append(f"еӯёжӯ·{fields['education']}")

    info_str = "гҖҒ".join(parsed_info) if parsed_info else ""
    msg = f"рҹ“Ӣ е·Іж”¶еҲ°з…§жңғпјҡ{name}"
    if info_str:
        msg += f"\nрҹ“қ е·ІиЁҳйҢ„пјҡ{info_str}"
    return msg


# вӯҗ е°Қдҝқ 4 еӯҗжӯҘй©ҹеҒөжё¬
def detect_pairing_substep(text: str) -> str:
    """еҒөжё¬е°ҚдҝқеӯҗжӯҘй©ҹпјҢеӣһеӮіеӯҗзӢҖж…ӢеҗҚзЁұпјҲз©әеӯ—дёІ=дёҚжҳҜе°ҚдҝқиЁҠжҒҜпјү

    еӣһеӮіеҖјпјҡ
    - "жҙҫе°Қдҝқ" - 8a иЎҢж”ҝзҷјжҙҫе°ҚдҝқпјҲеҗ«гҖҢжҙҫе°ҚдҝқгҖҚгҖҢиҫҰзҗҶж–№жЎҲгҖҚ+гҖҢе°Қдҝқең°еҚҖгҖҚпјү
    - "е§”е°Қж”¶" - 8b е°Қдҝқе“ЎжҺҘе–®еӣһиҰҶгҖҢе§”е°Қж”¶гҖҚ
    - "зҙ„жҷӮй–“" - 8c е°Қдҝқе“ЎеӣһжҷӮй–“+ең°й»һ
    - "е°ҚеҘҪ"   - 8d е°Қдҝқе®ҢжҲҗеӣһе ұпјҲгҖҢе°ҚеҘҪгҖҚгҖҢе°Қдҝқе®ҢжҲҗгҖҚгҖҢдёҚж”¶дёҚз°ҪгҖҚпјү
    """
    if not text:
        return ""
    if "е°ҚеҘҪ" in text or "е°Қдҝқе®ҢжҲҗ" in text or "дёҚж”¶дёҚз°Ҫ" in text or "дёҚз°ҪдёҚж”¶" in text:
        return "е°ҚеҘҪ"
    if "е§”е°Қж”¶" in text:
        return "е§”е°Қж”¶"
    if "жҙҫе°Қдҝқ" in text or ("иҫҰзҗҶж–№жЎҲ" in text and "е°Қдҝқең°еҚҖ" in text):
        return "жҙҫе°Қдҝқ"
    if ("е°ҚдҝқжҷӮй–“" in text or "е°Қдҝқең°й»һ" in text or
        ("жҷӮй–“" in text and "ең°й»һ" in text and len(text) < 100)):
        return "зҙ„жҷӮй–“"
    return ""


