def now_iso() -> str:
    # Render и·‘еңЁ US/UTCгҖҒдҪҶжҘӯеӢҷеңЁеҸ°зҒЈз”Ё вҶ’ зЎ¬иҪү UTC+8
    from datetime import timezone, timedelta
    tw = timezone(timedelta(hours=8))
    return datetime.now(tw).strftime("%Y-%m-%d %H:%M:%S")

def now_tw() -> "datetime":
    """еҸ–еҫ—еҸ°зҒЈз•¶ең°жҷӮй–“пјҲзөҰе…¶д»–ең°ж–№з”Ёпјү"""
    from datetime import timezone, timedelta
    return datetime.now(timezone(timedelta(hours=8))).replace(tzinfo=None)


def short_id() -> str:
    return str(uuid.uuid4())[:8]


def get_conn():
    """еҸ–еҫ— DB йҖЈз·ҡпјҲеҗ‘еҫҢзӣёе®№пјҢйңҖжүӢеӢ• closeпјү"""
    pathlib.Path(DB_PATH).parent.mkdir(parents=True, exist_ok=True)
    # Bug 16: timeout еҫһ 10 еҠ еҲ° 30 з§’пјҢзөҰ BEGIN IMMEDIATE жҺ’йҡҠжӣҙеӨҡжҷӮй–“
    conn = sqlite3.connect(DB_PATH, timeout=30)
    conn.row_factory = sqlite3.Row
    conn.execute("PRAGMA journal_mode=WAL")
    return conn


from contextlib import contextmanager

@contextmanager
def db_conn(commit: bool = False):
    """DB йҖЈз·ҡ context managerпјҲBug 5/6/16 дҝ®еҫ©пјү

    дҝқиӯүпјҡ
    - дҫӢеӨ–жҷӮйҖЈз·ҡдёҖе®ҡжңғ closeпјҲBug 5 йҖЈз·ҡжҙ©жјҸпјү
    - commit=True жҷӮз”Ё BEGIN IMMEDIATE з«ӢеҲ»жӢҝеҜ«йҺ–пјҢйҳІ raceпјҲBug 6/16пјү
    - дҫӢеӨ–жҷӮиҮӘеӢ• rollback
    """
    conn = get_conn()
    try:
        if commit:
            # Bug 16: еҲҮжҸӣзӮәжүӢеӢ•дәӨжҳ“жЁЎејҸпјҢз«ӢеҲ»жӢҝеҜ«йҺ–пјҲйҒҝе…Қ read-modify-write raceпјү
            conn.isolation_level = None
            conn.execute("BEGIN IMMEDIATE")
        yield conn
        if commit:
            conn.execute("COMMIT")
    except Exception:
        try:
            if commit:
                conn.execute("ROLLBACK")
        except Exception:
            pass
        raise
    finally:
        try:
            conn.close()
        except Exception:
            pass


