def render_pagination(page: int, total_pages: int, total_count: int, base_url: str, query_params: dict) -> str:
    """еҲҶй ҒжҢүйҲ•еҲ—пјҲдҫӣ /history /search зӯүе…ұз”ЁпјүгҖӮ
    query_params: зӣ®еүҚй Ғйқўзҡ„жҹҘи©ўеҸғж•ёпјҲдёҚеҗ« pageпјүпјҢз”Ёж–ј hyperlink дҝқз•ҷжҗңе°Ӣжўқд»¶гҖӮ"""
    from urllib.parse import urlencode
    if total_count == 0:
        return ""
    if total_pages <= 1:
        return f'<div style="font-size:13px;color:#6a5e4e;padding:14px 0;text-align:center">е…ұ {total_count} зӯҶ</div>'
    def url(p):
        qp = {k: v for k, v in (query_params or {}).items() if v not in (None, "")}
        qp["page"] = p
        return f"{base_url}?{urlencode(qp)}"
    btns = []
    btn_style = "padding:6px 12px;border:1px solid #ddd5ca;border-radius:6px;color:#4a3e30;text-decoration:none;font-size:13px;background:#faf7f4"
    active_style = "padding:6px 12px;border:1px solid #6a5e4e;border-radius:6px;color:#fff;background:#6a5e4e;font-size:13px;font-weight:700"
    dis_style = "padding:6px 12px;color:#c8bfb5;font-size:13px"
    if page > 1:
        btns.append(f'<a href="{url(page-1)}" style="{btn_style}">вҶҗ дёҠдёҖй Ғ</a>')
    else:
        btns.append(f'<span style="{dis_style}">вҶҗ дёҠдёҖй Ғ</span>')
    start = max(1, page - 2)
    end = min(total_pages, page + 2)
    if start > 1:
        btns.append(f'<a href="{url(1)}" style="{btn_style}">1</a>')
        if start > 2:
            btns.append(f'<span style="{dis_style}">...</span>')
    for p in range(start, end + 1):
        if p == page:
            btns.append(f'<span style="{active_style}">{p}</span>')
        else:
            btns.append(f'<a href="{url(p)}" style="{btn_style}">{p}</a>')
    if end < total_pages:
        if end < total_pages - 1:
            btns.append(f'<span style="{dis_style}">...</span>')
        btns.append(f'<a href="{url(total_pages)}" style="{btn_style}">{total_pages}</a>')
    if page < total_pages:
        btns.append(f'<a href="{url(page+1)}" style="{btn_style}">дёӢдёҖй Ғ вҶ’</a>')
    else:
        btns.append(f'<span style="{dis_style}">дёӢдёҖй Ғ вҶ’</span>')
    return (f'<div style="display:flex;gap:8px;align-items:center;justify-content:center;padding:18px 0;flex-wrap:wrap">'
            + "".join(btns)
            + f'<span style="font-size:12px;color:#6a5e4e;margin-left:12px">з¬¬ {page}/{total_pages} й ҒпјҢе…ұ {total_count} зӯҶ</span>'
            + '</div>')


def fmt_salary(s) -> str:
    """жңҲи–ӘйЎҜзӨәж јејҸеҢ–пјҡзөұдёҖијёеҮәгҖҢNиҗ¬гҖҚпјҲжҺҘеҸ—гҖҢ3.5гҖҚгҖҢ3.5иҗ¬гҖҚгҖҢ35000гҖҚгҖҢ35000е…ғгҖҚзӯүеҗ„зЁ® DB ж—ўеӯҳеҖјпјүгҖӮ
    з©әеҖј вҶ’ з©әеӯ—дёІгҖӮ>=1000 иҰ–зӮәе…ғгҖҒиҮӘеӢ•иҪүиҗ¬гҖӮ"""
    raw = (str(s) if s is not None else "").replace("иҗ¬", "").replace("е…ғ", "").replace(",", "").strip()
    if not raw:
        return ""
    try:
        n = float(raw)
        if n >= 1000:
            n = n / 10000
        return f"{int(n)}иҗ¬" if n == int(n) else f"{n}иҗ¬"
    except Exception:
        return raw + "иҗ¬"


def normalize_ai_text(text: str) -> str:
    """зөұдёҖеҢ–ж–Үеӯ—пјҡе…ЁеҪўиҪүеҚҠеҪўгҖҒеҺ»з©әзҷҪ"""
    text = (text or "")
    # е…ЁеҪўпј вҶ’@гҖҒе…ЁеҪўз©әж јвҶ’еҚҠеҪў
    text = text.replace("пј ", "@").replace("гҖҖ", " ")
    # е…ЁеҪўиӢұж–Ү пјЎ-пјә пҪҒ-пҪҡ вҶ’ еҚҠеҪў
    result = ""
    for c in text:
        code = ord(c)
        if 0xFF01 <= code <= 0xFF5E:
            result += chr(code - 0xFEE0)
        else:
            result += c
    return result


def has_ai_trigger(text: str) -> bool:
    """ж”ҜжҸҙе…ЁеҪўеҚҠеҪўеӨ§е°ҸеҜ«пјҢеҰӮ @AI / пј AI / @ai / @ A I / пј пјЎпј©"""
    normalized = re.sub(r"\s+", "", normalize_ai_text(text))
    return bool(re.search(r"@ai|#ai", normalized, re.IGNORECASE))


def strip_ai_trigger(text: str) -> str:
    """еҺ»жҺүжүҖжңү @AI и§ёзҷји©һ + LINE @жЁҷиЁҳе…¶д»–дәә"""
    text = normalize_ai_text(text)
    # е…ҲеҺ»жҺү @AI
    text = re.sub(r"(@aiеҠ©зҗҶ|#aiеҠ©зҗҶ|@ai|#ai)", "", text, flags=re.IGNORECASE)
    # еҶҚеҺ»жҺүе…¶д»– LINE @жЁҷиЁҳпјҲ@дәәеҗҚпјҢдҪҶдёҚжҳҜ @aiпјү
    text = re.sub(r"@[^\s@]{1,20}", "", text)
    return text.strip()


