def extract_company(text: str) -> str:
    if not text:
        return ""
    # е…ҲжҠҠиә«еҲҶиӯү/еұ…з•ҷиӯүиҷҹзўјз§»йҷӨпјҲйҒҝе…Қ U121558670 зҡ„ 21 иў«жҠ“жҲҗе…¬еҸёпјү
    text = re.sub(r"[A-Z][A-Z0-9]\d{8}", "", text, flags=re.IGNORECASE)
    # еҸӘзңӢзӢҖж…Ӣй—ңйҚөеӯ—д№ӢеүҚзҡ„йғЁеҲҶпјҲзӢҖж…ӢеҫҢйқўйғҪжҳҜеӮҷиЁ»еҺҹеӣ пјҢдёҚжҠ“пјү
    search_text = text
    for kw in ["ж ёеҮҶ", "ж ёжә–", "е©үжӢ’", "з”іиҰҶеӨұж•—", "иЈңд»¶", "еҫ…ж ёеҮҶ", "з…§жңғ", "ж’Ҙж¬ҫ"]:
        idx = search_text.find(kw)
        if idx > 0:
            search_text = search_text[:idx]
            break
    # еҸӘзңӢз¬¬дёҖиЎҢпјҲеӨҡиЎҢиЁҠжҒҜеҫҢйқўйҖҡеёёжҳҜеӮҷиЁ»пјү
    search_text = search_text.splitlines()[0] if search_text else ""
    # жүҫеҮәжүҖжңүеҢ№й…ҚеҸҠе…¶дҪҚзҪ®пјҢеҸ–жңҖеүҚйқўеҮәзҸҫзҡ„
    matches = []
    for c in COMPANY_LIST:
        idx = search_text.find(c)
        if idx >= 0:
            matches.append((idx, c, c))
    for alias, real in COMPANY_ALIAS.items():
        idx = search_text.find(alias)
        if idx >= 0:
            matches.append((idx, alias, real))
    if not matches:
        return ""
    # жҢүдҪҚзҪ®жҺ’еәҸпјҢеҗҢдҪҚзҪ®жҷӮй•·еәҰй•·зҡ„е„Әе…ҲпјҲдәһеӨӘе•Ҷе“Ғ > дәһеӨӘпјү
    matches.sort(key=lambda x: (x[0], -len(x[1])))
    return matches[0][2]


def get_group_name(group_id: str) -> str:
    if not group_id:
        return "жңӘзҹҘзҫӨзө„"
    conn = get_conn()
    cur = conn.cursor()
    cur.execute("SELECT group_name FROM groups WHERE group_id=?", (group_id,))
    row = cur.fetchone()
    conn.close()
    return row["group_name"] if row else "жңӘзҹҘзҫӨзө„"


def get_all_group_names() -> Dict[str, str]:
    """дёҖж¬Ўијүе…ҘжүҖжңүзҫӨзө„еҗҚзЁұпјҢйҒҝе…Қ N+1 жҹҘи©ў"""
    conn = get_conn(); cur = conn.cursor()
    cur.execute("SELECT group_id, group_name FROM groups")
    result = {r["group_id"]: r["group_name"] for r in cur.fetchall()}
    conn.close()
    return result


