def get_a_group_for_sales(sales_group_id: str) -> str:
    """жұәе®ҡжҘӯеӢҷзҫӨзҡ„жЎҲд»¶иҰҒжҺЁеҲ°е“ӘеҖӢ A зҫӨгҖӮ
    - жҘӯеӢҷзҫӨжңүиЁӯе®ҡ linked_a_group_id вҶ’ з”ЁиЁӯе®ҡзҡ„
    - жІ’иЁӯе®ҡ вҶ’ fallback еҲ°з’°еўғи®Ҡж•ё A_GROUP_ID
    """
    if not sales_group_id:
        return A_GROUP_ID
    try:
        conn = get_conn()
        cur = conn.cursor()
        cur.execute("SELECT linked_a_group_id FROM groups WHERE group_id=? AND is_active=1",
                    (sales_group_id,))
        row = cur.fetchone()
        conn.close()
        if row and row["linked_a_group_id"]:
            return row["linked_a_group_id"]
    except Exception:
        pass
    return A_GROUP_ID


