# LINE API
# =========================
def push_text(to_group_id: str, text: str):
    """жҺЁйҖҒиЁҠжҒҜгҖӮи¶…йҒҺ 4900 еӯ—жңғиҮӘеӢ•еҲҶж®өжҺЁйҖҒпјҢжҜҸж®өйғҪеҠ гҖҢ(N/M)гҖҚжЁҷиЁҳ"""
    if not CHANNEL_ACCESS_TOKEN:
        return False, "жңӘиЁӯе®ҡ CHANNEL_ACCESS_TOKEN"
    text = text or ""
    # и¶…й•·жҷӮеҲҶж®өпјҲжҜҸж®ө 4900 еӯ—пјү
    if len(text) > 4900:
        segments = []
        # е„Әе…ҲеңЁжҸӣиЎҢеҲҶж®өпјҢйҒҝе…ҚеҲҮеҚҠ
        remaining = text
        while len(remaining) > 4900:
            cut = remaining.rfind("\n", 0, 4900)
            if cut < 3500:  # жІ’жүҫеҲ°еҗҲйҒ©жҸӣиЎҢпјҢеј·еҲҮ
                cut = 4900
            segments.append(remaining[:cut])
            remaining = remaining[cut:].lstrip("\n")
        if remaining:
            segments.append(remaining)
        total = len(segments)
        last_ok, last_err = True, ""
        for i, seg in enumerate(segments, 1):
            tag = f"({i}/{total}) " if total > 1 else ""
            try:
                resp = req_lib.post(
                    "https://api.line.me/v2/bot/message/push",
                    headers={"Authorization": f"Bearer {CHANNEL_ACCESS_TOKEN}", "Content-Type": "application/json"},
                    json={"to": to_group_id, "messages": [{"type": "text", "text": (tag + seg)[:4900]}]},
                    timeout=10,
                )
                if resp.status_code != 200:
                    last_ok = False
                    last_err = f"HTTP {resp.status_code}"
            except Exception as e:
                last_ok = False
                last_err = str(e)
        return last_ok, last_err
    try:
        resp = req_lib.post(
            "https://api.line.me/v2/bot/message/push",
            headers={"Authorization": f"Bearer {CHANNEL_ACCESS_TOKEN}", "Content-Type": "application/json"},
            json={"to": to_group_id, "messages": [{"type": "text", "text": text[:4900]}]},
            timeout=10,
        )
        return (200 <= resp.status_code < 300), "" if 200 <= resp.status_code < 300 else f"LINE pushеӨұж•—({resp.status_code})"
    except Exception as e:
        return False, str(e)


def reply_text(reply_token: str, text: str):
    if not CHANNEL_ACCESS_TOKEN or reply_token == "TEST":
        return
    try:
        req_lib.post(
            "https://api.line.me/v2/bot/message/reply",
            headers={"Authorization": f"Bearer {CHANNEL_ACCESS_TOKEN}", "Content-Type": "application/json"},
            json={"replyToken": reply_token, "messages": [{"type": "text", "text": text[:4900]}]},
            timeout=10,
        )
    except Exception:
        pass


def make_quick_reply_item(label: str, text: str):
    return {"type": "action", "action": {"type": "message", "label": label[:20], "text": text}}


def push_text_with_buttons(to_group_id: str, text: str, items):
    """жҺЁйҖҒиЁҠжҒҜ + Quick Reply жҢүйҲ•пјҲз”Ёж–јдё»еӢ•йҖҡзҹҘйңҖиҰҒеҫ©еҺҹзӯүж“ҚдҪңзҡ„зҫӨзө„пјү"""
    if not CHANNEL_ACCESS_TOKEN:
        return False, "жңӘиЁӯе®ҡ CHANNEL_ACCESS_TOKEN"
    if len(items) > 13:
        items = items[:13]
    try:
        req_lib.post(
            "https://api.line.me/v2/bot/message/push",
            headers={"Authorization": f"Bearer {CHANNEL_ACCESS_TOKEN}", "Content-Type": "application/json"},
            json={"to": to_group_id, "messages": [{"type": "text", "text": (text or "")[:4900], "quickReply": {"items": items}}]},
            timeout=10,
        )
        return True, ""
    except Exception as e:
        return False, str(e)


def reply_text_multi(reply_token: str, texts):
    """дёҖж¬Ў reply йҖҒеӨҡеүҮиЁҠжҒҜпјҲLINE reply API ж”ҜжҸҙжңҖеӨҡ 5 еүҮгҖҒдёҚз®— push й…ҚйЎҚпјү"""
    if not CHANNEL_ACCESS_TOKEN or reply_token == "TEST":
        return
    texts = [t for t in (texts or []) if t]
    if not texts:
        return
    messages = [{"type": "text", "text": t[:4900]} for t in texts[:5]]
    try:
        req_lib.post(
            "https://api.line.me/v2/bot/message/reply",
            headers={"Authorization": f"Bearer {CHANNEL_ACCESS_TOKEN}", "Content-Type": "application/json"},
            json={"replyToken": reply_token, "messages": messages},
            timeout=10,
        )
    except Exception:
        pass


def reply_quick_reply(reply_token: str, text: str, items):
    if not CHANNEL_ACCESS_TOKEN or reply_token == "TEST":
        return
    # LINE Quick Reply дёҠйҷҗ 13 еҖӢжҢүйҲ•пјҢи¶…йҒҺиӯҰе‘Ҡ + жҲӘж–·
    if len(items) > 13:
        print(f"[reply_quick_reply] иӯҰе‘ҠпјҡжҢүйҲ•ж•ё {len(items)} и¶…йҒҺ 13пјҢе·ІжҲӘж–·")
        items = items[:13]
    try:
        req_lib.post(
            "https://api.line.me/v2/bot/message/reply",
            headers={"Authorization": f"Bearer {CHANNEL_ACCESS_TOKEN}", "Content-Type": "application/json"},
            json={"replyToken": reply_token, "messages": [{"type": "text", "text": text[:4900], "quickReply": {"items": items}}]},
            timeout=10,
        )
    except Exception:
        pass


