def ensure_column(cur, table: str, column: str, definition: str):
    """еҠ ж¬„дҪҚпјҲDB migration з”Ёпјү

    Bug 7: еҠ  whitelist йҳІ SQL injectionгҖӮ
    table/column еҝ…й ҲжҳҜеҗҲжі•иӯҳеҲҘеӯ—пјҲеӯ—жҜҚ+еә•з·ҡ+ж•ёеӯ—пјҢдёҚиғҪд»Ҙж•ёеӯ—й–Ӣй ӯпјү
    definition еҝ…й ҲжҳҜ SQLite еҗҲжі•еһӢеҲҘеӯ—дёІ
    """
    if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", table):
        raise ValueError(f"йқһжі•зҡ„ table еҗҚзЁұпјҡ{table!r}")
    if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", column):
        raise ValueError(f"йқһжі•зҡ„ column еҗҚзЁұпјҡ{column!r}")
    # definition еҡҙж јзҷҪеҗҚе–®пјҡж“Ӣ SQL injectionгҖӮиҰҒж–°еўһеһӢеҲҘи«ӢеҠ еҲ°йҖҷеҖӢ set иЈЎ
    _ALLOWED_DEFS = {
        # TEXT
        "TEXT", "TEXT NOT NULL", "TEXT DEFAULT ''", "TEXT DEFAULT '' NOT NULL",
        # INTEGER
        "INTEGER", "INTEGER NOT NULL", "INTEGER DEFAULT 0", "INTEGER DEFAULT 0 NOT NULL",
        "INTEGER DEFAULT 1", "INTEGER DEFAULT 1 NOT NULL",
        # REAL
        "REAL", "REAL NOT NULL", "REAL DEFAULT 0", "REAL DEFAULT 0 NOT NULL",
        # NUMERIC / BLOB / TIMESTAMP
        "NUMERIC", "BLOB",
        "TIMESTAMP", "DATETIME", "DATE",
    }
    if definition not in _ALLOWED_DEFS:
        raise ValueError(
            f"йқһжі•зҡ„ definitionпјҡ{definition!r}\n"
            f"и«ӢдҪҝз”Ёд»ҘдёӢе…¶дёӯдёҖзЁ®пјҢжҲ–еңЁ ensure_column зҡ„ _ALLOWED_DEFS ж–°еўһпјҡ\n"
            f"{sorted(_ALLOWED_DEFS)}"
        )
    cur.execute(f"PRAGMA table_info({table})")
    cols = [row[1] for row in cur.fetchall()]
    if column not in cols:
        cur.execute(f"ALTER TABLE {table} ADD COLUMN {column} {definition}")


