def seed_groups():
    conn = get_conn()
    cur = conn.cursor()
    now = now_iso()
    for row in [
        (A_GROUP_ID, "AзҫӨ", "A_GROUP", 1, now),
        (B_GROUP_ID, "BзҫӨ", "SALES_GROUP", 1, now),
        (C_GROUP_ID, "CзҫӨ", "SALES_GROUP", 1, now),
    ]:
        cur.execute("INSERT OR IGNORE INTO groups (group_id,group_name,group_type,is_active,created_at) VALUES (?,?,?,?,?)", row)
    conn.commit()
    conn.close()


def init_settings():
    """еҲқе§ӢеҢ–еҜҶзўјпјҲBug 3 дҝ®еҫ©пјү

    е„Әе…Ҳй ҶеәҸпјҡ
    1. е·ІеӯҳеңЁеҜҶзўј вҶ’ дёҚеӢ•
    2. з’°еўғи®Ҡж•ёжңүиЁӯ вҶ’ з”Ёз’°еўғи®Ҡж•ёзҡ„еҜҶзўј
    3. йғҪжІ’жңү вҶ’ з”ўз”ҹйҡЁж©ҹеҜҶзўјдёҰеҚ°еҮә logпјҲдёҚеҶҚз”ЁзЎ¬з·Ёзўјй җиЁӯеҖјпјү
    """
    import secrets as _secrets
    env_var_map = {
        "admin_pw": "ADMIN_PASSWORD",
        "adminB_pw": "ADMINB_PASSWORD",
        "ops_admin_pw": "OPS_ADMIN_PASSWORD",
        "sales_admin_pw": "SALES_ADMIN_PASSWORD",
        "report_pw": "REPORT_PASSWORD",
        "vba_secret": "VBA_SECRET",
    }
    conn = get_conn(); cur = conn.cursor()
    for key, env_var in env_var_map.items():
        cur.execute("SELECT value FROM settings WHERE key=?", (key,))
        if cur.fetchone():
            continue  # е·ІжңүеҜҶзўјпјҢи·ійҒҺ
        env_pw = os.getenv(env_var, "")
        if env_pw:
            pw_to_set = env_pw
            try:
                print(f"[init_settings] {key}: loaded from env {env_var}")
            except Exception:
                pass
        else:
            pw_to_set = _secrets.token_urlsafe(16)
            try:
                print(f"[init_settings] WARNING {key} env not set, generated random password: {pw_to_set}")
                print(f"[init_settings] WARNING please save it and set env var {env_var}")
            except Exception:
                pass
        cur.execute("INSERT INTO settings (key,value,updated_at) VALUES (?,?,?)",
            (key, hash_pw(pw_to_set), now_iso()))
    conn.commit(); conn.close()


