def get_pending_action_and_delete(action_id):
    """Bug 3: еҺҹеӯҗеҢ–и®ҖеҸ–+еҲӘйҷӨпјҢйҳІеҝ«йҖҹйҮҚиӨҮй»һж“ҠйҖ жҲҗйҮҚиӨҮиҷ•зҗҶ"""
    with db_conn(commit=True) as conn:
        cur = conn.cursor()
        cur.execute("SELECT * FROM pending_actions WHERE action_id=?", (action_id,))
        row = cur.fetchone()
        if not row:
            return None
        cur.execute("DELETE FROM pending_actions WHERE action_id=?", (action_id,))
        data = dict(row)
        try:
            data["payload"] = json.loads(data["payload"])
        except Exception:
            data["payload"] = {}
        return data


