# ж ёеҮҶйҮ‘йЎҚ / ж’Ҙж¬ҫеҗҚе–®е·Ҙе…·
# =========================
def extract_approved_amount(text: str) -> str:
    """
    еҫһиЁҠжҒҜжҠ“еҸ–ж ёеҮҶйҮ‘йЎҚпјҲж”№иүҜзүҲпјүгҖӮ
    ж”ҜжҸҙж јејҸпјҡ
    - 20иҗ¬ / 6W / 6.5иҗ¬ / (5).(8)иҗ¬
    - йҷҚж’Ҙ4иҗ¬ / жң¬еҲ©ж”Ө50иҗ¬
    - 120,000 / 40000пјҲеӨ§ж•ёеӯ—иҮӘеӢ•жҸӣз®—пјү
    - ж ёеҮҶйҮ‘йЎҚ20иҗ¬ / жңҖй«ҳж ёиІёйҮ‘йЎҚ20иҗ¬
    жіЁж„ҸпјҡгҖҢж ёеҮҶ30жңҹгҖҚзҡ„30жҳҜжңҹж•ёдёҚжҳҜйҮ‘йЎҚпјҢжңғиҮӘеӢ•и·ійҒҺ
    """
    # 1. е…Ҳжүҫжңүиҗ¬/Wеӯ—зҡ„пјҲжңҖеҸҜйқ пјү
    wan_patterns = [
        r"\((\d+)\)\s*\.\s*\((\d+)\)\s*иҗ¬",   # (5).(8)иҗ¬
        r"йҷҚж’Ҙ\s*(\d+(?:\.\d+)?)\s*иҗ¬",             # йҷҚж’Ҙ4иҗ¬
        r"жң¬еҲ©ж”Ө\s*(\d+(?:\.\d+)?)\s*иҗ¬",           # жң¬еҲ©ж”Ө50иҗ¬
        r"йҮ‘йЎҚ[:пјҡ]?\s*(\d+(?:\.\d+)?)\s*иҗ¬",       # йҮ‘йЎҚ20иҗ¬
        r"ж ё[еҮҶиІё]\s*йҮ‘йЎҚ?\s*[:пјҡ]?\s*(\d+(?:\.\d+)?)\s*иҗ¬",  # ж ёеҮҶйҮ‘йЎҚ20иҗ¬
        r"(\d+(?:\.\d+)?)\s*[Wwиҗ¬]",                 # 20иҗ¬ / 6W
    ]
    for pat in wan_patterns:
        m = re.search(pat, text)
        if m:
            if m.lastindex == 2:  # (5).(8)иҗ¬ж јејҸ
                return f"{m.group(1)}.{m.group(2)}иҗ¬"
            raw = m.group(1)
            try:
                num = float(raw)
                if num > 0:
                    return f"{int(num)}иҗ¬" if num == int(num) else f"{num}иҗ¬"
            except Exception:
                pass

    # 2. жүҫеӨ§ж•ёеӯ—пјҲи¶…йҒҺ10000иҰ–зӮәе…ғпјҢжҸӣз®—жҲҗиҗ¬пјү
    for m in re.finditer(r"(\d{1,3}(?:,\d{3})+|\d{5,})", text):
        num_str = m.group(1).replace(",", "")
        try:
            num = int(num_str)
            if num >= 10000:
                wan = num // 10000
                return f"{wan}иҗ¬"
        except Exception:
            pass

    # 3. жңҖеҫҢжүҚз”ЁгҖҢж ёеҮҶ+ж•ёеӯ—гҖҚпјҢдҪҶжҺ’йҷӨжңҹж•ё
    m = re.search(r"ж ёеҮҶ\s*(\d+)", text)
    if m:
        num = int(m.group(1))
        after = text[m.end():][:5]
        if num <= 60 and any(c in after for c in ["жңҹ", "пјҢ", ",", "/"]):
            pass  # йҖҷжҳҜжңҹж•ёпјҢи·ійҒҺ
        elif num > 0:
            return f"{num}иҗ¬"

    return ""



async def extract_approved_amount_with_ai(text: str) -> str:
    api_key = os.getenv("ANTHROPIC_API_KEY", "")
    if not api_key:
        return ""
    try:
        resp = req_lib.post(
            "https://api.anthropic.com/v1/messages",
            headers={"x-api-key": api_key, "anthropic-version": "2023-06-01", "content-type": "application/json"},
            json={"model": "claude-haiku-4-5-20251001", "max_tokens": 100, "messages": [{"role": "user", "content": f"""иІёж¬ҫж ёеҮҶиЁҠжҒҜеҰӮдёӢпјҢи«ӢеҲӨж–·жҳҜеҗҰзӮәзңҹжӯЈж ёеҮҶдёҰжҠ“еҮәйҮ‘йЎҚгҖӮ
иЁҠжҒҜпјҡ{text}
еҸӘеӣһеӮіJSONпјҢдёҚиҰҒе…¶д»–ж–Үеӯ—пјҡ{{"is_approved": trueжҲ–false, "amount": "йҮ‘йЎҚеӯ—дёІжҲ–з©әеӯ—дёІ"}}
йҮ‘йЎҚж јејҸеҰӮпјҡ20иҗ¬гҖҒ6иҗ¬гҖҒ50иҗ¬гҖӮжіЁж„Ҹпјҡжңҹж•ёдёҚжҳҜйҮ‘йЎҚпјҢжңҲд»ҳдёҚжҳҜйҮ‘йЎҚпјҢеҲқдј°/еҫ…иЈң/йңҖиЈң/з…§жңғ=falseгҖӮ"""}]},
            timeout=15,
        )
        if resp.status_code == 200:
            import json as jl
            result = resp.json()["content"][0]["text"].strip().replace("```json","").replace("```","").strip()
            data = jl.loads(result)
            if data.get("is_approved") and data.get("amount"):
                return data["amount"]
    except Exception as e:
        print(f"AIи§ЈжһҗеӨұж•—: {e}")
    return ""


def parse_disbursement_list(text: str) -> Dict:
    """
    и§Јжһҗж’Ҙж¬ҫеҗҚе–®ж јејҸпјҡ
    04/01 21 ж’Ҙж¬ҫеҗҚе–®
    еҗізҝ°жқ°
    и”Ўж–Үжқ°
    ...
    04/01 дәһеӨӘжҺ’ж’Ҙ
    жҙӘиҺүиҗҚ

    еӣһеӮі {"04/01": {"21": ["еҗізҝ°жқ°","и”Ўж–Үжқ°"], "дәһеӨӘ": ["жҙӘиҺүиҗҚ"]}}
    """
    result = {}
    current_date = ""
    current_company = ""

    # ж’Ҙж¬ҫеҗҚе–®жЁҷй ӯжӯЈеүҮпјҲжңүж—Ҙжңҹ + е…¬еҸёпјү
    DISB_HEADER_RE = re.compile(
        r"(\d{1,2}/\d{1,2})\s*([\wгҗҖ-йҝҝпӨҖ-п«ҝ]+?)\s*(ж’Ҙж¬ҫеҗҚе–®|й җиЁҲжҺ’ж’Ҙ|жҺ’ж’Ҙ|д»Ҡж—Ҙж’Ҙж¬ҫ|е•Ҷе“Ғж’Ҙж¬ҫ|ж©ҹи»Ҡж’Ҙж¬ҫ|жұҪи»Ҡж’Ҙж¬ҫ|ж’Ҙж¬ҫ)",
        re.IGNORECASE
    )
    # з„Ўе…¬еҸёжЁҷй ӯпјҲжңүж—ҘжңҹгҖҒз„Ўе…¬еҸёпјүпјҡгҖҢ4/24 ж’Ҙж¬ҫгҖҚ/гҖҢ4/24 ж’Ҙж¬ҫеҗҚе–®гҖҚ вҶ’ е…¬еҸёз©әеӯ—дёІгҖҒеҫҢйқўжҹҘжҜҸеҖӢе®ўжҲ¶зҡ„ж ёеҮҶе…¬еҸё
    DISB_HEADER_NOCO_RE = re.compile(
        r"^\s*(\d{1,2}/\d{1,2})\s*(ж’Ҙж¬ҫеҗҚе–®|й җиЁҲжҺ’ж’Ҙ|жҺ’ж’Ҙ|д»Ҡж—Ҙж’Ҙж¬ҫ|ж’Ҙж¬ҫ)\s*$",
        re.IGNORECASE
    )
    # з„Ўж—ҘжңҹжЁҷй ӯпјҡгҖҢиІёж•‘иЈң д»Ҡж—Ҙж’Ҙж¬ҫгҖҚ
    DISB_HEADER_NODATE_RE = re.compile(
        r"^([\wгҗҖ-йҝҝпӨҖ-п«ҝ]+?)\s*(ж’Ҙж¬ҫеҗҚе–®|й җиЁҲжҺ’ж’Ҙ|жҺ’ж’Ҙ|д»Ҡж—Ҙж’Ҙж¬ҫ|е•Ҷе“Ғж’Ҙж¬ҫ|ж©ҹи»Ҡж’Ҙж¬ҫ|жұҪи»Ҡж’Ҙж¬ҫ|ж’Ҙж¬ҫ)\s*$",
        re.IGNORECASE
    )

    today_date = now_tw().strftime("%#m/%#d") if os.name == "nt" else now_tw().strftime("%-m/%-d")

    lines = text.splitlines()
    for line in lines:
        line = line.strip()
        if not line:
            continue

        # з„Ўе…¬еҸёжЁҷй ӯпјҲ4/24 ж’Ҙж¬ҫпјүе„Әе…ҲжҜ”е°ҚпјҡйҒҝе…Қ "(date)(ж’Ҙж¬ҫ keyword)" иў« DISB_HEADER_RE жҠ“жҲҗ company=ж’Ҙж¬ҫ
        m_noco = DISB_HEADER_NOCO_RE.match(line)
        if m_noco:
            current_date = m_noco.group(1)
            current_company = ""  # з©ә = еҫҢйқўз”Ёе®ўжҲ¶зҡ„ж ёеҮҶе…¬еҸё
            if current_date not in result:
                result[current_date] = {}
            if current_company not in result[current_date]:
                result[current_date][current_company] = []
            continue

        m = DISB_HEADER_RE.search(line)
        if m:
            current_date = m.group(1)
            current_company = m.group(2).strip()
            # жҺ’йҷӨжҠҠгҖҢж’Ҙж¬ҫгҖҚиҮӘе·ұиӘӨз•¶е…¬еҸёеҗҚпјҲдҫӢеҰӮ "4/24 ж’Ҙж¬ҫ" ж•ҙж®өдәӮеҗғпјү
            if current_company in ("ж’Ҙж¬ҫ", "ж’Ҙж¬ҫеҗҚе–®", "жҺ’ж’Ҙ", "й җиЁҲжҺ’ж’Ҙ", "д»Ҡж—Ҙж’Ҙж¬ҫ"):
                continue
            if current_date not in result:
                result[current_date] = {}
            if current_company not in result[current_date]:
                result[current_date][current_company] = []
            continue

        # з„Ўж—ҘжңҹжЁҷй ӯпјҲеҰӮгҖҢиІёж•‘иЈң д»Ҡж—Ҙж’Ҙж¬ҫгҖҚпјүпјҢз”Ёд»Ҡж—Ҙж—Ҙжңҹ
        m2 = DISB_HEADER_NODATE_RE.match(line)
        if m2:
            current_date = current_date or today_date
            current_company = m2.group(1).strip()
            if current_date not in result:
                result[current_date] = {}
            if current_company not in result[current_date]:
                result[current_date][current_company] = []
            continue

        # еҗҚеӯ—иЎҢпјҲ2-4еҖӢдёӯж–Үеӯ—пјҢжҲ–еҗ«иӢұж–Үзҡ„е§“еҗҚпјү
        if current_date and current_company:
            name_m = re.match(r"^([гҗҖ-йҝҝпӨҖ-п«ҝ]{2,6})\s*$", line)
            if name_m:
                result[current_date][current_company].append(name_m.group(1))

    return result


def is_disbursement_list(text: str) -> bool:
    """еҲӨж–·жҳҜеҗҰзӮәж’Ҙж¬ҫеҗҚе–®пјҲеӨҡиЎҢж јејҸпјҢжЁҷй ӯ+дәәеҗҚиЎҢпјү"""
    lines = [l.strip() for l in (text or "").splitlines() if l.strip()]
    if len(lines) < 2:
        return False
    # иҮіе°‘дёҖиЎҢиҰҒжҳҜжЁҷй ӯпјҲеҗ«ж’Ҙж¬ҫй—ңйҚөи©һпјү
    header_re = re.compile(
        r"(ж’Ҙж¬ҫеҗҚе–®|жҺ’ж’Ҙ|й җиЁҲжҺ’ж’Ҙ|д»Ҡж—Ҙж’Ҙж¬ҫ|е•Ҷе“Ғж’Ҙж¬ҫ|ж©ҹи»Ҡж’Ҙж¬ҫ|жұҪи»Ҡж’Ҙж¬ҫ|ж’Ҙж¬ҫ)"
    )
    has_header = False
    header_idx = -1
    for i, line in enumerate(lines):
        if header_re.search(line):
            has_header = True
            header_idx = i
            break
    if not has_header:
        return False
    # жЁҷй ӯеҫҢйқўиҮіе°‘иҰҒжңүдёҖиЎҢзҙ”дәәеҗҚпјҲ2-4еҖӢдёӯж–Үеӯ—пјү
    name_re = re.compile(r"^[гҗҖ-йҝҝпӨҖ-п«ҝ]{2,6}$")
    for line in lines[header_idx + 1:]:
        if name_re.match(line):
            return True
    return False


def get_admin_group_for_sales(sales_group_id: str) -> Optional[str]:
    """
    жүҫе°ҚжҮүзҡ„иЎҢж”ҝзҫӨIDгҖӮ
    е„Әе…ҲжүҫжңүиЁӯе®ҡ linked_sales_group_id е°ҚжҮүзҡ„пјҢ
    жүҫдёҚеҲ°е°ұжүҫд»»дҪ•е•ҹз”Ёзҡ„иЎҢж”ҝзҫӨпјҲжүҖжңүжҘӯеӢҷзҫӨе…ұз”ЁдёҖеҖӢиЎҢж”ҝзҫӨзҡ„жғ…жіҒпјүгҖӮ
    """
    conn = get_conn(); cur = conn.cursor()
    # е…ҲжүҫжңүжҳҺзўәе°ҚжҮүзҡ„
    cur.execute("""
        SELECT group_id FROM groups
        WHERE group_type='ADMIN_GROUP' AND linked_sales_group_id=? AND is_active=1
        LIMIT 1
    """, (sales_group_id,))
    row = cur.fetchone()
    if row:
        conn.close()
        return row["group_id"]
    # жүҫдёҚеҲ°е°ұз”Ёд»»дҪ•е•ҹз”Ёзҡ„иЎҢж”ҝзҫӨ
    cur.execute("""
        SELECT group_id FROM groups
        WHERE group_type='ADMIN_GROUP' AND is_active=1
        LIMIT 1
    """)
    row = cur.fetchone(); conn.close()
    return row["group_id"] if row else None


def get_all_admin_groups() -> List[str]:
    """еҸ–еҫ—жүҖжңүе•ҹз”Ёзҡ„иЎҢж”ҝзҫӨIDпјҲз”Ёж–је»Јж’ӯж’Ҙж¬ҫеҗҚе–®пјү"""
    conn = get_conn(); cur = conn.cursor()
    cur.execute("SELECT group_id FROM groups WHERE group_type='ADMIN_GROUP' AND is_active=1")
    rows = cur.fetchall(); conn.close()
    return [r["group_id"] for r in rows]


# =========================
# зӢҖж…Ӣж‘ҳиҰҒжҸҗеҸ–
# =========================
_INTERNAL_ACTION_KEYWORDS = [
    "иЁӯйҖҒд»¶", "ж ёеҮҶйҮ‘йЎҚдҝ®ж”№зӮә", "иҪүйҖҒ", "еҠ йҖҒ/еӮҷиЁ»", "еҠ йҖҒ",
    "ж”№еҗҚзӮә",            # ж”№еҗҚеӢ•дҪңж–Үеӯ—
    "ж”№иә«еҲҶиӯү",          # ж”№иә«еҲҶиӯүеӢ•дҪңж–Үеӯ—
    "йҮҚе•ҹжЎҲд»¶",          # йҮҚе•ҹеӢ•дҪң
    "йӮ„еҺҹеҲ°",            # йӮ„еҺҹеӢ•дҪң
    "дёҚйҖҒпјҡ",            # A ж–№жЎҲз§»йҷӨеҗҢйҖҒ
    "е©үжӢ’пјҲеҫһеҗҢйҖҒ",      # reject_company з§»йҷӨеҗҢйҖҒ
    "еҢҜе…Ҙ",              # еҢҜе…ҘеӢ•дҪңпјҲ/admin/import-loan зӯүпјү
    "жҗ¬еҲ°гҖҗ",            # зҫӨзө„жҗ¬з§»еӢ•дҪң
    "ж”№й ҶеәҸпјҡ",          # ж”№йҖҒд»¶й ҶеәҸеӢ•дҪң
    # зјәд»¶жҢҮд»Өзҡ„е…§йғЁзҙҖйҢ„ж–Үеӯ—пјҲpending_docs ж¬„дҪҚеҸҰеӨ–йЎҜзӨәзӮәгҖҢ(зјәXX)гҖҚгҖҒ
    # дёҚиҰҒи®“ last_update зҡ„йҖҷдәӣж–Үеӯ—иў« extract_status_summary з•¶зӢҖж…ӢжҠ“еҮәдҫҶпјү
    # жіЁж„ҸпјҡгҖҢе·ІиЈңпјҡгҖҚдёҚеҸҜеҠ е…ҘгҖҒжңғиӘӨж®әжӯЈеёёгҖҢе·ІиЈңжҷӮж®ө/е·ІиЈңз…§жңғ/е·ІиЈңиіҮж–ҷгҖҚзӢҖж…Ӣ
    "зјәд»¶пјҡ",            # @AI е§“еҗҚ зјә XX
    "зјәд»¶е·Іе…ЁйғЁиЈңе®Ң",    # @AI е§“еҗҚ е·ІиЈң е…ЁйғЁ
    "зјәд»¶иЈңе®Ң:",         # mark_doc_completed йҮқе°Қ pending_docs й …зӣ®зҡ„е…§йғЁзҙҖйҢ„
    "з…§жңғи©ұиЎ“",          # @AI е§“еҗҚ е…¬еҸё з…§жңғпјҲи§ёзҷји©ұиЎ“жҢҮд»ӨгҖҒдёҚжҳҜ statusпјү
    "[з¶Ій Ғз·ЁијҜ]",        # /case-edit й җиЁӯ last_update жЁҷиЁҳгҖҒдёҚжҳҜ status
    "з¶Ій Ғдҝ®ж”№жЎҲд»¶зӢҖж…Ӣ",  # жҺЁеҲ°зҫӨзө„зҡ„з¶Ій Ғз·ЁијҜйҖҡзҹҘгҖҒдёҚжҳҜ status
]


def extract_status_summary(first_line: str, customer_name: str) -> str:
    """
    еҫһиЁҠжҒҜз¬¬дёҖиЎҢжҸҗеҸ–зӢҖж…Ӣй—ңйҚөеӯ—пјҢз”Ёж–јж—Ҙе ұйЎҜзӨәгҖӮ
    жЁҷжә–еҢ–жЁҷзұӨпјҡ
    - жңүж ёеҮҶ вҶ’ гҖҢж ёеҮҶгҖҚ
    - иЈңз…§жңғ/з…§жңғ вҶ’ гҖҢе·ІиЈңз…§жңғгҖҚ
    - иЈңз”іиҰҶ/з”іиҰҶ вҶ’ гҖҢе·ІиЈңз”іиҰҶгҖҚ
    - иЈңд»¶йЎһ вҶ’ гҖҢе·ІиЈңиіҮж–ҷгҖҚ
    - NA/жңӘжҺҘз…§жңғ вҶ’ гҖҢNAгҖҚ
    - е…¶д»– вҶ’ йЎҜзӨәеүҚ20еӯ—
    """
    if not first_line:
        return ""
    # е…§йғЁеӢ•дҪңпјҲ@AI жҢҮд»Өз”ўз”ҹзҡ„иЁҳйҢ„ж–Үеӯ—пјүдёҚйЎҜзӨәзӮәжҘӯеӢҷзӢҖж…Ӣ
    if any(kw in first_line for kw in _INTERNAL_ACTION_KEYWORDS):
        return ""
    # з…§жңғи©ұиЎ“жҢҮд»Өж јејҸпјҡгҖҢ{е§“еҗҚ} з…§жңғ {е…¬еҸё}гҖҚ = жҘӯеӢҷи§ёзҷји©ұиЎ“гҖҒдёҚжҳҜ status
    # е…је®№иҲҠзүҲпјҲlast_update еҜ«гҖҢз…§жңғгҖҚжІ’гҖҢи©ұиЎ“гҖҚеӯ—е°ҫпјү
    if re.match(r"^[гҗҖ-йҝҝпӨҖ-п«ҝ.пјҺВ·вҖўгғ»вҖ§]{2,12}\s+з…§жңғ\s+", first_line):
        return ""
    # е°ҚдҝқеҘҪпјҲдёҚз°ҪдёҚж”¶ / дёҚж”¶дёҚз°ҪпјүвҶ’ гҖҢе°ҚеҘҪгҖҚ
    if "е°ҚеҘҪ" in first_line or "дёҚз°ҪдёҚж”¶" in first_line or "дёҚж”¶дёҚз°Ҫ" in first_line:
        return "е°ҚеҘҪ"
    # ж’Ҙж¬ҫйҡҺж®өе®ўжҲ¶йӣ»и©ұжңӘжҺҘ вҶ’ гҖҢж’Ҙж¬ҫжңӘжҺҘгҖҚжҸҗйҶ’иҰҒеӮ¬е®ўжҲ¶жҺҘйӣ»и©ұ
    if "ж’Ҙж¬ҫйӣ»и©ұжңӘжҺҘ" in first_line or "ж’Ҙж¬ҫжңӘжҺҘ" in first_line:
        return "ж’Ҙж¬ҫжңӘжҺҘ"
    # A зҫӨи«ӢжҘӯеӢҷиЈңжҷӮж®өпјҡгҖҢи«ӢжҸҗдҫӣXXеҸҜз…§жңғжҷӮй–“гҖҚгҖҢи«ӢжҸҗдҫӣз…§жңғжҷӮж®өгҖҚвҶ’ еҫ…иЈңжҷӮж®ө
    if ("и«ӢжҸҗдҫӣ" in first_line or "еҶҚйә»з…©" in first_line) and ("з…§жңғ" in first_line or "жҷӮж®ө" in first_line or "жҷӮй–“" in first_line):
        return "еҫ…иЈңжҷӮж®ө"
    # е©үжӢ’ вҶ’ гҖҢе©үжӢ’гҖҚзҹӯеҪўејҸпјҲе©үжӢ’еҫҢе®ўжҲ¶йҖҡеёёе·ІиҪүдёӢдёҖе®¶гҖҒдёҚйңҖиҰҒеңЁеҺҹе®¶ section з•ҷзҗҶз”ұпјү
    if "е©үжӢ’" in first_line:
        return "е©үжӢ’"
    # гҖҢеҫ…ж ёеҮҶ/еҫ…ж ёжә–гҖҚпјҡжҳҺзўәйӮ„жІ’ж ёеҮҶ вҶ’ дҝқз•ҷе®Ңж•ҙеӮҷиЁ»пјҲеҗ«йҮ‘йЎҚ/иЈңд»¶иіҮиЁҠпјүпјҢдёҚиҰҒз№јзәҢеҫҖдёӢиӘӨеҲӨжҲҗгҖҢе·ІиЈңгҖҚ
    if "еҫ…ж ёеҮҶ" in first_line or "еҫ…ж ёжә–" in first_line:
        import re as _re
        m = _re.search(r"еҫ…ж ё[еҮҶжә–]\s*(\d+(?:\.\d+)?\s*иҗ¬?)", first_line)
        if m:
            return f"еҫ…ж ёеҮҶ{m.group(1).strip()}"
        return "еҫ…ж ёеҮҶ"
    # е…ҲжҹҘжҳҜеҗҰзңҹжӯЈж ёеҮҶ
    text_wo_pending = first_line.replace("еҫ…ж ёеҮҶ", "").replace("еҫ…ж ёжә–", "")
    if "ж ёеҮҶ" in text_wo_pending or "ж ёжә–" in text_wo_pending:
        # ж ёеҮҶеҫҢйӮ„йңҖжҺҘз…§жңғ вҶ’ гҖҢж ёеҮҶеҫ…з…§жңғгҖҚпјҲжҺ’йҷӨгҖҢе·ІжҺҘз…§жңғгҖҚгҖҢз…§жңғе®ҢгҖҚ= зңҹжӯЈе®ҢжҲҗпјү
        has_need_contact = any(w in first_line for w in ["жҺҘз…§жңғ", "еҫ…з…§жңғ", "йңҖз…§жңғ", "зӯүз…§жңғ", "еҶҚз…§жңғ"])
        has_done_contact = any(w in first_line for w in ["е·ІжҺҘз…§жңғ", "з…§жңғе®Ң", "з…§жңғйҒҺ", "жҺҘе®Ңз…§жңғ"])
        if has_need_contact and not has_done_contact:
            return "ж ёеҮҶеҫ…з…§жңғ"
        return "ж ёеҮҶ"
    # е·ІиЈңжҷӮж®өпјҲжҘӯеӢҷе·Із¶“жҸҗдҫӣз…§жңғжҷӮй–“пјүвҶ’ жҳҺзўәгҖҢе·ІиЈңгҖҚпјҢе„Әе…ҲиӯҳеҲҘ
    if "е·ІиЈңжҷӮж®ө" in first_line:
        tm = re.search(r"(\d{1,2}[:пјҡй»һ]\d{0,2}(?:\s*[-~пҪһиҮіеҲ°]\s*\d{1,2}[:пјҡй»һ]?\d{0,2})?)", first_line)
        if tm:
            tr = tm.group(1).replace("~", "~").replace("-", "~").replace("иҮі", "~").replace("еҲ°", "~").replace("пјҡ", ":")
            return f"е·ІиЈңжҷӮж®ө {tr}"
        return "е·ІиЈңжҷӮж®ө"
    # иЈңжҷӮж®өпјҲз…§жңғжҷӮж®өпјүпјҡгҖҢиЈңжҷӮж®ө 11:00~12:00гҖҚжҲ–гҖҢиЈңжҷӮж®ө 11й»һ~12й»һгҖҚ= еҫ…иЈң
    m_notif_time = re.search(r"иЈңжҷӮж®ө\s*(\d{1,2}(?:[:пјҡ]\d{1,2}|й»һ)?\s*[~пҪһ\-иҮіеҲ°]\s*\d{1,2}(?:[:пјҡ]\d{1,2}|й»һ)?)", first_line)
    if m_notif_time:
        time_range = m_notif_time.group(1).replace("~", "~").replace("-", "~").replace("иҮі", "~").replace("еҲ°", "~").replace("пјҡ", ":")
        return f"з…§жңғжҷӮж®ө {time_range}"

    # гҖҢеҫ…ж ёеҮҶгҖҚдёӢж–№еҲӨж–·жңғиҷ•зҗҶе…·й«”зјәй …пјҲиЈңз…§жңғ/иЈңз”іиҰҶ/иЈңд»¶йЎһпјүпјӣиӢҘйғҪжІ’е‘ҪдёӯпјҢжңҖеҫҢ fallbackгҖҢеҫ…ж ёеҮҶгҖҚ
    # зӯүдҝқжӣёзҙ°еҲҶпјҡж №ж“ҡиЁҠжҒҜе…§е…¶д»–й—ңйҚөеӯ—жұәе®ҡеҜҰйҡӣеӯҗзӢҖж…Ӣ
    if "зӯүдҝқжӣё" in first_line or "зӯүдҝқдәә" in first_line:
        # жҸӣдҝқдәәйЎһпјҡжӣҙжҸӣ/дёҚеҗҲж ј/еҸҰжүҫ/жҸӣдёҖдҪҚ/жҸӣеҖӢ
        if any(k in first_line for k in ["жӣҙжҸӣ", "жҸӣдёҖдҪҚ", "жҸӣеҖӢ", "жҸӣеҸҰ", "дёҚеҗҲж ј", "дёҚз¬ҰеҗҲ", "йҮҚжүҫ", "еҸҰжүҫ", "еҸҰеӨ–жүҫ", "еҶҚжүҫ"]):
            return "жҸӣдҝқдәә"
        # иЈңдҝқдәәйЎһпјҡжІ’дҝқдәә/йӮ„жІ’/йңҖиЈң/жҸҗдҫӣдҝқдәә
        if any(k in first_line for k in ["иЈңдҝқдәә", "жІ’дҝқдәә", "жІ’жңүдҝқдәә", "жүҫдҝқдәә", "жҸҗдҫӣдҝқдәә"]):
            return "иЈңдҝқдәә"
        # з°ҪеҗҚйЎһ
        if any(k in first_line for k in ["з°ҪеҗҚ", "зӯүз°Ҫ", "иҰӘз°Ҫ", "еҫ…з°Ҫ"]):
            return "зӯүдҝқдәәз°Ҫ"
        # иЈңиіҮж–ҷ/ж–Үд»¶йЎһ
        if any(k in first_line for k in ["дҝқдәәиЈң", "дҝқжӣёиЈң", "иЈңиіҮж–ҷ", "иЈңд»¶", "иіҮж–ҷдёҚйҪҠ"]):
            return "дҝқдәәиЈңд»¶"
        # д»Җйәјзү№е®ҡй—ңйҚөеӯ—йғҪжІ’ вҶ’ йЎҜзӨәгҖҢзӯүдҝқжӣёгҖҚ
        return "зӯүдҝқжӣё"
    # е·ІиЈңз…§жңғ / з…§жңғе®Ң / жҺҘе®Ңз…§жңғ вҶ’ е·Іе®ҢжҲҗпјҲе…ҲжҹҘпјҢйҒҝе…Қе‘ҪдёӯдёӢйқўзҡ„гҖҢиЈңз…§жңғгҖҚпјү
    if "е·ІиЈңз…§жңғ" in first_line or "з…§жңғе®Ң" in first_line or "жҺҘе®Ңз…§жңғ" in first_line:
        return "е·ІиЈңз…§жңғ"
    if "иЈңз…§жңғ" in first_line:
        # еҰӮжһңжңүжҷӮж®өпјҲжҷӮй–“еӯ—жҲ–ж•ёеӯ—:ж•ёеӯ—пјүвҶ’ йЎҜзӨәжҷӮж®ө
        import re as _re
        tm = _re.search(r"(\d{1,2}[:пјҡй»һ]\d{0,2}(?:[-~иҮіеҲ°]\d{1,2}[:пјҡй»һ]?\d{0,2})?)", first_line)
        if tm:
            return f"иЈңз…§жңғ{tm.group(1)}"
        return "еҫ…иЈңз…§жңғ"
    # иЈңз№іж¬ҫ/иЈңз№іжҒҜпјҡз§»йҷӨ specific checkгҖҒи®“ generic fallback жҠ“гҖҢе…¬еҸёд№ӢеҫҢгҖҚе…Ёж–Ү
    # пјҲжҘӯеӢҷеҜ«гҖҢе·ІиЈңз№іжҒҜ жҷӮж®өгҖҚ/гҖҢеҫ…иЈңз№іжҒҜгҖҚ/гҖҢиЈңз№іжҒҜ+з…§жңғгҖҚйғҪи®“ generic иҷ•зҗҶпјү
    # гҖҢз…§жңғгҖҚ generic = е·ІйҖҒд»¶ вҶ’ з§»йҷӨпјҲи®“ generic fallback жҠ“зңҹеҜҰ status textгҖҒйҒҝе…ҚеҗғжҺү compound зӢҖж…Ӣпјү
    # иЈңд»¶/з”іиҰҶеҲӨж–·пјҡ
    # - жҳҺзўәгҖҢе·ІиЈңгҖҚ/гҖҢеҫ…иЈңгҖҚй—ңйҚөеӯ—е„Әе…Ҳ
    # - жҘӯеӢҷдё»еӢ•иӘһж°ЈпјҲжҘӯеӢҷиӘӘ/жҲ‘иЈң/е№«иЈң/иЈңеҘҪ/иЈңе®ҢпјүвҶ’ е·ІиЈң
    # - еҸӘжңүгҖҢиЈңXXгҖҚеҗ«зіҠ вҶ’ й җиЁӯеҫ…иЈңпјҲйңҖи·іжҢүйҲ•з”ұжҘӯеӢҷзўәиӘҚпјү
    _business_done_markers = ["жҘӯеӢҷиӘӘ", "жҲ‘иЈң", "жҲ‘е·ІиЈң", "е№«иЈң", "дё»еӢ•иЈң", "иЈңеҘҪдәҶ", "иЈңе®ҢдәҶ",
                              "иЈңйҒҺдәҶ", "жҘӯеӢҷиЈң", "иЈңе®ҢжҲҗ"]
    _explicit_pending_markers = ["еҫ…иЈң", "и«ӢиЈң", "иҰҒиЈң", "зјә", "жңӘиЈң", "йӮ„жІ’иЈң", "е°ҡзјә",
                                  "и«ӢжҸҗдҫӣ", "йә»з…©иЈң", "йңҖиЈң"]

    # з”іиҰҶйЎһ
    if "з”іиҰҶ" in first_line:
        # жҳҺзўәе·ІиЈңпјҡгҖҢе·ІиЈң XX з”іиҰҶгҖҚгҖҢз”іиҰҶе®Ң/йҖҡйҒҺ/еҘҪгҖҚгҖҢе·ІжӣҙжҸӣ / е·ІжҸҗдҫӣ / иЈңи¶ігҖҚзӯүе·Іиҷ•зҗҶй—ңйҚөеӯ—
        if ("е·ІиЈң" in first_line or "з”іиҰҶе®Ң" in first_line or "з”іиҰҶйҖҡйҒҺ" in first_line
            or "з”іиҰҶеҘҪ" in first_line or "иЈңе®Ңз”іиҰҶ" in first_line or "иЈңеҘҪз”іиҰҶ" in first_line
            or "е·ІжӣҙжҸӣ" in first_line or "е·ІжҸҗдҫӣ" in first_line or "иЈңи¶і" in first_line):
            return "е·ІиЈңз”іиҰҶ"
        # жҳҺзўәеҫ…иЈңпјҡгҖҢеҫ…иЈң/и«ӢиЈң/иҰҒиЈң/зјәгҖҚзӯү
        if any(m in first_line for m in _explicit_pending_markers):
            return "еҫ…иЈңз”іиҰҶ"
        # C ж–№жЎҲпјҡжҘӯеӢҷдё»еӢ•иӘһж°Ј вҶ’ е·ІиЈң
        if any(m in first_line for m in _business_done_markers):
            return "е·ІиЈңз”іиҰҶ"
        # еҗ«зіҠгҖҢиЈң X з”іиҰҶгҖҚвҶ’ й җиЁӯеҫ…иЈң
        return "еҫ…иЈңз”іиҰҶ"

    # иЈңд»¶йЎһпјҡе…ҲжҜ”е°Қе…·й«”й …зӣ®пјҲдҝқдәә/иҒҜеҫө/и–ӘиҪү зӯүпјүвҶ’ йЎҜзӨәе…·й«”зӢҖж…Ӣпјӣ
    # жІ’е‘Ҫдёӯе…·й«”й …зӣ®жүҚ fallback еҲ°гҖҢеҫ…иЈңиіҮж–ҷ / е·ІиЈңиіҮж–ҷгҖҚжіӣзӢҖж…Ӣ
    # й ҶеәҸпјҡдҝқдәә / иҒҜеҫө / и–ӘиҪү ... вҶ’ и¶Ҡзү№е®ҡи¶ҠеүҚйқўгҖҒйҒҝе…Қиў«гҖҢиЈңд»¶гҖҚжіӣеӯ—и“ӢжҺү
    _specific_supp = [
        ("иЈңдҝқдәә", "дҝқдәә"), ("зјәдҝқдәә", "дҝқдәә"), ("иЈңдҝқ", "дҝқдәә"),  # гҖҢиЈңдҝқгҖҚзҹӯеҜ« = дҝқдәә
        ("иЈңиҒҜеҫө", "иҒҜеҫө"), ("зјәиҒҜеҫө", "иҒҜеҫө"),
        ("иЈңJCIC", "JCIC"), ("иЈңjcic", "JCIC"), ("зјәJCIC", "JCIC"), ("зјәjcic", "JCIC"),
        ("иЈңи–ӘиҪү", "и–ӘиҪү"), ("зјәи–ӘиҪү", "и–ӘиҪү"),
        ("иЈңеңЁиҒ·", "еңЁиҒ·"), ("зјәеңЁиҒ·", "еңЁиҒ·"),
        ("иЈңеӯҳж‘ә", "еӯҳж‘ә"), ("зјәеӯҳж‘ә", "еӯҳж‘ә"),
        ("иЈңеӢһдҝқ", "еӢһдҝқ"),
        ("иЈңй§•з…§", "й§•з…§"),
        ("иЈңиә«еҲҶиӯү", "иә«еҲҶиӯү"),
        ("иЈңиЎҢз…§", "иЎҢз…§"),
        ("иЈңжҷӮж®ө", "жҷӮж®ө"),
        ("иЈңз…§зүҮ", "з…§зүҮ"),
    ]
    _bu_generic = ["иЈңд»¶", "иЈңиіҮж–ҷ", "зјәиіҮж–ҷ"]
    _has_done = ("е·ІиЈң" in first_line or "иЈңеҘҪ" in first_line or "иЈңе®Ң" in first_line
                 or any(m in first_line for m in _business_done_markers))
    for kw, item in _specific_supp:
        if kw in first_line:
            return f"е·ІиЈң{item}" if _has_done else f"еҫ…иЈң{item}"
    if any(w in first_line for w in _bu_generic):
        return "е·ІиЈңиіҮж–ҷ" if _has_done else "еҫ…иЈңиіҮж–ҷ"
    if "жңӘжҺҘз…§жңғ" in first_line or first_line.strip().endswith("NA") or " NA" in first_line:
        return "NA"
    # гҖҢеҫ…ж ёеҮҶгҖҚfallbackпјҡжІ’е‘Ҫдёӯе…·й«”иЈңд»¶/з…§жңғ вҶ’ зӣҙжҺҘйЎҜзӨәгҖҢеҫ…ж ёеҮҶгҖҚ
    if "еҫ…ж ёеҮҶ" in first_line or "еҫ…ж ёжә–" in first_line:
        return "еҫ…ж ёеҮҶ"

    # еҺ»жҺүе®ўжҲ¶е§“еҗҚ
    text = first_line.replace(customer_name, "").strip()

    # еҺ»жҺүиә«еҲҶиӯү/еұ…з•ҷиӯүпјҲйҒҝе…Қиә«еҲҶиӯүжң«зўјиў«з•¶зӢҖж…Ӣж–Үеӯ—пјү
    text = re.sub(r"[A-Z][A-Z0-9]\d{8}", "", text, flags=re.IGNORECASE).strip()

    # еҺ»жҺүй–Ӣй ӯзҡ„ж—ҘжңҹеүҚз¶ҙпјҲиҰҒеҫҢйқўжҺҘ dash жҲ–з©әзҷҪжүҚз®—ж—ҘжңҹеүҚз¶ҙпјӣеғҸгҖҢ4/27зәҢеҜ©гҖҚдҝқз•ҷпјү
    text = re.sub(r"^\d{1,4}/\d{1,2}(/\d{1,2})?[-пјҚ\s]+", "", text).strip()

    # йҖҒд»¶й ҶеәҸж јејҸпјҲеӨҡе®¶е…¬еҸёд»Ҙ / еҲҶйҡ”пјүвҶ’ зӣҙжҺҘдҝқз•ҷеҺҹж–ҮпјҢдёҚеүқе…¬еҸёеҗҚ
    if "/" in text and re.search(r"[\u3400-\u9fff\uf900-\ufaff0-9]+/[\u3400-\u9fff\uf900-\ufaff0-9]+", text):
        return text[:40]
    # еҺ»жҺүе…¬еҸёеҗҚзЁұпјҲCOMPANY_LIST + COMPANY_ALIAS еҲҘеҗҚпјү
    all_companies = list(COMPANY_LIST) + list(COMPANY_ALIAS.keys())
    for c in sorted(all_companies, key=len, reverse=True):
        text = text.replace(c, "").strip()

    # еҺ»жҺүгҖҗNгҖ‘д№ӢеҫҢзҡ„е…§е®№
    text = re.sub(r"гҖҗ\d+гҖ‘.*", "", text).strip()

    # еҺ»жҺүз©әжӢ¬иҷҹпјҲе…¬еҸёеҗҚиў«жё…жҺүеҫҢз•ҷдёӢзҡ„жӢ¬иҷҹпјү
    text = re.sub(r"[\(пјҲ][\s]*[\)пјү]", "", text).strip()

    # еҺ»жҺүеӨҡйӨҳжЁҷй»һ
    text = re.sub(r"^[-пјҚ/\s()пјҲпјү]+|[-пјҚ/\s()пјҲпјү]+$", "", text).strip()

    # гҖҢзјәXXгҖҚж–Үеӯ—иӢҘжҳҜ pending_docs з”ЁгҖҢзјәд»¶пјҡгҖҚж јејҸиЁҳйҢ„зҡ„е…§йғЁзҙҖйҢ„гҖҒдёҚйЎҜзӨә
    # дҪҶгҖҢзјәеҗҲз…§/зјәPDFгҖҚзӯүиҮӘз„¶иӘһж°Јж–Үеӯ—пјҲжҘӯеӢҷжҢҮе®ҡзү№е®ҡе…¬еҸёзјәд»¶пјүдҝқз•ҷйЎҜзӨә
    # ж”№з”ұ _INTERNAL_ACTION_KEYWORDS иҷ•зҗҶгҖҢзјәд»¶пјҡгҖҚеҗһжҺүгҖҒиҮӘз„¶иӘһж°Јз•ҷдёӢ

    # еҸӘеҸ–еүҚ20еӯ—
    return text[:12] if text else ""


# =========================
# ж—Ҙе ұз”ўз”ҹ
# =========================
# е…¬еҸёеӯҗеҲҶйЎһжӯёеҲ°ж—Ҙе ұдё»ж¬„дҪҚ
COMPANY_SECTION_MAP = {
    # е’ҢиЈ•жүҖжңүж–№жЎҲ вҶ’ е…ЁйғЁжӯёеҲ°гҖҢе’ҢиЈ•гҖҚж¬„дҪҚ
    "е’ҢиЈ•е•Ҷе“Ғ": "е’ҢиЈ•", "з¶ӯеҠӣе•Ҷе“ҒиІё": "е’ҢиЈ•",
    "е’ҢиЈ•ж©ҹи»Ҡ": "е’ҢиЈ•", "е’ҢиЈ•ж©ҹ": "е’ҢиЈ•",
    "з¶ӯеҠӣж©ҹи»Ҡе°Ҳ": "е’ҢиЈ•", "з¶ӯеҠӣж©ҹи»ҠиІё": "е’ҢиЈ•",
    # дәһеӨӘжүҖжңүж–№жЎҲ вҶ’ е…ЁйғЁжӯёеҲ°гҖҢдәһеӨӘгҖҚж¬„дҪҚ
    "дәһеӨӘе•Ҷе“Ғ": "дәһеӨӘ", "дәһеӨӘе·Ҙжңғ": "дәһеӨӘ", "дәһеӨӘе·Ҙ": "дәһеӨӘ",
    "дәһеӨӘж©ҹи»Ҡ": "дәһеӨӘ", "дәһеӨӘж©ҹ": "дәһеӨӘ",
    # 21ж–№жЎҲ вҶ’ ж©ҹи»Ҡ/е•Ҷе“Ғ/25иҗ¬ жӯёеҲ°гҖҢ21гҖҚж¬„дҪҚгҖҒдҪҶ 21жұҪи»ҠзҚЁз«ӢеҚҖеЎҠ
    "21ж©ҹи»Ҡ": "21",
    "21ж©ҹ": "21", "21ж©ҹ25": "21", "21ж©ҹ25иҗ¬": "21",
    "21ж©ҹи»Ҡ12иҗ¬": "21", "21ж©ҹи»Ҡ25иҗ¬": "21",
    # 21жұҪи»Ҡ / 21жұҪ дёҚжӯёеҲ° 21гҖҒдҝқз•ҷеҗ„иҮӘзҚЁз«ӢеҚҖеЎҠпјҲREPORT_SECTION_1 е·Іеҗ«гҖҢ21жұҪи»ҠгҖҚпјү
    "21жұҪ": "21жұҪи»Ҡ",
    # еҲҶиІқж–№жЎҲ вҶ’ еҗ„иҮӘж¬„дҪҚ
    "еҲҶиІқжұҪ": "еҲҶиІқжұҪи»Ҡ",
    "еҲҶиІқж©ҹ": "еҲҶиІқж©ҹи»Ҡ",
    # еүөйү…ж–№жЎҲ вҶ’ е…ЁйғЁжӯёеҲ°гҖҢеүөйү…гҖҚж¬„дҪҚ
    "еүөйү…жүӢж©ҹ": "еүөйү…", "еүөйү…жүӢ": "еүөйү…",
    "еүөйү…ж©ҹи»Ҡ": "еүөйү…", "еүөйү…ж©ҹ": "еүөйү…",
    # йә»еҗүж–№жЎҲ вҶ’ е…ЁйғЁжӯёеҲ°гҖҢйә»еҗүгҖҚж¬„дҪҚ
    "йә»еҗүж©ҹи»Ҡ": "йә»еҗү", "йә»еҗүж©ҹ": "йә»еҗү",
    "йә»еҗүжүӢж©ҹ": "йә»еҗү", "йә»еҗүжүӢ": "йә»еҗү",
    # её¶йҮ‘йЎҚзүҲжң¬ вҶ’ дё»е…¬еҸё
    "дәһеӨӘе·Ҙ15": "дәһеӨӘ", "дәһеӨӘ25": "дәһеӨӘ", "дәһеӨӘ15": "дәһеӨӘ",
    "дәһеӨӘжұҪи»Ҡ": "дәһеӨӘ",
    "дәһеӨӘж©ҹ25иҗ¬": "дәһеӨӘ", "дәһеӨӘж©ҹи»Ҡ25иҗ¬": "дәһеӨӘ", "дәһеӨӘж©ҹи»Ҡ15иҗ¬": "дәһеӨӘ",
    "21е•Ҷе“Ғ": "21",
    "еҗҲдҝЎж©ҹи»Ҡ": "еҗҲдҝЎ", "еҗҲдҝЎжүӢж©ҹ": "еҗҲдҝЎ", "еҗҲдҝЎдәҢијӘ": "еҗҲдҝЎ",
    "з¬¬дёҖе•Ҷе“Ғ": "з¬¬дёҖ", "з¬¬дёҖж©ҹи»Ҡ": "з¬¬дёҖ",
    "е–¬зҫҺ40": "е–¬зҫҺ", "е–¬зҫҺ14": "е–¬зҫҺ",
    "иҲҲйҒ”ж©ҹи»Ҡ": "иҲҲйҒ”", "иҲҲйҒ”ж©ҹ": "иҲҲйҒ”",
    "з¶ӯеҠӣ": "е’ҢиЈ•",
    "й җд»ҳжүӢж©ҹ": "й җд»ҳжүӢж©ҹеҲҶжңҹ",
    # ж–°й‘«/еңҹең° вҶ’ жҲҝең°
    "ж–°й‘«": "жҲҝең°", "еңҹең°": "жҲҝең°",
    "дј°жҲҝ": "жҲҝең°", "дј°еңҹең°": "жҲҝең°",
    # еҗ‘дёӢзӣёе®№иҲҠеӯ—
    "иІёе°ұиЈң": "иІёж•‘иЈң",
    # ж°‘й–“ж–№жЎҲз°ЎзЁұ
    "й„ү": "й„үж°‘", "з ”": "е•Ҷе“ҒиІё", "з•¶": "з•¶иҲ–е°ҲжЎҲ", "е•Ҷ": "е•Ҷе“ҒиІё",
    "йҠҖи§’": "йӣ¶еҚЎ", "ж…ўй»һд»ҳ": "йӣ¶еҚЎ", "еҲҶжңҹи¶Ј": "йӣ¶еҚЎ",
    # йјҺеӨҡ = е–¬зҫҺ
    "йјҺеӨҡ": "е–¬зҫҺ",
}

def normalize_section(section: str) -> str:
    """ж—Ҙе ұеҚҖеЎҠиҰҸзҜ„еҢ–гҖӮе„Әе…ҲжҹҘ COMPANY_SECTION_MAPпјҢfallback з”Ё COMPANY_ALIASгҖӮ
    дҫӢпјҡгҖҢе…ғеӨ§гҖҚвҶ’ COMPANY_SECTION_MAP з„Ў вҶ’ COMPANY_ALIASгҖҢе…ғеӨ§вҶ’йҠҖиЎҢгҖҚвҶ’ жӯёгҖҢйҠҖиЎҢгҖҚеҚҖеЎҠ
    """
    if section in COMPANY_SECTION_MAP:
        return COMPANY_SECTION_MAP[section]
    aliased = COMPANY_ALIAS.get(section)
    if aliased:
        # alias еҫҢеҶҚжҹҘдёҖж¬ЎпјҲдҫӢпјҡгҖҢе…ғеӨ§вҶ’йҠҖиЎҢгҖҚпјҢйҠҖиЎҢеңЁ REPORT_SECTION_2 зӣҙжҺҘйЎҜзӨәпјү
        return COMPANY_SECTION_MAP.get(aliased, aliased)
    return section


# =========================================================================
# ж—Ҙе ұйЎҜзӨәе…ұз”Ё helperпјҲLINE ж—Ҙе ұ + з¶Ій Ғж—Ҙе ұе…ұз”ЁгҖҒзўәдҝқе…©йӮҠж°ёйҒ дёҖиҮҙпјү
# =========================================================================
_DISPLAY_SHORTEN_SECTIONS = {"21", "дәһеӨӘ", "е’ҢиЈ•", "йә»еҗү", "еҲҶиІқ", "иҲҲйҒ”", "еҗҲдҝЎ"}
_DISPLAY_SECTION_SHORT_CODE = {
    "йӣ¶еҚЎ": "C", "йҠҖиЎҢ": "йҠҖ", "е•Ҷе“ҒиІё": "е•Ҷ",
    "д»Јжӣё": "д»Ј", "з•¶иҲ–": "з•¶", "й„үж°‘": "й„ү",
}
_DISPLAY_FAMILY_CS_KEY = {"еҲҶиІқж©ҹи»Ҡ": "еҲҶиІқ", "еҲҶиІқжұҪи»Ҡ": "еҲҶиІқ"}


def _display_co_short(co_raw):
    """ж—Ҙе ұе…¬еҸёеҗҚз°ЎеҢ–пјҡиІёж¬ҫж–№жЎҲжүҚз°ЎеҜ«гҖҒж°‘й–“ж–№жЎҲдҝқз•ҷеҺҹеҗҚ"""
    if not co_raw:
        return co_raw
    if co_raw in _DISPLAY_SECTION_SHORT_CODE:
        return _DISPLAY_SECTION_SHORT_CODE[co_raw]
    norm = normalize_section(co_raw)
    if norm in _DISPLAY_SHORTEN_SECTIONS and co_raw != norm:
        return norm
    return co_raw


def _compress_status_short(s):
    """ж—Ҙе ұзӢҖж…ӢеЈ“зё®пјҡе·ІиЈң/еҫ…иЈң/зјә/иЈңжҷӮж®ө е…Ёж–Үдҝқз•ҷ 14 еӯ—гҖҒе…¶д»–еҺҹжЁЈ"""
    if not s:
        return s
    if s.startswith("е·ІиЈң") or s.startswith("еҫ…иЈң") or s.startswith("зјә") or s.startswith("("):
        return s.split("\n")[0][:14]
    if s.startswith("иЈңжҷӮж®ө") or s.startswith("иЈңз…§жңғ") or s.startswith("з…§жңғжҷӮж®ө"):
        return s.split("\n")[0][:14]
    return s


def _default_sent_for_major_section(sn):
    """21/дәһеӨӘ зі»еҲ—еңЁйҖҒгҖҒз„Ўе…·й«”зӢҖж…Ӣ вҶ’ йЎҜзӨәгҖҢе·ІйҖҒд»¶гҖҚ"""
    return "е·ІйҖҒд»¶" if sn in ("21", "дәһеӨӘ") else ""


def _get_cs_key_for_section(cs, sec_name):
    """жүҫ company_status е…§е°ҚжҮү section зҡ„ key
    е„Әе…Ҳй ҶеәҸпјҡе®¶ж—Ҹдё»е…¬еҸё вҶ’ зІҫзўә вҶ’ normalize вҶ’ prefix йӣҷеҗ‘"""
    if not sec_name or not cs:
        return None
    _family_main = _DISPLAY_FAMILY_CS_KEY.get(sec_name)
    if _family_main and _family_main in cs:
        return _family_main
    if sec_name in cs:
        return sec_name
    for k in cs.keys():
        if normalize_section(k) == sec_name:
            return k
    for k in cs.keys():
        if k and sec_name and (sec_name.startswith(k) or k.startswith(sec_name)):
            return k
    return None


def _get_section_status_for_row(row, sec_name, cs=None, first_line=None):
    """еҸ–еҫ—и©Іе®ўжҲ¶еңЁжҹҗ section зҡ„зӢҖж…Ӣж–Үеӯ—пјҲе…ұз”ЁйӮҸијҜгҖҒLINE/з¶Ій ҒйғҪз”ЁжӯӨпјү
    - cs/first_line еҸҜй җе…ҲеӮіе…ҘйҒҝе…ҚйҮҚиӨҮз®—
    - е„Әе…Ҳ cs[sec] вҶ’ fallback last_update вҶ’ 21/дәһеӨӘ fallbackгҖҢе·ІйҖҒд»¶гҖҚ
    """
    if cs is None:
        try:
            cs = json.loads(row["company_status"] or "{}")
        except Exception:
            cs = {}
    if first_line is None:
        last = row["last_update"] or ""
        first_line = last.splitlines()[0].strip() if last.strip() else ""
    customer_name = row["customer_name"]
    cs_key = _get_cs_key_for_section(cs, sec_name)
    if cs_key is not None:
        cs_text = cs[cs_key]
        for ln in cs_text.splitlines():
            ln = ln.strip()
            if not ln:
                continue
            s = extract_status_summary(ln, customer_name)
            if s:
                return s
        return _default_sent_for_major_section(sec_name)
    # жҳҜ concurrent дҪҶз„Ў cs_key вҶ’ йЎҜзӨәгҖҢе·ІйҖҒд»¶гҖҚпјҲ21/дәһеӨӘпјү
    concurrent_list = [c.strip() for c in (row["concurrent_companies"] or "").split(",") if c.strip()]
    is_concurrent = any(normalize_section(c) == sec_name for c in concurrent_list)
    status_short = extract_status_summary(first_line, customer_name)
    # status_short е„Әе…Ҳпјҡlast_update жҸҗеҲ°зҡ„е…¬еҸёиӢҘ == sec_name вҶ’ еҘ—
    if status_short:
        mentioned_co = extract_company(first_line) or ""
        if mentioned_co and normalize_section(mentioned_co) != sec_name:
            # иЁҠжҒҜжҳҺзўәжҸҗеҲ°еҲҘе®¶гҖҒи©І sec дёҚи©ІжұЎжҹ“
            return ""
        if not mentioned_co:
            if not cs:
                return status_short
        else:
            return status_short
    if is_concurrent:
        return _default_sent_for_major_section(sec_name)
    if cs:
        return _default_sent_for_major_section(sec_name)
    return status_short


def compute_customer_display(row):
    """е–®дёҖе®ўжҲ¶зҡ„ж—Ҙе ұдё»иҰҒйЎҜзӨәиіҮиЁҠпјҲLINE ж—Ҙе ұи·ҹз¶Ій Ғж—Ҙе ұе…ұз”Ёж ёеҝғпјү

    еӣһ dictпјҡ
      - section: и©Іжӯёзҡ„ж—Ҙе ұеҚҖпјҲ21 / дәһеӨӘ / еҫ…ж’Ҙж¬ҫ / ж ёеҮҶ(жҲҝең°) / ...пјү
      - current_co: еҺҹ current_companyпјҲеүқжӢ¬иҷҹеҫҢпјү
      - company_short: з°ЎеҜ«е…¬еҸёеҗҚпјҲзөҰж—Ҙе ұйЎҜзӨәз”Ёпјү
      - status: е·ІеЈ“зё®зӢҖж…Ӣж–Үеӯ—пјҲе·ІйҖҒд»¶ / е·ІиЈңиіҮж–ҷ / еҫ…иЈңдҝқдәә / ...пјү
      - pending_str: зјәд»¶жҸҗзӨәпјҲеҰӮгҖҢ (зјәеҗҲз…§)гҖҚпјү
      - amount_display: еҫ…ж’Ҙж¬ҫ/ж ёеҮҶ(жҲҝең°) зҡ„йҮ‘йЎҚйЎҜзӨәиЎҢпјҲе…¶д»–з©әпјү
      - date_str: е»әжЎҲж—ҘжңҹпјҲM/D ж јејҸпјү
      - is_today: д»ҠеӨ©йҖІд»¶ вҶ’ еҠ  рҹҶ•
      - is_pre_send: жҳҜеҗҰгҖҢйҖҒд»¶еҚҖеЎҠгҖҚпјҲйӮ„жІ’еҜҰйҡӣйҖҒпјү
      - cs: е·І parse зҡ„ company_status dictпјҲзөҰ extras йҮҚз”Ёпјү
      - first_line: last_update з¬¬дёҖиЎҢпјҲзөҰ extras йҮҚз”Ёпјү
    """
    report_sec = row["report_section"] or ""
    current_co_raw = row["current_company"] or row["company"] or ""
    # йҳІе‘ҶпјҡеүқжҺүжӢ¬иҷҹе…§е®№пјҲзјәд»¶гҖҒзӢҖж…Ӣзӯүпјү
    current_co = re.sub(r"\s*\([^)]*\)\s*", "", current_co_raw).strip()
    section = report_sec or current_co or "йҖҒд»¶"

    try:
        pend = (row["pending_docs"] or "").strip()
    except (IndexError, KeyError):
        pend = ""
    try:
        cs = json.loads(row["company_status"] or "{}")
    except Exception:
        cs = {}

    # гҖҢйӮ„жІ’йҖҒд»¶гҖҚеҲӨе®ҡ
    is_pre_send = (
        (bool(pend) and not cs and report_sec != "еҫ…ж’Ҙж¬ҫ")
        or report_sec == "йҖҒд»¶"
    )
    if is_pre_send:
        section = "йҖҒд»¶"
    elif section == "йҖҒд»¶" and current_co:
        section = current_co

    # ж ёеҮҶиЈңеј·пјҲжҲҝең°зү№дҫӢ вҶ’ ж ёеҮҶ(жҲҝең°) еҚҖеЎҠгҖҒе…¶д»– вҶ’ еҫ…ж’Ҙж¬ҫпјү
    if not is_pre_send:
        try:
            appr = get_all_approved(row["route_plan"] or "")
            if appr:
                appr_co = (appr[0].get("company") or "").strip()
                appr_norm = normalize_section(appr_co) if appr_co else ""
                if appr_norm == "жҲҝең°":
                    section = "ж ёеҮҶ(жҲҝең°)"
                elif section != "еҫ…ж’Ҙж¬ҫ":
                    section = "еҫ…ж’Ҙж¬ҫ"
        except Exception:
            pass
    section = normalize_section(section)

    # е©үжӢ’ rerouteпјҡеҰӮжһңдё» section жҳҜгҖҢе·Іе©үжӢ’гҖҚзҡ„е®¶гҖҒжүҫйқһе©үжӢ’зҡ„е®¶з•¶ж–° section
    # еҲӨе®ҡгҖҢе·Іе©үжӢ’гҖҚпјҲuser иҰҒжұӮ 2026-05-14 ж”¶з·Ҡпјүпјҡ
    #   (1) cs[section] е…§е®№еҗ«гҖҢе©үжӢ’гҖҚеӯ—зңј вҶ’ fire
    #   (2) cs[section] зӮәз©әпјҲжІ’дәәйҮҚж–°иҷ•зҗҶпјү+ history жңү {co: section, status: е©үжӢ’} вҶ’ fire
    #   (3) cs[section] е…§е®№жҳҜиЈңд»¶/е·ІиЈңзӯүпјҲжҘӯеӢҷе·ІжҒўеҫ©пјүвҶ’ дёҚ fireгҖҒз№јзәҢйЎҜзӨәи©Іе®¶
    # жүҫж–° section зҡ„й ҶеәҸпјҡroute_plan order дёӢдёҖе®¶ вҶ’ concurrent вҶ’ cs е…¶д»– key
    if section not in ("еҫ…ж’Ҙж¬ҫ", "ж ёеҮҶ(жҲҝең°)", "йҖҒд»¶"):
        _section_norm = section
        # жҠ“ route_plan history е…§жүҖжңүе©үжӢ’йҒҺзҡ„е®¶
        _rejected_secs = set()
        try:
            _hist_for_chk = parse_route_json(row["route_plan"] or "").get("history", []) or []
            for _h in _hist_for_chk:
                if _h.get("status") == "е©үжӢ’":
                    _r_co = _h.get("company") or ""
                    if _r_co:
                        _rejected_secs.add(normalize_section(_r_co))
        except Exception:
            pass
        _section_cs_key = _get_cs_key_for_section(cs, section) if cs else None
        _cs_value = cs.get(_section_cs_key, "") if _section_cs_key else ""
        # зӢҖж…ӢеҸӘзңӢгҖҢз¬¬дёҖиЎҢгҖҚгҖҒз¬¬дәҢиЎҢд»ҘеҫҢжҳҜи©ізҙ°еӮҷиЁ»пјҲuser иҰҸеүҮпјү
        # йҒҝе…ҚгҖҢиЈңз”іиҰҶ\nгҖҗ1гҖ‘д№ӢеүҚе©үжӢ’еҺҹеӣ ...гҖҚиӘӨжҠ“з¬¬ 2 иЎҢгҖҢе©үжӢ’гҖҚз•¶зӢҖж…Ӣ
        _cs_first_line = _cs_value.splitlines()[0] if _cs_value else ""
        _cs_has_reject = bool(_cs_first_line) and "е©үжӢ’" in _cs_first_line
        _cs_empty = not _cs_value  # cs жІ’иЁҳйҢ„и©Іе®¶пјҲжІ’дәәйҮҚж–°иҷ•зҗҶпјү
        _history_has_reject = _section_norm in _rejected_secs
        # cs жңүйқһе©үжӢ’е…§е®№пјҲиЈңд»¶/е·ІиЈң/иЈңз”іиҰҶпјүвҶ’ жҘӯеӢҷе·ІйҮҚж–°иҷ•зҗҶгҖҒдёҚ reroute
        if _cs_has_reject or (_history_has_reject and _cs_empty):
            _rerouted = False
            # 1. е„Әе…Ҳз”Ё route_plan order е…§гҖҢcurrent д№ӢеҫҢзҡ„з¬¬дёҖеҖӢйқһе©үжӢ’е®¶гҖҚпјҲuser иҰҸеүҮпјҡжІ’жҢҮе®ҡе°ұи·ідёӢдёҖе®¶пјү
            try:
                _rp_data = parse_route_json(row["route_plan"] or "")
                _order = _rp_data.get("order", []) or []
                _rp_idx = _rp_data.get("current_index", 0)
                if not isinstance(_rp_idx, int) or _rp_idx < 0:
                    _rp_idx = 0
                # е…Ҳи©Ұ current_index д№ӢеҫҢ
                for _i in range(_rp_idx, len(_order)):
                    _o_co = _order[_i]
                    _o_sec = normalize_section(_o_co)
                    if _o_sec == _section_norm:
                        continue  # skip е©үжӢ’йӮЈе®¶
                    if _o_sec in _rejected_secs:
                        continue
                    # cs е…§йҖҷе®¶иӢҘжҳҜе©үжӢ’гҖҒд№ҹ skipпјҲеҸӘзңӢз¬¬дёҖиЎҢпјү
                    _o_cs_key = _get_cs_key_for_section(cs, _o_sec) if cs else None
                    _o_cs_first = (cs.get(_o_cs_key, "") or "").splitlines()[0] if _o_cs_key else ""
                    if "е©үжӢ’" in _o_cs_first:
                        continue
                    section = _o_sec
                    current_co = _o_co
                    _rerouted = True
                    break
            except Exception:
                pass
            # 2. route_plan жүҫдёҚеҲ° вҶ’ жүҫ concurrent йқһе©үжӢ’зҡ„е®¶
            if not _rerouted:
                _concur_list = [c.strip() for c in (row["concurrent_companies"] or "").split(",") if c.strip()]
                for _alt_co in _concur_list:
                    _alt_sec = normalize_section(_alt_co)
                    if _alt_sec in _rejected_secs:
                        continue
                    _alt_cs_key = _get_cs_key_for_section(cs, _alt_sec) if cs else None
                    _alt_cs_text = cs.get(_alt_cs_key, "") if _alt_cs_key else ""
                    _alt_cs_first = _alt_cs_text.splitlines()[0] if _alt_cs_text else ""
                    if "е©үжӢ’" in _alt_cs_first:
                        continue
                    section = _alt_sec
                    current_co = _alt_co
                    _rerouted = True
                    break
            # 3. йӮ„жүҫдёҚеҲ° вҶ’ жүҫ cs е…¶д»– key е…§йқһе©үжӢ’зҡ„е®¶пјҲеҸӘзңӢз¬¬дёҖиЎҢпјү
            if not _rerouted and cs:
                for _cs_k, _cs_v in cs.items():
                    if _cs_k == _section_cs_key:
                        continue
                    _cs_v_first = (_cs_v or "").splitlines()[0] if _cs_v else ""
                    if "е©үжӢ’" in _cs_v_first:
                        continue
                    _alt_sec = normalize_section(_cs_k)
                    if _alt_sec in _rejected_secs:
                        continue
                    section = _alt_sec
                    current_co = _cs_k
                    _rerouted = True
                    break

    company_short = _display_co_short(current_co) or current_co

    last = row["last_update"] or ""
    first_line = last.splitlines()[0].strip() if last.strip() else ""

    status = _compress_status_short(_get_section_status_for_row(row, section, cs, first_line))

    pending_str = ""
    if pend:
        docs = [d.strip() for d in pend.split(",") if d.strip()]
        if docs:
            pending_str = " (зјә" + "/".join(docs) + ")"

    created = row["created_at"] or ""
    date_str = created[5:10].replace("-", "/") if created else ""
    today_str = now_tw().strftime("%Y-%m-%d")
    is_today = created[:10] == today_str

    amount_display = ""
    if section == "еҫ…ж’Ҙж¬ҫ":
        amount = row["approved_amount"] or ""
        signing_time = (row["signing_time"] or "").strip()
        signing_date = signing_time.split()[0] if signing_time else ""
        pending_tag = f"(е°Қдҝқ{signing_date})" if signing_date else "(еҫ…ж’Ҙж¬ҫ)"
        approved_list = get_all_approved(row["route_plan"] or "")
        if approved_list:
            parts = []
            for ap in approved_list:
                co = ap.get('company') or ''
                co_s = _display_co_short(co) or co
                amt = ap.get('amount') or ''
                disb = ap.get('disbursed') or ''
                if disb:
                    parts.append(f"{co_s} {amt}(ж’Ҙж¬ҫ{disb})")
                else:
                    parts.append(f"{co_s} {amt}{pending_tag}")
            amount_display = "-ж ёеҮҶ" + "/".join(parts)
        elif amount:
            disb_date = row["disbursement_date"] or ""
            disb_str = f"(ж’Ҙж¬ҫ{disb_date})" if disb_date else pending_tag
            co_s = _display_co_short(current_co) or current_co
            co_prefix = f"-{co_s}" if co_s else ""
            amount_display = f"{co_prefix}-ж ёеҮҶ{amount}{disb_str}"
    elif section == "ж ёеҮҶ(жҲҝең°)":
        approved_list = get_all_approved(row["route_plan"] or "")
        amt = ""
        co_show = current_co or "жҲҝең°"
        disb = ""
        if approved_list:
            _ap = approved_list[0]
            amt = _ap.get('amount') or ''
            co_show = _ap.get('company') or co_show
            disb = _ap.get('disbursed') or ''
        elif (row["approved_amount"] or "").strip():
            amt = row["approved_amount"]
        # fallbackпјҡhistory жІ’ж’Ҙж¬ҫж—ҘгҖҒз”Ё customer.disbursement_date
        if not disb:
            disb = (row["disbursement_date"] or "").strip()
        if disb:
            amount_display = f"-ж°‘й–“{co_show}ж ёеҮҶ{amt}(ж’Ҙж¬ҫ{disb})"
        else:
            amount_display = f"-ж°‘й–“{co_show}ж ёеҮҶ{amt}"

    return {
        "section": section,
        "current_co": current_co,
        "company_short": company_short,
        "status": status,
        "pending_str": pending_str,
        "amount_display": amount_display,
        "date_str": date_str,
        "is_today": is_today,
        "is_pre_send": is_pre_send,
        "cs": cs,
        "first_line": first_line,
    }


def build_section_map(all_rows) -> Dict[str, List[str]]:
    """жҠҠе®ўжҲ¶еҲ—иЎЁиҪүжҲҗ section_mapпјҲLINE ж—Ҙе ұз”Ёпјү"""
    section_map: Dict[str, List[str]] = {}
    for row in all_rows:
        info = compute_customer_display(row)
        section = info["section"]
        date_str = info["date_str"]
        company_short = info["company_short"]
        status = info["status"]
        pending_str = info["pending_str"]
        amount_display = info["amount_display"]
        is_today = info["is_today"]
        current_co = info["current_co"]
        cs = info["cs"]
        first_line = info["first_line"]
        customer_name = row["customer_name"]
        created = row["created_at"] or ""

        # === дё»иЎҢ ===
        if section == "еҫ…ж’Ҙж¬ҫ":
            created_date = created[5:10].replace("-", "/") if created else date_str
            line = f"{created_date}-{customer_name}{amount_display}"
        elif section == "ж ёеҮҶ(жҲҝең°)":
            created_date = created[5:10].replace("-", "/") if created else date_str
            line = f"{created_date}-{customer_name}{amount_display}"
        else:
            line = f"{date_str}-{customer_name}-{company_short}"
            if status and not pending_str:
                line += f"-{status}"
            line += pending_str
        if is_today:
            line = "рҹҶ•" + line
        section_map.setdefault(section, []).append(line)

        # === extra_sectionпјҲеҫ…ж’Ҙж¬ҫжҷӮгҖҒеҺҹ current йӮ„еңЁйҖҒ вҶ’ д№ҹжӯёиҮӘе·ұеҚҖеЎҠпјү===
        extra_section = None
        if section == "еҫ…ж’Ҙж¬ҫ" and current_co:
            approved_companies = [h.get("company", "") for h in get_all_approved(row["route_plan"] or "")]
            _main_amt = (row["approved_amount"] or "").strip()
            if not approved_companies and _main_amt and current_co:
                approved_companies.append(current_co)
            still_sending = current_co not in approved_companies and not any(
                current_co in ac or ac in current_co for ac in approved_companies
            )
            if still_sending:
                extra_section = normalize_section(current_co)
        if extra_section and extra_section != section:
            extra_status = _compress_status_short(_get_section_status_for_row(row, extra_section, cs, first_line))
            extra_line = f"{date_str}-{customer_name}-{company_short}"
            if extra_status and not pending_str:
                extra_line += f"-{extra_status}"
            extra_line += pending_str
            if is_today:
                extra_line = "рҹҶ•" + extra_line
            section_map.setdefault(extra_section, []).append(extra_line)

        # === е·Іж ёеҮҶ sectionsпјҲconcurrent ж•Јй–ӢжҷӮи·ійҒҺгҖҒйҒҝе…ҚйҮҚиӨҮпјү===
        approved_sections = set()
        try:
            for ap in get_all_approved(row["route_plan"] or ""):
                ap_co = ap.get("company") or ""
                if ap_co:
                    approved_sections.add(normalize_section(ap_co))
        except Exception:
            pass

        # === concurrent ж•Јй–ӢпјҡеҗҢйҖҒе…¬еҸёд№ҹиҰҒйЎҜзӨәеңЁиҮӘе·ұеҚҖеЎҠ ===
        concurrent_str = row["concurrent_companies"] or ""
        if concurrent_str:
            for co in concurrent_str.split(","):
                co = co.strip()
                if not co:
                    continue
                co_section = normalize_section(co)
                if co_section in approved_sections:
                    continue
                if co_section != section:
                    # е©үжӢ’зҡ„е®¶дёҚйЎҜзӨәпјҲеҸӘзңӢ cs з¬¬дёҖиЎҢгҖҒйҒҝе…Қз¬¬ 2 иЎҢи©ізҙ°еӮҷиЁ»иӘӨжҠ“пјү
                    _cs_key_chk = _get_cs_key_for_section(cs, co_section)
                    _cs_text_chk = cs.get(_cs_key_chk, "") if _cs_key_chk else ""
                    _cs_first_chk = _cs_text_chk.splitlines()[0] if _cs_text_chk else ""
                    if "е©үжӢ’" in _cs_first_chk:
                        continue
                    co_status = _compress_status_short(_get_section_status_for_row(row, co_section, cs, first_line))
                    # йӣҷйҮҚдҝқйҡӘпјҡextract еҫҢ status жҳҜгҖҢе©үжӢ’гҖҚд№ҹж“Ӣ
                    if co_status == "е©үжӢ’":
                        continue
                    co_short = _display_co_short(co) or co
                    co_line = f"{date_str}-{customer_name}-{co_short}"
                    if co_status and not pending_str:
                        co_line += f"-{co_status}"
                    co_line += pending_str
                    if is_today:
                        co_line = "рҹҶ•" + co_line
                    section_map.setdefault(co_section, []).append(co_line)

        # иЁ»пјҡе…ҲеүҚжңүгҖҢе©үжӢ’'d е…¬еҸёиӢҘ cs жңүиЈңд»¶ вҶ’ д№ҹйЎҜзӨәгҖҚйӮҸијҜгҖҒuser 2026-05-14 иҰҒжұӮжӢҝжҺү
        # е©үжӢ’ = ж¶ҲеӨұгҖҒиҰҒжҒўеҫ©з”ЁгҖҢ@AI е§“еҗҚ е…¬еҸё еҸ–ж¶Ҳе©үжӢ’гҖҚжҢҮд»ӨгҖӮ
    return section_map


def build_segment(sections: List[str], section_map: Dict, shown: set) -> str:
    """жҠҠжҢҮе®ҡ sections зҡ„е…§е®№зө„жҲҗдёҖж®өж–Үеӯ—"""
    lines = []
    for sec in sections:
        if sec in section_map:
            # гҖҢж ёеҮҶ(жҲҝең°)гҖҚйЎҜзӨәжҲҗгҖҢж ёеҮҶгҖҚпјҲзІҫз°ЎжЁҷйЎҢпјү
            lines.append("ж ёеҮҶ" if sec == "ж ёеҮҶ(жҲҝең°)" else sec)
            lines.extend(section_map[sec])
            lines.append("вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”")
            shown.add(sec)
    return "\n".join(lines)


def generate_report_lines(group_id: str) -> List[str]:
    """
    з”ўз”ҹж—Ҙе ұпјҢеҲҶдёүж®өе°Қи©ұжЎҶпјҡ
    з¬¬1ж®өпјҡиІёж¬ҫж–№жЎҲпјҲйә»еҗү~жүӢж©ҹеҲҶжңҹпјү+ йҖҒд»¶ + еҫ…ж’Ҙж¬ҫ
    з¬¬2ж®өпјҡж°‘й–“ж–№жЎҲпјҲйҠҖиЎҢ/йӣ¶еҚЎ/е•Ҷе“ҒиІё/д»Јжӣё/з•¶иҲ–/ж ёеҮҶпјү
    з¬¬3ж®өпјҡжҲҝең°пјҲжҲҝең°/ж ёеҮҶ(жҲҝең°)пјү
    жҜҸж®өйғҪеҸӘеңЁжңүе®ўжҲ¶жҷӮжүҚйЎҜзӨәпјҢжҜҸж®өи¶…йҒҺ4500еӯ—еҶҚиҮӘеӢ•еҲҮеүІгҖӮ
    """
    group_name = get_group_name(group_id)
    today = now_tw().strftime("%m/%d")
    conn = get_conn(); cur = conn.cursor()
    cur.execute("SELECT * FROM customers WHERE source_group_id=? AND status='ACTIVE' ORDER BY updated_at DESC", (group_id,))
    all_rows = cur.fetchall(); conn.close()

    if not all_rows:
        return [f"рҹ“Ҡ {group_name} ж—Ҙе ұ {today}\nпјҲзӣ®еүҚз„Ўжңүж•ҲжЎҲд»¶пјү"]

    section_map = build_section_map(all_rows)
    shown = set()
    segments = []

    # з¬¬1ж®өпјҡиІёж¬ҫж–№жЎҲ + йҖҒд»¶
    seg1 = build_segment(REPORT_SECTION_1, section_map, shown)
    if seg1:
        segments.append(f"рҹ“Ҡ {group_name} ж—Ҙе ұ {today}\n{seg1}")

    # з¬¬2ж®өпјҡж°‘й–“ж–№жЎҲ
    seg2 = build_segment(REPORT_SECTION_2, section_map, shown)
    if seg2:
        segments.append(seg2)

    # з¬¬3ж®өпјҡжҲҝең°
    seg3 = build_segment(REPORT_SECTION_3, section_map, shown)
    if seg3:
        segments.append(seg3)

    # жңӘжӯёйЎһзҡ„пјҲдёҚеңЁд»»дҪ•sectionзҡ„пјҢжҺ’йҷӨеҫ…ж’Ҙж¬ҫпјүиЈңеҲ°з¬¬1ж®өеҫҢйқў
    extra = []
    for sec, lines in section_map.items():
        if sec not in shown and sec != "еҫ…ж’Ҙж¬ҫ":
            extra.append(sec)
            extra.extend(lines)
            extra.append("вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”вҖ”")
    if extra:
        if segments:
            segments[0] += "\n" + "\n".join(extra)
        else:
            segments.append(f"рҹ“Ҡ {group_name} ж—Ҙе ұ {today}\n" + "\n".join(extra))

    # з¬¬4ж®өпјҡеҫ…ж’Ҙж¬ҫпјҲжҺ’еңЁжңҖеҫҢпјү
    seg4 = build_segment(REPORT_SECTION_4, section_map, shown)
    if seg4:
        segments.append(seg4)

    # еҫ…ж’Ҙж¬ҫи¶…йҒҺ7еӨ©жҸҗйҶ’пјҲеҫһж ёеҮҶж—Ҙз®—гҖҒдёҚжҳҜе»әжЎҲж—Ҙпјү
    overdue_lines = []
    for row in all_rows:
        if (row["report_section"] or "") == "еҫ…ж’Ҙж¬ҫ" and not (row["disbursement_date"] or ""):
            # е„Әе…Ҳз”Ё approved_atпјҲж ёеҮҶжҷӮй–“пјүгҖҒfallback еҲ° created_atпјҲе»әжЎҲжҷӮй–“пјү
            anchor = row["approved_at"] if "approved_at" in row.keys() else None
            anchor = anchor or row["created_at"] or ""
            if anchor:
                try:
                    days = (now_tw() - datetime.fromisoformat(anchor.replace("Z",""))).days
                    if days >= 7:
                        signing_time = (row["signing_time"] or "").strip()
                        signing_date = signing_time.split()[0] if signing_time else ""
                        extra = f"пјҢе°Қдҝқ{signing_date}" if signing_date else ""
                        overdue_lines.append(f"  {row['customer_name']}пјҲж ёеҮҶ{days}еӨ©{extra}пјү")
                except Exception:
                    pass
    if overdue_lines:
        segments.append(f"вҸ° еҫ…ж’Ҙж¬ҫи¶…йҒҺ7еӨ©пјҲ{len(overdue_lines)}зӯҶпјү\n" + "\n".join(overdue_lines))

    if not segments:
        return [f"рҹ“Ҡ {group_name} ж—Ҙе ұ {today}\nпјҲзӣ®еүҚз„Ўжңүж•ҲжЎҲд»¶пјү"]

    # жҜҸж®өи¶…йҒҺ4500еӯ—еҶҚеҲҮеүІ
    final_segments = []
    for seg in segments:
        if len(seg) <= 4500:
            final_segments.append(seg)
        else:
            lines = seg.splitlines()
            current = ""
            for line in lines:
                if len(current) + len(line) + 1 > 4500:
                    final_segments.append(current.strip())
                    current = line + "\n"
                else:
                    current += line + "\n"
            if current.strip():
                final_segments.append(current.strip())

    return final_segments


def search_customer_info(name: str, group_id: str) -> str:
    rows = find_any_by_name(name)
    active = [r for r in rows if r["status"] == "ACTIVE" and r["source_group_id"] == group_id]
    if not active:
        active = [r for r in rows if r["status"] == "ACTIVE"]
    if not active:
        closed = [r for r in rows if r["status"] != "ACTIVE"]
        if closed:
            return f"вқҢ {name} е·ІзөҗжЎҲпјҲ{closed[0]['updated_at'][:10]}пјү"
        return f"вқҢ жүҫдёҚеҲ°е®ўжҲ¶пјҡ{name}"
    r = active[0]
    route_data = parse_route_json(r["route_plan"] or "")
    order, idx = route_data.get("order", []), route_data.get("current_index", 0)
    history = route_data.get("history", [])
    # з”Ё compute_customer_display жӢҝ reroute еҫҢзҡ„ currentпјҲйҒҝе…Қе©үжӢ’зҡ„е®¶йӮ„з•¶гҖҢзӣ®еүҚйҖҒд»¶гҖҚйЎҜзӨәпјү
    _disp = compute_customer_display(dict(r))
    display_current_co = _disp.get("current_co") or r["current_company"] or r["company"] or ""
    # йҮҚз®— idxпјҡз”ЁйЎҜзӨәз”Ё current еңЁ order е…§зҡ„дҪҚзҪ®
    if display_current_co and order:
        for _i, _co in enumerate(order):
            if normalize_section(_co) == normalize_section(display_current_co):
                idx = _i
                break
    lines = [f"рҹ‘Ө {name}"]
    if r["id_no"]:
        lines.append(f"иә«еҲҶиӯүпјҡ{r['id_no']}")
    lines.append(f"жүҖеұ¬зҫӨзө„пјҡ{get_group_name(r['source_group_id'])}")
    current_co = display_current_co
    if current_co:
        lines.append(f"зӣ®еүҚйҖҒд»¶пјҡ{current_co}")
    # еҗҢйҖҒе…¶д»–е®¶ concurrent
    concurrent_list = [c.strip() for c in (r["concurrent_companies"] or "").split(",") if c.strip()]
    if concurrent_list:
        lines.append(f"еҗҢйҖҒе…¶д»–е®¶пјҡ{', '.join(concurrent_list)}")
    # ж ёеҮҶйҮ‘йЎҚ / ж’Ҙж¬ҫ
    if r["approved_amount"]:
        disb = r["disbursement_date"] or ""
        lines.append(f"ж ёеҮҶпјҡ{r['approved_amount']}" + (f"пјҲж’Ҙж¬ҫ{disb}пјү" if disb else "пјҲеҫ…ж’Ҙж¬ҫпјү"))
    if order:
        # е®Ңж•ҙйҖҒд»¶й ҶеәҸпјҡе·ІйҖҒйҒҺ вң“гҖҒзӣ®еүҚ рҹ‘ҲгҖҒжңӘйҖҒз•ҷзҷҪ
        order_parts = []
        for i, co in enumerate(order):
            if i < idx:
                order_parts.append(f"{co}вң“")
            elif i == idx:
                order_parts.append(f"{co}рҹ‘Ҳ")
            else:
                order_parts.append(co)
        lines.append(f"йҖҒд»¶й ҶеәҸпјҡ{' вҶ’ '.join(order_parts)}")
        if idx + 1 < len(order):
            lines.append(f"дёӢдёҖе®¶пјҡ{order[idx+1]}")
        if history:
            lines.append("йҖҒд»¶жӯ·зЁӢпјҡ")
            for h in history[-3:]:
                lines.append(f"  {h.get('date','')} {h.get('company','')} вҶ’ {h.get('status','')}")
    last_update = (r["last_update"] or "").strip()
    if last_update:
        last_lines = [l.strip() for l in last_update.splitlines() if l.strip()]
        if last_lines:
            lines.append(f"жңҖж–°йҖІеәҰпјҡ{last_lines[0][:80]}")
            for extra in last_lines[1:4]:
                lines.append(f"  {extra[:80]}")
    # еҗ„е…¬еҸёзҚЁз«ӢзӢҖж…ӢпјҲcompany_statusпјүвҖ” еҫ…иЈңзҙ°й …
    try:
        cs = json.loads(r["company_status"] or "{}")
        if cs:
            lines.append("еҗ„е®¶зӢҖж…Ӣпјҡ")
            for co, note in cs.items():
                # note еҸҜиғҪеӨҡиЎҢжҲ–еҗ«иЁҠжҒҜе…Ёж–ҮпјҢеҸӘйЎҜзӨәеүҚ 60 еӯ—
                note_short = (note or "").replace("\n", " ")[:60]
                if note_short:
                    lines.append(f"  {co}пјҡ{note_short}")
    except Exception:
        pass
    return "\n".join(lines)


