def send_reopen_case_buttons(reply_token, block_text, closed_rows, source_group_id, push_to_a_after_reopen=False):
    action_id = short_id()
    closed_rows = sorted(closed_rows, key=lambda x: x["updated_at"], reverse=True)[:1]
    save_pending_action(action_id, "reopen_or_new_case", {
        "block_text": block_text, "case_ids": [r["case_id"] for r in closed_rows],
        "source_group_id": source_group_id, "push_to_a_after_reopen": push_to_a_after_reopen,
    })
    items = [make_quick_reply_item(f'йҮҚе•ҹ-{c["customer_name"]}-{c["company"] or "жңӘеЎ«"}',
                                    f"REOPEN_CASE|{action_id}|{c['case_id']}") for c in closed_rows]
    items += [make_quick_reply_item("е»әз«Ӣж–°жЎҲд»¶", f"CREATE_NEW_CASE|{action_id}"),
              make_quick_reply_item("еҸ–ж¶Ҳ", f"CANCEL_REOPEN|{action_id}")]
    reply_quick_reply(reply_token, "вҡ пёҸ жӯӨе®ўжҲ¶жЎҲд»¶е·ІзөҗжЎҲпјҢи«ӢйҒёж“ҮиҰҒйҮҚе•ҹеҺҹжЎҲд»¶жҲ–е»әз«Ӣж–°жЎҲд»¶", items)


def send_ambiguous_case_buttons(reply_token, block_text, matches):
    action_id = short_id()
    save_pending_action(action_id, "route_a_case", {"block_text": block_text, "case_ids": [m["case_id"] for m in matches]})
    items = [make_quick_reply_item(
        f"{c['customer_name']}-{c['company'] or 'жңӘеЎ«'}-{get_group_name(c['source_group_id'])}",
        f"SELECT_CASE|{action_id}|{c['case_id']}") for c in matches[:10]]
    reply_quick_reply(reply_token, "вҡ пёҸ еӨҡзӯҶеҗҢеҗҚе®ўжҲ¶пјҢи«ӢйҒёж“ҮиҰҒеӣһиІјзҡ„жЎҲд»¶", items)


def send_transfer_case_buttons(reply_token, customer, source_group_id, block_text, allow_new=True):
    # Bug 6: й©—иӯү source_group_id еҗҲжі•жҖ§пјҢйҒҝе…ҚжҢүйҲ•еӣһиӘҝеҜ«е…ҘдёҚеӯҳеңЁзҡ„зҫӨзө„
    new_g = get_group_name(source_group_id) if source_group_id else ""
    if not source_group_id or not new_g or new_g == "жңӘзҹҘзҫӨзө„":
        reply_text(reply_token, "вҡ пёҸ з„Ўжі•иҪүйҖҒпјҡдҫҶжәҗзҫӨзө„дёҚеӯҳеңЁжҲ–е°ҡжңӘиЁ»еҶҠпјҢи«ӢиҒҜзөЎз®ЎзҗҶе“Ў")
        return
    action_id = short_id()
    save_pending_action(action_id, "transfer_customer", {
        "case_id": customer["case_id"], "target_group_id": source_group_id,
        "block_text": block_text, "name": extract_name(block_text) or customer["customer_name"],
    })
    old_g = get_group_name(customer["source_group_id"])
    # дёүжҢүйҲ•иӘһж„ҸпјҡжІҝз”Ё = е…©йӮҠеҗ„жңүзҚЁз«ӢжЎҲд»¶пјӣиҪүз§» = еҺҹзҫӨзө„жҗ¬еҲ°ж–°зҫӨзө„пјӣеҸ–ж¶Ҳ
    items = [make_quick_reply_item(f"жІҝз”Ё(е…©йӮҠйғҪжңү)", f"CREATE_NEW_FROM_TRANSFER|{action_id}"),
             make_quick_reply_item(f"иҪүз§»еҲ°{new_g}", f"CONFIRM_TRANSFER|{action_id}"),
             make_quick_reply_item("еҸ–ж¶Ҳ", f"CANCEL_TRANSFER|{action_id}")]
    reply_quick_reply(reply_token, f"вҡ пёҸ {old_g} е·ІжңүеҗҢеҗҚе®ўжҲ¶пјҢи«ӢйҒёж“ҮпјҡжІҝз”Ё(е…©йӮҠеҗ„е»әзҚЁз«ӢжЎҲ)/иҪүз§»(жҗ¬еҲ°{new_g})/еҸ–ж¶Ҳ", items)


