def send_confirm_new_case_buttons(reply_token, block_text, existing_customer, source_group_id):
    action_id = short_id()
    save_pending_action(action_id, "confirm_new_case_with_existing_id", {
        "block_text": block_text, "source_group_id": source_group_id,
        "existing_case_id": existing_customer["case_id"],
    })
    old_g, new_g = get_group_name(existing_customer["source_group_id"]), get_group_name(source_group_id)
    name = extract_name(block_text) or existing_customer["customer_name"]
    # дёүжҢүйҲ•иӘһж„ҸпјҡжІҝз”Ё = е…©йӮҠеҗ„жңүзҚЁз«ӢжЎҲд»¶пјҲж–°зҫӨзө„е»әж–°жЎҲгҖҒеҺҹзҫӨзө„дҝқз•ҷпјүпјӣиҪүз§» = жҗ¬еҲ°ж–°зҫӨзө„пјӣеҸ–ж¶Ҳ
    items = [make_quick_reply_item(f"жІҝз”Ё(е…©йӮҠйғҪжңү)", f"FORCE_CREATE_NEW|{action_id}"),
             make_quick_reply_item(f"иҪүз§»еҲ°{new_g}", f"TRANSFER_FROM_CONFIRM|{action_id}"),
             make_quick_reply_item("еҸ–ж¶Ҳ", f"CANCEL_NEW_CASE|{action_id}")]
    reply_quick_reply(reply_token, f"вҡ пёҸ {name} иә«еҲҶиӯүе·ІеӯҳеңЁж–ј{old_g}пјҢи«ӢйҒёж“ҮпјҡжІҝз”Ё(е…©йӮҠеҗ„е»әзҚЁз«ӢжЎҲ)/иҪүз§»(жҗ¬еҲ°{new_g})/еҸ–ж¶Ҳ", items)


# =========================
# зү№ж®ҠжҢҮд»Ө
# =========================
def parse_special_command(text: str, group_id: str) -> Optional[Dict]:
    clean = strip_ai_trigger(text).strip()
    # ж–Үеӯ—жӯЈиҰҸеҢ–пјҲе…ЁеҪўвҶ’еҚҠеҪўгҖҒз•°й«”еӯ—зөұдёҖгҖҒз©әзҷҪеҗҲдҪөпјү
    clean = normalize_command_text(clean)

    # жү№ж¬ЎзөҗжЎҲпјҡ@AI жү№ж¬ЎзөҗжЎҲ\nе§“еҗҚ1\nе§“еҗҚ2\n...
    if clean.startswith("жү№ж¬ЎзөҗжЎҲ"):
        rest = clean[len("жү№ж¬ЎзөҗжЎҲ"):].strip()
        names = [n.strip() for n in rest.splitlines() if n.strip()]
        if names:
            return {"type": "batch_close", "names": names}

    # жү№ж¬Ўе©үжӢ’пјҡ@AI жү№ж¬Ўе©үжӢ’\nе§“еҗҚ1\nе§“еҗҚ2\n...
    if clean.startswith("жү№ж¬Ўе©үжӢ’"):
        rest = clean[len("жү№ж¬Ўе©үжӢ’"):].strip()
        names = [n.strip() for n in rest.splitlines() if n.strip()]
        if names:
            return {"type": "batch_reject", "names": names}

    # еҫ…ж’Ҙж¬ҫеҗҚе–®пјҡ@AI еҫ…ж’Ҙж¬ҫ
    if re.match(r"^еҫ…ж’Ҙж¬ҫ$", clean):
        return {"type": "pending_disbursement"}

    # еҫ…и·ҹйҖІжё…е–®пјҡ@AI еҫ…и·ҹйҖІ / @AI и·ҹйҖІ
    if re.match(r"^еҫ…?и·ҹйҖІ$", clean):
        return {"type": "follow_up_list"}

    # зөұиЁҲпјҡ@AI зөұиЁҲ
    if re.match(r"^зөұиЁҲ$", clean):
        return {"type": "stats"}

    # зҫӨзө„IDжҹҘи©ўпјҲдёҚеҲҶеӨ§е°ҸеҜ«пјү
    if re.match(r"^зҫӨзө„[Ii][Dd]$", clean):
        return {"type": "group_id"}

    # ж—Ҙе ұ
    if re.match(r"^ж—Ҙе ұ$", clean):
        return {"type": "report"}

    # жҢҮд»ӨйҖҹжҹҘеҚЎпјҲеҸӘз•ҷе…©еҖӢпјҡ@AI ж јејҸ / @AI иӘӘжҳҺпјү
    if clean in ["ж јејҸ", "иӘӘжҳҺ"]:
        return {"type": "help"}

    # жҹҘи©ўпјҡж”ҜжҸҙжүҖжңүж јејҸ
    # @AI жҹҘ еҪӯй§ҝзӮә / еҪӯй§ҝзӮә жҹҘ@AI / еҪӯй§ҝзӮә@AI жҹҘ
    m = re.match(r"^жҹҘ\s*([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})$", clean)
    if m:
        return {"type": "search", "name": m.group(1)}
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*жҹҘ$", clean)
    if m:
        return {"type": "search", "name": m.group(1)}

    # иҪүдёӢдёҖе®¶ / иҪүдёӢе®¶пјҲеҗҢзҫ©пјү
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*иҪүдёӢ(?:дёҖ)?е®¶$", clean)
    if m:
        return {"type": "advance", "name": m.group(1), "target": None}

    # ж”№й ҶеәҸпјҡ@AI е§“еҗҚ ж”№й ҶеәҸ A/B/C/D вҶ’ иҰҶеҜ« current д№ӢеҫҢзҡ„ routeпјҢдҝқз•ҷ history/current
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*ж”№й ҶеәҸ\s+(.+)$", clean)
    if m:
        return {"type": "reorder_route", "name": m.group(1), "new_order": m.group(2).strip()}

    # зјәд»¶жё…е–®пјҲжҢҮе®ҡе…¬еҸёпјүпјҡ@AI е§“еҗҚ е…¬еҸё зјә иә«еҲҶиӯү+и–ӘиҪү
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s+(\S+?)\s+зјә\s+(.+)$", clean)
    if m:
        _name, _co, _docs = m.group(1), m.group(2).strip(), m.group(3).strip()
        _co_canon = COMPANY_ALIAS.get(_co, _co)
        if _co_canon in _get_valid_company_names():
            return {"type": "set_missing_docs", "name": _name, "company": _co_canon, "docs": _docs}

    # зјәд»¶жё…е–®пјҡ@AI е§“еҗҚ зјә иә«еҲҶиӯү+и–ӘиҪү+еёіе–®
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*зјә\s*(.+)$", clean)
    if m:
        return {"type": "set_missing_docs", "name": m.group(1), "company": "", "docs": m.group(2).strip()}

    # е·ІиЈңпјҲжҢҮе®ҡе…¬еҸёпјүпјҡ@AI е§“еҗҚ е…¬еҸё е·ІиЈң иә«еҲҶиӯү
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s+(\S+?)\s+е·ІиЈң\s+(.+)$", clean)
    if m:
        _name, _co, _doc = m.group(1), m.group(2).strip(), m.group(3).strip()
        _co_canon = COMPANY_ALIAS.get(_co, _co)
        if _co_canon in _get_valid_company_names():
            if _doc in ("е…ЁйғЁ", "е®Ңз•ў", "йғҪеҘҪ", "еҘҪдәҶ"):
                return {"type": "clear_missing_docs", "name": _name, "company": _co_canon}
            return {"type": "mark_doc_completed", "name": _name, "company": _co_canon, "doc": _doc}

    # е·ІиЈңе–®й …/е…Ёжё…пјҡ@AI е§“еҗҚ е·ІиЈң иә«еҲҶиӯү / @AI е§“еҗҚ е·ІиЈң е…ЁйғЁ / @AI е§“еҗҚ е·ІиЈңжҷӮж®ө зӯү
    # жҷӮж®ө/з”іиҰҶ/иіҮж–ҷ/з…§жңғ зӢҖж…ӢжҸҸиҝ° дёҖеҫӢиө° mark_doc_completed и®“ company_status еҲ·ж–°
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*е·ІиЈң\s*(.*)$", clean)
    if m:
        docs = m.group(2).strip()
        if docs in ("", "е…ЁйғЁ", "е®Ңз•ў", "йғҪеҘҪ", "еҘҪдәҶ"):
            return {"type": "clear_missing_docs", "name": m.group(1), "company": ""}
        return {"type": "mark_doc_completed", "name": m.group(1), "company": "", "doc": docs}

    # еҠ йҖҒпјҡ@AI е§“еҗҚ йҖҒе…¬еҸё[+е…¬еҸё] [йҮ‘йЎҚ/жңҹж•ё] вҶ’ еҠ е…ҘеҗҢжҷӮйҖҒд»¶жё…е–®пјҢдёҚжҸӣжҺүеҺҹжң¬зҡ„
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*йҖҒ\s*([^\s]+)(?:\s+(\d+(?:\.\d+)?)\s*иҗ¬?\s*[/пјҸ]\s*(\d+)\s*жңҹ?)?\s*$", clean)
    if m and "дёӢдёҖе®¶" not in m.group(2) and "иҪү" not in m.group(2):
        return {"type": "add_concurrent", "name": m.group(1), "company": m.group(2).strip(),
                "notify_amount": m.group(3) or "", "notify_period": m.group(4) or ""}

    # иҪүжҢҮе®ҡе…¬еҸёпјҲж”ҜжҸҙеӨҡе®¶еҗҢйҖҒгҖҢиҪүA+BгҖҚгҖҒеҸҜеё¶йҖҒд»¶йҮ‘йЎҚгҖҢиҪүA+B 100иҗ¬/24жңҹгҖҚпјү
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*иҪү([^\s]+)(?:\s+(\d+(?:\.\d+)?)\s*иҗ¬?\s*[/пјҸ]\s*(\d+)\s*жңҹ?)?\s*$", clean)
    if m and m.group(2).strip() != "дёӢдёҖе®¶":
        return {"type": "advance", "name": m.group(1), "target": m.group(2).strip(),
                "notify_amount": m.group(3) or "", "notify_period": m.group(4) or ""}

    # еҸ–ж¶Ҳж ёеҮҶпјҡ@AI е§“еҗҚ е…¬еҸё еҸ–ж¶Ҳж ёеҮҶ
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*(.+?)\s*еҸ–ж¶Ҳж ёеҮҶ$", clean)
    if m:
        return {"type": "cancel_approval", "name": m.group(1), "company": m.group(2).strip()}

    # еҸ–ж¶Ҳе©үжӢ’пјҡ@AI е§“еҗҚ е…¬еҸё еҸ–ж¶Ҳе©үжӢ’пјҲжё… cs[е…¬еҸё] + route_plan history е…§и©Іе…¬еҸёе©үжӢ’иЁҳйҢ„пјү
    m = re.match(r"^([гҗҖ-йҝҝпӨҖ-п«ҝ.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*(.+?)\s*еҸ–ж¶Ҳе©үжӢ’$", clean)
    if m:
        return {"type": "cancel_reject", "name": m.group(1), "company": m.group(2).strip()}

    # еҸ–ж¶Ҳж’Ҙж¬ҫпјҡ@AI е§“еҗҚ е…¬еҸё еҸ–ж¶Ҳж’Ҙж¬ҫпјҲдҝқз•ҷж ёеҮҶгҖҒжё…жҺүж’Ҙж¬ҫж—Ҙжңҹпјү
    m = re.match(r"^([гҗҖ-йҝҝпӨҖ-п«ҝ]{2,6})\s*(.+?)\s*еҸ–ж¶Ҳж’Ҙж¬ҫ$", clean)
    if m:
        return {"type": "cancel_disbursement", "name": m.group(1), "company": m.group(2).strip()}

    # дҝ®ж”№ж ёеҮҶйҮ‘йЎҚпјҡ@AI е§“еҗҚ е…¬еҸё ж ёеҮҶ йҮ‘йЎҚпјҲе§“еҗҚе’Ңе…¬еҸёд№Ӣй–“еҝ…й Ҳжңүз©әж јпјү
    # з•°й«”еӯ—пјҲж ёжә–вҶ’ж ёеҮҶпјүз”ұ normalize_command_text зөұдёҖпјӣз”Ё lookbehind жҺ’йҷӨгҖҢеҫ…ж ёеҮҶгҖҚ
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s+(.+?)\s*(?<!еҫ…)ж ёеҮҶ\s*(.+)$", clean)
    if m:
        return {"type": "update_amount", "name": m.group(1), "company": m.group(2).strip(), "amount": m.group(3).strip()}

    # ж ёеҮҶйҮ‘йЎҚпјҲжңӘжҢҮе®ҡе…¬еҸё вҶ’ з”Ёз•¶еүҚ current_companyпјүпјҡе§“еҗҚж ёеҮҶ йҮ‘йЎҚ
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*(?<!еҫ…)ж ёеҮҶ\s*(.+)$", clean)
    if m:
        return {"type": "update_amount", "name": m.group(1), "company": "", "amount": m.group(2).strip()}

    # ж’Ҙж¬ҫпјҲж—ҘжңҹеңЁеүҚгҖҒжңүе…¬еҸёпјүпјҡ@AI е§“еҗҚ е…¬еҸё M/D ж’Ҙж¬ҫ
    # жҺ’йҷӨгҖҢзөҗжЎҲ/йҒ•зҙ„йҮ‘/еҸ–ж¶Ҳж ёеҮҶгҖҚзӯүеӢ•и©һеӯ—иў«з•¶е…¬еҸёеҗҚ
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s+(?!зөҗжЎҲ|йҒ•зҙ„йҮ‘|еҸ–ж¶Ҳж ёеҮҶ)(\S+)\s+(\d{1,2}/\d{1,2})\s*ж’Ҙж¬ҫ$", clean)
    if m:
        return {"type": "disbursed", "name": m.group(1),
                "company": m.group(2).strip(), "date": m.group(3)}

    # ж’Ҙж¬ҫпјҲе…¬еҸё+йҮ‘йЎҚгҖҒжІ’ж—Ҙжңҹпјүпјҡ@AI е§“еҗҚ е…¬еҸё Nиҗ¬ ж’Ҙж¬ҫ [M/D]
    # дҫӢпјҡжұҹж·‘иҠі ж…ўй»һд»ҳ 2иҗ¬ ж’Ҙж¬ҫ
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s+(?!зөҗжЎҲ|йҒ•зҙ„йҮ‘|еҸ–ж¶Ҳж ёеҮҶ)(\S+)\s+(\d+(?:\.\d+)?)\s*иҗ¬\s*ж’Ҙж¬ҫ\s*(\d{1,2}/\d{1,2})?$", clean)
    if m:
        return {"type": "disbursed", "name": m.group(1),
                "company": m.group(2).strip(), "date": m.group(4) or "",
                "amount": m.group(3).strip()}

    # ж’Ҙж¬ҫпјҲж—ҘжңҹеңЁеүҚгҖҒз„Ўе…¬еҸёпјүпјҡ@AI е§“еҗҚ M/D ж’Ҙж¬ҫ
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s+(\d{1,2}/\d{1,2})\s*ж’Ҙж¬ҫ$", clean)
    if m:
        return {"type": "disbursed", "name": m.group(1),
                "company": "", "date": m.group(2)}

    # ж’Ҙж¬ҫжҢҮе®ҡе…¬еҸёпјҲж—ҘжңҹеңЁеҫҢпјүпјҡ@AI е§“еҗҚ е…¬еҸё ж’Ҙж¬ҫ M/D
    # жҺ’йҷӨгҖҢзөҗжЎҲ е·Іж’Ҙж¬ҫгҖҚзӯүжңғиў«иӘӨеҲӨпјҲгҖҢзөҗжЎҲ е·ІгҖҚз•¶е…¬еҸёпјү
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s+(?!зөҗжЎҲ|йҒ•зҙ„йҮ‘|еҸ–ж¶Ҳж ёеҮҶ)(.+?)\s*ж’Ҙж¬ҫ\s*(\d{1,2}/\d{1,2})?$", clean)
    if m:
        return {"type": "disbursed", "name": m.group(1),
                "company": m.group(2).strip(), "date": m.group(3) or ""}

    # ж’Ҙж¬ҫпјҲз„Ўе…¬еҸёгҖҒж—ҘжңҹеңЁеҫҢжҲ–зңҒз•Ҙпјүпјҡ@AI е§“еҗҚ ж’Ҙж¬ҫ M/D
    # иҰҒе…Ҳж–ј missing_verbпјҢеҗҰеүҮ 4/19 жңғиў«иӘӨеҲӨзӮә 4иҗ¬/19жңҹ
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*ж’Ҙж¬ҫ\s*(\d{1,2}/\d{1,2})?$", clean)
    if m:
        return {"type": "disbursed", "name": m.group(1),
                "company": "", "date": m.group(2) or ""}

    # йҳІйҢҜпјҡзңӢиө·дҫҶеғҸгҖҢе§“еҗҚ е…¬еҸё йҮ‘йЎҚ/жңҹж•ёгҖҚдҪҶзјәеӢ•и©һпјҲиҪү/йҖҒ/еҗҢйҖҒ/ж ёеҮҶпјү
    # handler е…§жңғеҲӨж–·пјҡеӢ•и©һеӯ—гҖҒдәӮе…¬еҸёгҖҒеҗҲжі•е…¬еҸё дёүзЁ®жғ…еўғеҲҶеҲҘжҸҗзӨә
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s+([^\s@]+?)\s*(\d+(?:\.\d+)?)\s*иҗ¬?\s*[/пјҸ]\s*(\d+)\s*жңҹ?\s*$", clean)
    if m:
        return {"type": "missing_verb", "name": m.group(1), "companies_raw": m.group(2),
                "amount": m.group(3), "period": m.group(4)}

    # йҳІйҢҜпјҡйҮ‘йЎҚжңҹж•ёжІ’з”ЁгҖҢ/гҖҚеҲҶйҡ”пјҲз©әзҷҪжҲ–е…¶д»–з¬Ұиҷҹпјү
    # дҫӢпјҡгҖҢе‘ЁйҰ®йҲәе©· иҪүе–¬зҫҺ 100 24гҖҚвҶ’ жҸҗзӨәдҪҝз”ЁиҖ…з”ЁгҖҢNиҗ¬/NжңҹгҖҚ
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*(иҪү|йҖҒ)([^\s]+)\s+(\d+(?:\.\d+)?)\s*иҗ¬?\s+(\d+)\s*жңҹ?\s*$", clean)
    if m:
        return {"type": "bad_amount_format", "name": m.group(1), "verb": m.group(2),
                "target": m.group(3), "n1": m.group(4), "n2": m.group(5)}

    # зјәж—Ҙжңҹзҡ„йҖҒд»¶й ҶеәҸпјҡе§“еҗҚ-е…¬еҸё/е…¬еҸё/...пјҲжІ’еүҚз¶ҙж—Ҙжңҹпјү
    # дҫӢпјҡгҖҢйғӯеҜҢеҹҺ-з¬¬дёҖ/дәһеӨӘж©ҹ/21ж©ҹ/йҠҖиЎҢгҖҚ
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})-([^\s]+)$", clean)
    if m and "/" in m.group(2):
        cos = [c.strip() for c in m.group(2).split("/") if c.strip()]
        valid = _get_valid_company_names()
        if any(COMPANY_ALIAS.get(c, c) in valid for c in cos):
            return {"type": "missing_date_hint", "name": m.group(1), "tail": m.group(2)}

    # йҳІйҢҜпјҡиЁҠжҒҜжІ’д»»дҪ•з©әзҷҪдҪҶеҗ«дёӯж–Ү + ж•ёеӯ—/ вҶ’ еҸҜиғҪжҳҜгҖҢе§“еҗҚе…¬еҸёй»ҸеңЁдёҖиө·гҖҚ
    # дҫӢпјҡгҖҢе‘ЁйҰ®йҲәе©·е–¬зҫҺ+жҲҝең°100иҗ¬/120жңҹгҖҚ
    if " " not in clean and "/" in clean and any(c in clean for c in COMPANY_LIST):
        return {"type": "no_space_hint", "raw": clean}

    # ж”№еҗҚпјҡ@AI иҲҠеҗҚ ж”№еҗҚ ж–°еҗҚ
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*ж”№еҗҚ\s*([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})$", clean)
    if m:
        return {"type": "rename", "old_name": m.group(1), "new_name": m.group(2)}

    # ж”№иә«еҲҶиӯүпјҡ@AI е§“еҗҚ ж”№иә«еҲҶиӯү ж–°IDпјҲе°ҫе·ҙеҸҜеҠ еӮҷиЁ»пјү
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*ж”№иә«еҲҶиӯү\s*([A-Z][A-Z0-9]\d{8})(?:\s+.*)?$", clean, re.IGNORECASE)
    if m:
        return {"type": "change_id", "name": m.group(1), "new_id": m.group(2).upper()}
    # ж”№иә«еҲҶиӯү + ID ж јејҸйҢҜпјҲдҫӢеҰӮе°‘дёҖдҪҚгҖҒжү“йҢҜеӯ—пјүвҶ’ жҸҗзӨәж јејҸпјҢдёҚиҗҪеҲ°ж–°е®ўжҲ¶е»әз«Ӣ
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*ж”№иә«еҲҶиӯү\s*(.+)$", clean, re.IGNORECASE)
    if m:
        return {"type": "bad_id_format", "name": m.group(1), "raw_id": m.group(2).strip()}

    # йҮҚе•ҹпјҡ@AI е§“еҗҚ йҮҚе•ҹ
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*йҮҚе•ҹ$", clean)
    if m:
        return {"type": "reopen", "name": m.group(1)}

    # жҹҘжӯ·еҸІпјҡ@AI е§“еҗҚ жӯ·еҸІ
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*жӯ·еҸІ$", clean)
    if m:
        return {"type": "history", "name": m.group(1)}

    # йӮ„еҺҹпјҡ@AI е§“еҗҚ йӮ„еҺҹ NпјҲN й җиЁӯ 1 = жңҖиҝ‘дёҖзӯҶпјү
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*йӮ„еҺҹ\s*(\d+)?$", clean)
    if m:
        try:
            idx = int(m.group(2) or "1")
        except Exception:
            idx = 1
        return {"type": "restore", "name": m.group(1), "index": idx}

    # зөҗжЎҲеё¶еҺҹеӣ пјҡ@AI е§“еҗҚ зөҗжЎҲ еҺҹеӣ 
    m = re.match(r"^([гҗҖ-йҝҝпӨҖ-п«ҝ]{2,6})\s*зөҗжЎҲ\s+(.+)$", clean)
    if m:
        return {"type": "close", "name": m.group(1), "reason": m.group(2).strip()}

    # зөҗжЎҲ
    m = re.match(r"^([гҗҖ-йҝҝпӨҖ-п«ҝ]{2,6})\s*(е·ІзөҗжЎҲ|зөҗжЎҲ)$", clean)
    if m:
        return {"type": "close", "name": m.group(1)}

    # жү№ж¬ЎзөҗжЎҲ/е©үжӢ’ж јејҸйҢҜпјҡе§“еҗҚеҮәзҸҫеңЁгҖҢжү№ж¬ЎзөҗжЎҲ/е©үжӢ’гҖҚеүҚ
    # дҫӢпјҡгҖҢй»ҺжҳҺ зҺӢйҷҪжҳҺ жү№ж¬ЎзөҗжЎҲгҖҚвҶ’ жҸҗзӨәжҸӣиЎҢж јејҸ
    m = re.match(r"^(.+)\s+жү№ж¬Ў(зөҗжЎҲ|е©үжӢ’)$", clean)
    if m:
        return {"type": "bad_batch_format", "action": m.group(2), "raw": clean}

    # гҖҗA ж–№жЎҲгҖ‘е§“еҗҚ е…¬еҸё зөҗжЎҲ вҶ’ е®ўжҲ¶е·Іж ёеҮҶжҷӮгҖҒеҸӘеҫһеҗҢйҖҒжё…е–®з§»йҷӨи©Іе®¶пјҲдёҚзөҗжЎҲе®ўжҲ¶пјү
    # е®ўжҲ¶жңӘж ёеҮҶжҷӮ вҶ’ handler жңғйҖҖеӣһжҷ®йҖҡзөҗжЎҲдёҰжҸҗзӨә
    m = re.match(r"^([гҗҖ-йҝҝпӨҖ-п«ҝ]{2,6})\s+(.+?)\s*зөҗжЎҲ$", clean)
    if m:
        return {"type": "remove_concurrent_or_close", "name": m.group(1),
                "company": m.group(2).strip()}

    # е©үжӢ’ иҪүXXXпјҲжҳҺзўәжҢҮе®ҡиҰҒе©үжӢ’зҡ„е…¬еҸё + и·іеҲ°жҢҮе®ҡе…¬еҸёпјү
    # дҫӢпјҡгҖҢзҺӢйҷҪжҳҺ иЈ•иһҚ е©үжӢ’ иҪүдәһеӨӘгҖҚ= е©үжӢ’иЈ•иһҚпјҲдёҚз®ЎеңЁ current жҲ– concurrentпјү+ current ж”№дәһеӨӘ
    m = re.match(r"^([гҗҖ-йҝҝпӨҖ-п«ҝ]{2,6})\s+(.+?)\s*е©үжӢ’\s*иҪү\s*(.+)$", clean)
    if m:
        return {"type": "reject_to", "name": m.group(1),
                "company": m.group(2).strip(), "target": m.group(3).strip()}

    # е©үжӢ’ иҪүXXXпјҲжІ’жҢҮе®ҡе…¬еҸёпјҢе©үжӢ’з•¶еүҚ current_companyпјү
    m = re.match(r"^([гҗҖ-йҝҝпӨҖ-п«ҝ]{2,6})\s*е©үжӢ’\s*иҪү\s*(.+)$", clean)
    if m:
        return {"type": "reject_to", "name": m.group(1),
                "company": "", "target": m.group(2).strip()}

    # е©үжӢ’ + еҠ йҖҒ иӨҮеҗҲжҢҮд»Өпјҡ@AI е§“еҗҚ е…¬еҸёAе©үжӢ’ йҖҒе…¬еҸёB
    # дҫӢпјҡеҗіз‘һйҠҳ е–¬зҫҺе©үжӢ’ йҖҒиІё10пјҲе–¬зҫҺе©үжӢ’гҖҒеҠ йҖҒиІёж•‘иЈңпјү
    m = re.match(r"^([гҗҖ-йҝҝпӨҖ-п«ҝ]{2,6})\s+(.+?)\s*е©үжӢ’\s*йҖҒ\s*([^\s]+)\s*$", clean)
    if m:
        return {"type": "reject_and_add", "name": m.group(1),
                "reject_company": m.group(2).strip(),
                "add_company": m.group(3).strip()}

    # е©үжӢ’пјҲжҺЁеҲ°дёӢдёҖе®¶пјү
    m = re.match(r"^([гҗҖ-йҝҝпӨҖ-п«ҝ]{2,6})\s*е©үжӢ’$", clean)
    if m:
        return {"type": "reject", "name": m.group(1)}

    # зўәиӘҚе©үжӢ’пјҲжҲҝең°/йҠҖиЎҢ/C йЎһеҲҘзҡ„дәҢж¬ЎзўәиӘҚжҢҮд»Өпјүпјҡ@AI е§“еҗҚ е…¬еҸё зўәиӘҚе©үжӢ’
    m = re.match(r"^([гҗҖ-йҝҝпӨҖ-п«ҝ]{2,6})\s+(.+?)\s*зўә[е®ҡиӘҚ]е©үжӢ’$", clean)
    if m:
        return {"type": "confirm_reject_company", "name": m.group(1), "company": m.group(2).strip()}

    # жҢҮе®ҡжҹҗе®¶е©үжӢ’пјҲдёҚи·іиҪүпјүпјҡ@AI е§“еҗҚ е…¬еҸё е©үжӢ’
    # дҫӢпјҡжһ—дҝҠжқ°еҗҢйҖҒжҲҝең°+йҠҖиЎҢпјҢйҠҖиЎҢи©•дј°дёҚйҒҺ вҶ’ гҖҢжһ—дҝҠжқ° йҠҖиЎҢ е©үжӢ’гҖҚ
    m = re.match(r"^([гҗҖ-йҝҝпӨҖ-п«ҝ]{2,6})\s+(.+?)\s*е©үжӢ’$", clean)
    if m:
        return {"type": "reject_company", "name": m.group(1), "company": m.group(2).strip()}

    def _parse_penalty_amt(num_str, is_wan):
        try:
            f = float(num_str)
            if is_wan: return str(int(f * 10000))
            if f < 1000: return str(int(f * 10000))  # зҙ”ж•ёеӯ— <1000 з•¶иҗ¬
            return str(int(f))
        except Exception:
            return num_str
    # йҒ•зҙ„йҮ‘зўәиӘҚж”Ҝд»ҳ вҖ” з¬¬дәҢйҡҺж®өжӯЈејҸзөҗжЎҲ
    m = re.match(r"^([гҗҖ-йҝҝпӨҖ-п«ҝ]{2,6})\s*йҒ•зҙ„йҮ‘(?:зўәиӘҚж”Ҝд»ҳ|ж”Ҝд»ҳзўәиӘҚ)\s*(\d+(?:\.\d+)?)\s*(иҗ¬)?", clean)
    if m:
        amt = _parse_penalty_amt(m.group(2), bool(m.group(3)))
        return {"type": "penalty", "name": m.group(1), "penalty": amt, "confirmed": True}
    # йҒ•зҙ„йҮ‘е·Іж”Ҝд»ҳ xxxx вҖ” з¬¬дёҖйҡҺж®өпјҡжЁҷиЁҳ pendingгҖҒзӯүдәҢж¬ЎзўәиӘҚ
    m = re.match(r"^([гҗҖ-йҝҝпӨҖ-п«ҝ]{2,6})\s*йҒ•зҙ„йҮ‘е·Іж”Ҝд»ҳ\s*(\d+(?:\.\d+)?)\s*(иҗ¬)?", clean)
    if m:
        amt = _parse_penalty_amt(m.group(2), bool(m.group(3)))
        return {"type": "penalty", "name": m.group(1), "penalty": amt, "confirmed": False}
    # FallbackпјҡиҲҠж јејҸ еҗ«йҖ—иҷҹж•ёеӯ—
    m = re.match(r"^([гҗҖ-йҝҝпӨҖ-п«ҝ]{2,6})\s*йҒ•зҙ„йҮ‘е·Іж”Ҝд»ҳ\s*([\d,пјҢ]+)", clean)
    if m:
        amt = m.group(2).replace(",","").replace("пјҢ","")
        return {"type": "penalty", "name": m.group(1), "penalty": amt, "confirmed": False}

    # з…§жңғпјҡеӨҡзЁ®ж јејҸйғҪж”ҜжҸҙ
    # е…Ҳе®ҡзҫ©пјҡеүқжҺү company еӯ—дёІеүҚе°Һзҡ„гҖҢйҖҒгҖҚгҖҢиҪүгҖҚгҖҢйҖҒеҲ°гҖҚгҖҢиҪүеҲ°гҖҚпјҢжҜҸж®ө + еүҚйғҪеҺ»пјҲеҰӮгҖҢйҖҒе–¬зҫҺ+21гҖҚпјү
    def _strip_verb(s):
        if not s: return s
        out = []
        for item in re.split(r"([+пјӢ])", s):
            if item in ("+", "пјӢ"): out.append(item); continue
            item = re.sub(r"^\s*(?:йҖҒеҲ°|иҪүеҲ°|йҖҒ|иҪү)\s*", "", item)
            out.append(item)
        return "".join(out).strip()
    # @AI з…§жңғ зҺӢе°ҸжҳҺ дәһеӨӘ+е’ҢиЈ•
    m = re.match(r"^з…§жңғ\s*([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})(?:\s+(.+))?$", clean)
    if m:
        return {"type": "notification", "name": m.group(1), "company": _strip_verb((m.group(2) or "").strip())}
    # @AI зҺӢе°ҸжҳҺ з…§жңғ дәһеӨӘ+е’ҢиЈ•
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*з…§жңғ(?:\s+(.+))?$", clean)
    if m:
        return {"type": "notification", "name": m.group(1), "company": _strip_verb((m.group(2) or "").strip())}
    # @AI зҺӢе°ҸжҳҺ дәһеӨӘ+е’ҢиЈ• з…§жңғ   (еҗ«гҖҢйҖҒе–¬зҫҺ+21 з…§жңғгҖҚ)
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s+(.+?)\s*з…§жңғ$", clean)
    if m:
        return {"type": "notification", "name": m.group(1), "company": _strip_verb(m.group(2).strip())}

    # е°Қдҝқжҙҫд»¶пјҲA иЁҠжҒҜпјүпјҡиҫҰзҗҶж–№жЎҲ/ж ёеҮҶйҮ‘йЎҚ/е®ўжҲ¶е§“еҗҚ/е°Қдҝқең°еҚҖ
    if "е®ўжҲ¶е§“еҗҚ" in clean and "е°Қдҝқең°еҚҖ" in clean:
        fields = {}
        for line in clean.splitlines():
            mm = re.match(r"^\s*(иҫҰзҗҶж–№жЎҲ|ж ёеҮҶйҮ‘йЎҚ|е®ўжҲ¶е§“еҗҚ|е°Қдҝқең°еҚҖ)\s*[:пјҡ]\s*(.+?)\s*$", line)
            if mm:
                fields[mm.group(1)] = mm.group(2).strip()
        name = fields.get("е®ўжҲ¶е§“еҗҚ", "")
        if name:
            return {
                "type": "signing_request",
                "name": name,
                "plan": fields.get("иҫҰзҗҶж–№жЎҲ", ""),
                "amount": fields.get("ж ёеҮҶйҮ‘йЎҚ", ""),
                "area": fields.get("е°Қдҝқең°еҚҖ", ""),
            }

    # е°ҚдҝқжҷӮй–“ең°й»һпјҲB иЁҠжҒҜпјүпјҡеӨҡзЁ®ж јејҸ
    # ж јејҸ A (иҲҠ)пјҡе°Қдҝқ жҘӯеӢҷе“Ў XXе°Қдҝқ / жҷӮй–“ X / ең°й»һ X
    # ж јејҸ B (ж–°)пјҡе§“еҗҚ е…¬еҸё/ж–№жЎҲ / жҷӮй–“ X / ең°й»һ X  пјҲе°Қдҝқе“ЎеҜҰйҡӣеёёз”Ёпјү
    lines_b = [ln.strip() for ln in clean.splitlines() if ln.strip()]
    if lines_b and len(lines_b) >= 2 and ("жҷӮй–“" in clean or "ең°й»һ" in clean):
        # иҲҠж јејҸ
        m = re.match(r"^е°Қдҝқ\s+([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s+(.+?)е°Қдҝқ\s*$", lines_b[0])
        if m:
            salesperson = m.group(1)
            signing_co = m.group(2).strip()
            time_str = ""
            loc_str = ""
            for line in lines_b[1:]:
                mt = re.match(r"^жҷӮй–“\s*[:пјҡ]?\s*(.+)$", line)
                if mt:
                    time_str = mt.group(1).strip()
                    continue
                ml = re.match(r"^ең°й»һ\s*[:пјҡ]?\s*(.+)$", line)
                if ml:
                    loc_str = ml.group(1).strip()
            return {
                "type": "signing_schedule",
                "salesperson": salesperson,
                "signing_company": signing_co,
                "time": time_str,
                "location": loc_str,
            }
        # ж–°ж јејҸпјҡз¬¬дёҖиЎҢгҖҢе§“еҗҚ е…¬еҸё/ж–№жЎҲгҖҚгҖҒдёӢйқўжңү жҷӮй–“/ең°й»һ
        m2 = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s+([\u3400-\u9fff\uf900-\ufaff0-9A-Z()пјҲпјү/]+?)(\s+ж”№жҷӮй–“)?\s*$", lines_b[0])
        if m2 and any(ln.startswith("жҷӮй–“") or ln.startswith("ең°й»һ") for ln in lines_b[1:]):
            name = m2.group(1)
            signing_co = m2.group(2).strip()
            time_str = ""
            loc_str = ""
            for line in lines_b[1:]:
                mt = re.match(r"^жҷӮй–“\s*[:пјҡ]?\s*(.+)$", line)
                if mt:
                    time_str = mt.group(1).strip()
                    continue
                ml = re.match(r"^ең°й»һ\s*[:пјҡ]?\s*(.+)$", line)
                if ml:
                    loc_str = ml.group(1).strip()
            if signing_co and (time_str or loc_str):
                return {
                    "type": "signing_schedule",
                    "name": name,
                    "signing_company": signing_co,
                    "time": time_str,
                    "location": loc_str,
                }

    # ===== еёёиҰӢйҢҜиӘӨж јејҸйҳІйҢҜпјҲзөҰжӯЈзўәзҜ„дҫӢжҸҗзӨәпјү=====
    # иҪүдҪҶжІ’жҢҮе®ҡе…¬еҸё
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*иҪү\s*$", clean)
    if m:
        return {"type": "format_hint", "hint": f"иҪүе“Әе®¶пјҹ\nдҫӢпјҡ@AI {m.group(1)} иҪүе–¬зҫҺ\nеё¶йҮ‘йЎҚпјҡ@AI {m.group(1)} иҪүе–¬зҫҺ 50иҗ¬/24жңҹ"}
    # йҖҒдҪҶжІ’жҢҮе®ҡе…¬еҸё
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*йҖҒ\s*$", clean)
    if m:
        return {"type": "format_hint", "hint": f"йҖҒе“Әе®¶пјҹ\nдҫӢпјҡ@AI {m.group(1)} йҖҒз¬¬дёҖ\nеё¶йҮ‘йЎҚпјҡ@AI {m.group(1)} йҖҒз¬¬дёҖ 30иҗ¬/24жңҹ"}
    # ж ёеҮҶдҪҶжІ’е…¬еҸёжІ’йҮ‘йЎҚ
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*ж ёеҮҶ\s*$", clean)
    if m:
        return {"type": "format_hint", "hint": f"е“Әе®¶ж ёеҮҶпјҹйҮ‘йЎҚеӨҡе°‘пјҹ\nдҫӢпјҡ@AI {m.group(1)} з¬¬дёҖ ж ёеҮҶ 30иҗ¬"}
    # йҒ•зҙ„йҮ‘жІ’йҮ‘йЎҚ
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*йҒ•зҙ„йҮ‘[е·Іж”Ҝд»ҳ]*\s*$", clean)
    if m:
        return {"type": "format_hint", "hint": f"йҒ•зҙ„йҮ‘еӨҡе°‘пјҹ\nдҫӢпјҡ@AI {m.group(1)} йҒ•зҙ„йҮ‘е·Іж”Ҝд»ҳ30000"}
    # ж”№еҗҚжІ’ж–°еҗҚ
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*ж”№еҗҚ\s*$", clean)
    if m:
        return {"type": "format_hint", "hint": f"ж”№жҲҗд»ҖйәјеҗҚеӯ—пјҹ\nдҫӢпјҡ@AI {m.group(1)} ж”№еҗҚ ж–°еҗҚеӯ—"}
    # ж”№иә«еҲҶиӯүжІ’ ID
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*ж”№иә«еҲҶиӯү\s*$", clean)
    if m:
        return {"type": "format_hint", "hint": f"ж–°иә«еҲҶиӯүпјҹ\nдҫӢпјҡ@AI {m.group(1)} ж”№иә«еҲҶиӯү A123456789"}
    # еҸ–ж¶Ҳж ёеҮҶжІ’жҢҮе®ҡе…¬еҸё
    m = re.match(r"^([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})\s*еҸ–ж¶Ҳж ёеҮҶ\s*$", clean)
    if m:
        return {"type": "format_hint", "hint": f"иҰҒеҸ–ж¶Ҳе“Әе®¶зҡ„ж ёеҮҶпјҹ\nдҫӢпјҡ@AI {m.group(1)} з¬¬дёҖ еҸ–ж¶Ҳж ёеҮҶ"}
    # ж’Ҙж¬ҫеӢ•и©һеңЁеүҚпјҲй ҶеәҸйҢҜпјү
    m = re.match(r"^ж’Ҙж¬ҫ\s+([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})", clean)
    if m:
        return {"type": "format_hint", "hint": f"ж’Ҙж¬ҫжҢҮд»Өж јејҸпјҡе§“еҗҚеңЁеүҚ\nдҫӢпјҡ@AI {m.group(1)} ж’Ҙж¬ҫ 4/18\nжҲ–пјҡ@AI {m.group(1)} иЈ•иһҚ ж’Ҙж¬ҫ 4/18"}
    # зөҗжЎҲеӢ•и©һеңЁеүҚ
    m = re.match(r"^зөҗжЎҲ\s+([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})", clean)
    if m:
        return {"type": "format_hint", "hint": f"зөҗжЎҲжҢҮд»Өж јејҸпјҡе§“еҗҚеңЁеүҚ\nдҫӢпјҡ@AI {m.group(1)} зөҗжЎҲ"}
    # е©үжӢ’еӢ•и©һеңЁеүҚ
    m = re.match(r"^е©үжӢ’\s+([\u3400-\u9fff\uf900-\ufaff.пјҺВ·вҖўгғ»вҖ§]{2,12})", clean)
    if m:
        return {"type": "format_hint", "hint": f"е©үжӢ’жҢҮд»Өж јејҸпјҡе§“еҗҚеңЁеүҚ\nдҫӢпјҡ@AI {m.group(1)} е©үжӢ’"}

    return None


def generate_notification_text(r: dict, company: str = "") -> str:
    """ж №ж“ҡе®ўжҲ¶ DB иіҮж–ҷиҮӘеӢ•з”ўз”ҹз…§жңғжіЁж„ҸдәӢй …ж–Үеӯ—гҖӮ
    еҘ—з”Ё adminB иӘҝж•ҙиҰҸеүҮпјҡжңҲи–Ә<3.5иҗ¬вҶ’3.5иҗ¬гҖҒе№ҙиіҮ<1вҶ’1е№ҙгҖҒеұ…дҪҸ<5вҶ’5е№ҙгҖҒ
    еұ…дҪҸз§ҹеұӢ/е®ҝиҲҚвҶ’иҰӘеұ¬гҖҒеӯёжӯ·еңӢдёӯвҶ’й«ҳдёӯ/иҒ·пјҲи·ҹ adminB й ҒйқўдёҖиҮҙпјүгҖӮ"""
    def v(k): return (r.get(k, "") or "").strip()

    # еҘ—з”Ё adminB иҰҸеүҮ вҶ’ еҸ–иӘҝж•ҙеҫҢзҡ„еҖј
    try:
        rules = apply_adminb_rules(r)
    except Exception:
        rules = {}

    name = v("customer_name")
    # е…¬еҸёпјҡе„Әе…Ҳз”ЁеҸғж•ёпјҢе…¶ж¬Ў current_companyпјҢжңҖеҫҢ company
    co = company or v("current_company") or v("company") or ""

    # еұ…дҪҸең°пјҡеҗҢжҲ¶зұҚвҶ’жҲ¶зұҚпјҢеҗҰеүҮвҶ’зҸҫеұ…ең°
    # дёүзЁ®жғ…жіҒйғҪз®—еҗҢжҲ¶зұҚпјҡ
    # (1) live_same_as_reg ж——жЁҷ = "1"
    # (2) дҪҸе®¶ең°еқҖж•ҙдёІзӮәз©әпјҲиЎЁзӨәжІ’еҲҶй–ӢеЎ«гҖҒй җиЁӯеҗҢжҲ¶зұҚпјү
    # (3) дҪҸе®¶ең°еқҖиҲҮжҲ¶зұҚең°еқҖеӯ—дёІзӣёзӯүпјҲдҪҝз”ЁиҖ…е…©йӮҠйғҪеЎ«дәҶдҪҶе…§е®№дёҖжЁЈпјү
    _reg_full = (v("reg_city") + v("reg_district") + v("reg_address")).replace(" ", "")
    _live_full = (v("live_city") + v("live_district") + v("live_address")).replace(" ", "")
    _live_empty = not _live_full.strip()
    _addr_match = bool(_reg_full) and _reg_full == _live_full
    live_type = "жҲ¶зұҚ" if (v("live_same_as_reg") == "1" or _live_empty or _addr_match) else "зҸҫеұ…ең°"
    live_years = (rules.get("live_years_val") or v("live_years") or "0")
    # еұ…дҪҸзӢҖжіҒпјҡз…§жңғи©ұиЎ“з…§ DB еҺҹеҖјпјҲе®ҝиҲҚе°ұиӘӘе®ҝиҲҚгҖҒзҲ¶жҜҚе°ұиӘӘзҲ¶жҜҚпјҢдёҚеҘ— adminB иҰҸеүҮзҡ„иҪүиҰӘеұ¬пјү
    live_status = v("live_status") or "иҮӘжңү"

    # е№ҙиіҮпјҲеҘ— <1вҶ’1 иҰҸеүҮпјү+ жңҲд»Ҫ
    co_years = (rules.get("company_years_val") or v("company_years") or "0")
    co_months = (rules.get("company_months_val") or v("company_months") or "0")
    try:
        _m_int = int(float(str(co_months).replace("жңҲ","").strip())) if co_months else 0
        co_years_str = f"{co_years}е№ҙ{_m_int}жңҲ" if _m_int > 0 else f"{co_years}е№ҙ"
    except Exception:
        co_years_str = f"{co_years}е№ҙ"

    # жңҲи–ӘпјҲеҘ— <3.5иҗ¬вҶ’3.5иҗ¬ иҰҸеүҮпјүпјҢијёеҮәгҖҢNиҗ¬гҖҚж јејҸ
    salary_raw = rules.get("salary_val") or v("company_salary") or "0"
    salary_str = ""
    try:
        _raw = str(salary_raw).replace("иҗ¬", "").replace(",", "").strip()
        sal = float(_raw) if _raw else 0
        # rules зҡ„ salary_val жҳҜиҗ¬зӮәе–®дҪҚпјҲеҰӮгҖҢ3.5гҖҚпјүпјҢDB еҺҹе§ӢеҸҜиғҪжҳҜгҖҢ35000гҖҚе…ғ
        if sal >= 1000:
            sal = sal / 10000
        if sal > 0:
            salary_str = f"{int(sal)}иҗ¬" if sal == int(sal) else f"{sal}иҗ¬"
        else:
            salary_str = "0"
    except Exception:
        salary_str = str(salary_raw)

    # йҖҒд»¶йҮ‘йЎҚ/жңҹж•ёпјҲnotify_amount вү  approved_amountпјүпјҡ
    # е„Әе…Ҳз”ЁжүӢеӢ•иЁӯе®ҡзҡ„йҖҒд»¶йҮ‘йЎҚ вҶ’ жІ’иЁӯеүҮз”Ё PLAN_INFO ж–№жЎҲй җиЁӯ вҶ’ еҶҚжІ’жңүеүҮз”Ё eval_fund_need
    # дёҚ fallback еҲ° approved_amountпјҲж ёеҮҶйҮ‘йЎҚпјүпјҢйҒҝе…Қе®ўжҲ¶ж ёеҮҶеҫҢз…§жңғиЁҠжҒҜйЎҜзӨәж ёеҮҶйҮ‘йЎҚйҖ жҲҗиӘӨе°Һ
    manual_amount = v("notify_amount")
    manual_period = v("notify_period")
    # жүҫ PLAN_INFOпјҡе…ҲзӣҙжҹҘгҖҒеҶҚи©Ұ COMPANY_ALIASгҖҒжңҖеҫҢи©Ұ normalize_section
    plan_info = PLAN_INFO.get(co)
    if not plan_info and co:
        aliased = COMPANY_ALIAS.get(co, "")
        if aliased:
            plan_info = PLAN_INFO.get(aliased)
    if not plan_info and co:
        try:
            norm = normalize_section(co)
            plan_info = PLAN_INFO.get(norm)
        except Exception:
            pass
    if manual_amount:
        amt_str = manual_amount if "иҗ¬" in manual_amount else f"{manual_amount}иҗ¬"
        amount_line = f"{amt_str}/{manual_period}жңҹ" if manual_period else amt_str
    elif plan_info and plan_info[1]:
        amount_line = plan_info[1]
    else:
        # eval_fund_need зҙ”ж•ёеӯ—пјҲеҰӮ 200000пјүиҮӘеӢ•иҪүиҗ¬
        raw_fund = v("eval_fund_need") or ""
        try:
            fund_num = float(raw_fund.replace("иҗ¬","").replace(",","").replace("$","").strip())
            if fund_num >= 10000:
                w = fund_num / 10000
                amount_line = f"{int(w)}иҗ¬" if w == int(w) else f"{w}иҗ¬"
            elif fund_num > 0:
                amount_line = f"{int(fund_num)}иҗ¬" if fund_num == int(fund_num) else f"{fund_num}иҗ¬"
            else:
                amount_line = ""
        except Exception:
            amount_line = raw_fund

    # йә»еҗүзі»еҲ—пјҡadminB еӢҫгҖҢ6иҗ¬18жңҹ3771гҖҚвҶ’ иҰҶеҜ« amount_lineпјҲе„Әе…Ҳж–ј PLAN_INFO й җиЁӯ 10иҗ¬/24пјү
    is_mj = "йә»еҗү" in co or (plan_info and "йә»еҗү" in plan_info[0])
    if is_mj and v("adminb_mj_6w18p") == "1":
        amount_line = "6иҗ¬/18жңҹ"

    # еӯёжӯ·пјҡиҪүжҲҗеҸЈиӘһ
    edu = v("education")
    EDU_MAP = {"е°Ҳз§‘/еӨ§еӯё": "еӨ§еӯё", "е°Ҳз§‘гҖҒеӨ§еӯё": "еӨ§еӯё", "й«ҳдёӯ/иҒ·": "й«ҳдёӯ",
               "й«ҳдёӯиҒ·": "й«ҳдёӯ", "з ”з©¶жүҖд»ҘдёҠ": "з ”з©¶жүҖ", "е…¶д»–": "й«ҳдёӯ"}
    edu_spoken = EDU_MAP.get(edu, edu) if edu else "й«ҳдёӯ"

    # иіҮйҮ‘з”ЁйҖ”пјҡз…§жңғи©ұиЎ“дёҖеҫӢеӣәе®ҡгҖҢе®¶з”ЁгҖҚпјҲadminb_fund_use еҸӘзөҰз”іи«ӢжӣёдёӢжӢүз”Ёпјү
    fund = "е®¶з”Ё"

    # еҗҚдёӢи»ҠиІёзӢҖжіҒпјҡжӘўжҹҘ debt_list иЈЎзҡ„еӢ•дҝқпјҸе…¬и·Ҝж¬„дҪҚ
    # иҰҸеүҮпјҡеҸӘиҰҒд»»дёҖзӯҶиІ еӮөзҡ„еӢ•дҝқж¬„дҪҚжҳҜгҖҢе…¬и·Ҝ/еӢ•дҝқ/е…¬и·Ҝ+еӢ•дҝқгҖҚвҶ’ еҗҚдёӢи»ҠиІёжӯЈеёёз№і
    # пјҲдёҚз®ЎиІёж¬ҫе•Ҷе®¶еҗҚзЁұпјҢеӢ•дҝқж¬„дҪҚе°ұжҳҜи»ҠиІёзҡ„жҳҺзўәжЁҷиЁҳпјү
    car_loan_status = "еҗҚдёӢз„ЎиІёж¬ҫ"
    try:
        debt_list = json.loads(v("debt_list")) if v("debt_list") else []
        for d in debt_list:
            dy = d.get("dy", "") or ""
            if "е…¬и·Ҝ" in dy or "еӢ•дҝқ" in dy:
                car_loan_status = "еҗҚдёӢи»ҠиІёжӯЈеёёз№і"
                break
    except Exception:
        pass

    # зө„еҗҲз…§жңғж–Үеӯ—
    lines = [
        name,
        "з…§жңғжіЁж„ҸдәӢй …",
        f"вң…зҸҫеұ…дҪҸ{live_type}ең°еқҖ еұ…дҪҸ{live_years}е№ҙ {live_status} е·ҘдҪңе№ҙиіҮ{co_years_str} жңҲи–Ә{salary_str}",
    ]
    if amount_line:
        lines.append(f"вң…{amount_line}")
    lines += [
        "вң…еёіе–®з°ЎиЁҠжўқзўјз№іж¬ҫ",
        "вң… е§“еҗҚиҰӘз°Ҫ",
        f"вң…еӯёжӯ·и©ўе•ҸеҲ°йә»з…©иӘӘ{edu_spoken}з•ў",
        f"вң…иіҮйҮ‘з”ЁйҖ” пјҡ{fund}",
        "вң… и©ўе•Ҹд»»дҪ•жі•еӯёпјҢеҲ‘дәӢпјҢдёҖеҫӢйғҪиӘӘдёҚжҳҜиҮӘе·ұзҡ„",
        "вң…еҒҮеҰӮе•ҸеҲ°еңЁеӨ–йқўжңүжІ’жңүж¬ ж¬ҫе…¬еҸёиҰҒиӘӘжІ’жңүпјҒ",
        f"вң…{car_loan_status}",
        "",
        "вҡ пёҸдёҚеҘҪзҡ„дёҖжҰӮеҗҰиӘҚе–”пјҢжҜ”еҰӮеҚЎеҫӘеҚЎеӮөе°ұз®—жё…е„ҹдәҶпјҢжІ’жӢүиҒҜеҫөпјҢжңғе•Ҹзҡ„жҜ”ијғеӨҡпјҒд»»дҪ•жі•еӯё еҰӮжһңи©ўе•Ҹйә»з…©д№ҹйғҪеҗҰиӘҚрҹ’Ҝ",
        "",
        "рҹ’ҢзўәиӘҚйҖІд»¶з…§жңғжҷӮй–“",
        "     рҹҺҖзҷҪеӨ©йҖҡзҹҘйҖІд»¶ дёӯеҚҲжҲ–жҳҜдёӢеҚҲд»ҘеүҚжіЁж„ҸдҫҶйӣ»",
    ]
    return "\n".join(lines)


def _get_valid_company_names():
    """жүҖжңүзі»зөұиӘҚиӯҳзҡ„е…¬еҸёеҗҚпјҲCOMPANY_LIST + COMPANY_ALIAS + PLAN_INFO + COMPANY_SECTION_MAPпјү"""
    valid = set(COMPANY_LIST) | set(COMPANY_ALIAS.keys()) | set(COMPANY_ALIAS.values())
    valid |= {v[0] for v in PLAN_INFO.values()} | set(PLAN_INFO.keys())
    valid |= set(COMPANY_SECTION_MAP.keys()) | set(COMPANY_SECTION_MAP.values())
    return valid


def _validate_companies_or_warn(companies, reply_token, name):
    """й©—иӯүе…¬еҸёеҗҚжё…е–®пјҢиӢҘжңүжңӘзҹҘеӣһиҰҶиӯҰе‘Ҡ + еҗҲжі•еҗҚжё…е–® дёҰеӣһ Falseпјӣе…ЁйғЁеҗҲжі•еӣһ True"""
    valid = _get_valid_company_names()
    unknown = [c for c in companies if c not in valid]
    if unknown:
        reply_text(reply_token,
                   f"вҡ пёҸ {name}пјҡжүҫдёҚеҲ°е…¬еҸёгҖҢ{'гҖҒ'.join(unknown)}гҖҚ\n"
                   f"еёёиҰӢе…¬еҸёеҗҚпјҡдәһеӨӘгҖҒе–¬зҫҺгҖҒз¬¬дёҖгҖҒжҲҝең°гҖҒ21гҖҒиЈ•иһҚгҖҒе’ҢиЈ•гҖҒйә»еҗүгҖҒиІёж•‘иЈңгҖҒй„үж°‘гҖҒйҠҖиЎҢгҖҒйӣ¶еҚЎгҖҒе•Ҷе“ҒиІёгҖҒд»ЈжӣёгҖҒз•¶иҲ–")
        return False
    return True


def _field_display_label(field_name: str) -> str:
    """DB ж¬„дҪҚеҗҚзҝ»иӯҜжҲҗжҘӯеӢҷзңӢеҫ—жҮӮзҡ„дёӯж–ҮпјҲз”Ёж–јеҹ·иЎҢж‘ҳиҰҒпјү"""
    return {
        "company": "е…¬еҸё",
        "current_company": "з•¶еүҚе…¬еҸё",
        "concurrent_companies": "еҗҢйҖҒ",
        "report_section": "ж—Ҙе ұеҚҖеЎҠ",
        "approved_amount": "ж ёеҮҶйҮ‘йЎҚ",
        "notify_amount": "йҖҒд»¶йҮ‘йЎҚ(иҗ¬)",
        "notify_period": "йҖҒд»¶жңҹж•ё",
        "disbursement_date": "ж’Ҙж¬ҫж—Ҙ",
        "status": "зӢҖж…Ӣ",
        "id_no": "иә«еҲҶиӯү",
        "customer_name": "е§“еҗҚ",
        "route_plan": "йҖҒд»¶й ҶеәҸ",
        "source_group_id": "жүҖеұ¬зҫӨзө„",
    }.get(field_name, field_name)


def update_with_verify(case_id: str, changes: Dict, from_group_id: str = "", text_log: str = ""):
    """еҹ·иЎҢ update_customer дёҰеҜҰжё¬ DB еүҚеҫҢи®ҠеҢ–пјҢеӣһеӮі (ok, diff_lines, customer_name)гҖӮ
    changes жҳҜиҰҒ update зҡ„ж¬„дҪҚ dictпјӣdiff_lines жҳҜеҜҰйҡӣи®ҠеӢ•зҡ„ж¬„дҪҚж‘ҳиҰҒпјҲгҖҢж¬„дҪҚ: иҲҠ вҶ’ ж–°гҖҚпјүгҖӮ
    иӢҘ case_id дёҚеӯҳеңЁ вҶ’ ok=FalseпјӣжүҖжңүж¬„дҪҚйғҪжІ’и®Ҡ вҶ’ diff_lines з©әпјҲиЎЁйқўз„Ўи®ҠеҢ–пјүгҖӮ
    """
    conn = get_conn(); cur = conn.cursor()
    cur.execute("SELECT * FROM customers WHERE case_id=?", (case_id,))
    before = cur.fetchone()
    if not before:
        conn.close()
        return False, ["вҡ пёҸ жЎҲд»¶дёҚеӯҳеңЁ"], ""
    before_dict = dict(before)
    conn.close()
    # йҒҺжҝҫ + key иҪүжҸӣпјҲupdate_customer з°ҪеҗҚз”Ё name е°ҚжҮү customer_nameпјү
    allowed_keys = {"company", "status", "source_group_id", "route_plan",
                    "current_company", "report_section", "approved_amount",
                    "disbursement_date", "signing_area", "signing_salesperson",
                    "signing_company", "signing_time", "signing_location",
                    "notify_amount", "notify_period", "concurrent_companies",
                    "id_no", "name", "company_status", "pending_docs"}
    filtered = {}
    for k, v in changes.items():
        # None дёҖеҫӢиҪү "" жүҚиғҪзңҹжӯЈжё…з©әж¬„дҪҚпјҲupdate_customer е°Қ None зҡ„иӘһж„ҸжҳҜгҖҢдёҚеӢ•гҖҚпјү
        if v is None:
            v = ""
        if k == "customer_name":
            filtered["name"] = v
        elif k in allowed_keys:
            filtered[k] = v
    kwargs = {"text": text_log, "from_group_id": from_group_id}
    kwargs.update(filtered)
    update_customer(case_id, **kwargs)
    conn2 = get_conn(); cur2 = conn2.cursor()
    cur2.execute("SELECT * FROM customers WHERE case_id=?", (case_id,))
    after = cur2.fetchone()
    conn2.close()
    after_dict = dict(after) if after else {}
    diffs = []
    for k in changes.keys():
        if k in ("text", "from_group_id"):
            continue
        old_v = before_dict.get(k)
        new_v = after_dict.get(k)
        if old_v != new_v:
            old_disp = old_v if old_v not in (None, "") else "(з©ә)"
            new_disp = new_v if new_v not in (None, "") else "(з©ә)"
            diffs.append(f"вҖў {_field_display_label(k)}: {old_disp} вҶ’ {new_disp}")
    return True, diffs, before_dict.get("customer_name", "")


def normalize_command_text(text: str) -> str:
    """@AI жҢҮд»Өж–Үеӯ—жӯЈиҰҸеҢ–пјҡе…ЁеҪўвҶ’еҚҠеҪўгҖҒз•°й«”еӯ—зөұдёҖгҖҒеӨҡз©әзҷҪеҗҲдҪөгҖӮ
    parse_special_command йҖІе…ҘеүҚе…Ҳи·‘пјҢи®“ regex еҸӘйңҖеҜ«дёҖеҘ—жЁҷжә–еҜ«жі•гҖӮ
    """
    if not text:
        return ""
    # е…ЁеҪўиӢұж•ё/жЁҷй»һ вҶ’ еҚҠеҪўпјҲU+FF01~U+FF5Eпјү
    out = []
    for ch in text:
        code = ord(ch)
        if 0xFF01 <= code <= 0xFF5E:
            out.append(chr(code - 0xFEE0))
        elif code == 0x3000:  # е…ЁеҪўз©әзҷҪ
            out.append(" ")
        else:
            out.append(ch)
    text = "".join(out)
    # з¬ҰиҷҹзөұдёҖ
    text = text.replace("пјҸ", "/").replace("пјӢ", "+")
    # з•°й«”еӯ—зөұдёҖпјҲеҸ°зҒЈжҘӯеӢҷеҸҜиғҪжү“гҖҢж ёеҮҶ/ж ёжә–/ж ёеҮ–гҖҒиә«д»Ҫиӯү/иә«еҲҶиӯүгҖҚпјү
    text = text.replace("ж ёжә–", "ж ёеҮҶ").replace("ж ёеҮ–", "ж ёеҮҶ")
    text = text.replace("иә«д»Ҫиӯү", "иә«еҲҶиӯү")
    # еӨҡеҖӢз©әзҷҪ/Tab вҶ’ е–®дёҖз©әзҷҪ
    text = re.sub(r"[ \t]+", " ", text).strip()
    return text


def _validate_new_case_fields(date: str, name: str, id_no: str):
    """е»әе®ўжҲ¶еүҚжӘўжҹҘиіҮж–ҷпјҢеӣһеӮіиӯҰе‘ҠиЁҠжҒҜеҲ—иЎЁпјҲдёҚ block е»әз«ӢпјҢеҸӘжҸҗзӨәпјүгҖӮ"""
    warnings = []
    if date:
        m = re.match(r"^(\d{1,4})/(\d{1,2})", date)
        if m:
            y = int(m.group(1))
            # еҗҲзҗҶпјҡж°‘еңӢ 100-130пјҲ2011-2041пјүгҖҒиҘҝе…ғ 2020-2100пјӣ3 дҪҚж•ё or 2 дҪҚж•ёж°‘еңӢе№ҙеёёиҰӢ
            if 1 <= y <= 3:
                warnings.append(f"ж—ҘжңҹгҖҢ{date}гҖҚж°‘еңӢе№ҙеӨӘе°ҸпјҢеҸҜиғҪжү“йҢҜ")
            elif 4 <= y < 80:  # ж°‘еңӢ 4~79 (1915~1990)пјҢе№ҙзҙҖеӨӘеӨ§зҡ„е®ўжҲ¶пјҹ
                warnings.append(f"ж—ҘжңҹгҖҢ{date}гҖҚе°ҚжҮүж°‘еңӢ{y}е№ҙ({1911+y}е№ҙ)пјҢзўәиӘҚз„ЎиӘӨпјҹ")
            elif 131 <= y < 1000:
                warnings.append(f"ж—ҘжңҹгҖҢ{date}гҖҚж°‘еңӢе№ҙеӨӘеӨ§пјҢеҸҜиғҪжү“йҢҜ")
    if id_no:
        if not re.match(r"^[A-Z][A-Z0-9]\d{8}$", id_no, re.IGNORECASE):
            warnings.append(f"иә«еҲҶиӯүгҖҢ{id_no}гҖҚж јејҸдёҚжЁҷжә–пјҲжҮүзӮә 1 иӢұж–Үеӯ—жҜҚ + 1 иӢұж•ё + 8 дҪҚж•ёеӯ—пјү")
        elif not validate_tw_id_checksum(id_no):
            warnings.append(f"иә«еҲҶиӯүгҖҢ{id_no}гҖҚж Ўй©—дҪҚдёҚз¬ҰпјҢеҸҜиғҪжү“йҢҜдёҖзўј")
    if name:
        if len(name) > 5:
            warnings.append(f"е§“еҗҚгҖҢ{name}гҖҚй•·еәҰ {len(name)} еӯ—пјҢзўәиӘҚз„ЎиӘӨпјҹ")
    return warnings


def _resolve_target(name: str, group_id: str, reply_token: str):
    """дҫқе§“еҗҚеңЁжң¬зҫӨзө„жүҫ ACTIVE е®ўжҲ¶пјҲиј•йҮҸзүҲпјҡеӨҡзӯҶеӣһиӯҰе‘ҠдёҚи·іжҢүйҲ•пјү"""
    rows = find_active_by_name(name)
    same = [r for r in rows if r["source_group_id"] == group_id]
    if len(same) == 1:
        return same[0]
    if len(same) > 1:
        lines = [f"вҡ пёҸ жң¬зҫӨзө„жңү {len(same)} дҪҚгҖҢ{name}гҖҚпјҢи«Ӣз”Ёиә«еҲҶиӯүжҲ–жӣҙзІҫзўәиӯҳеҲҘпјҡ"]
        for r in same:
            id4 = (r["id_no"] or "")[-4:] or "з„Ў"
            co = r["current_company"] or r["company"] or "жңӘеЎ«"
            lines.append(f"  - {co}пјҲиә«еҲҶиӯүжң«4пјҡ{id4}пјү")
        reply_text(reply_token, "\n".join(lines))
        return None
    if rows:
        return rows[0]
    reply_text(reply_token,
               f"вқҢ жүҫдёҚеҲ°е®ўжҲ¶пјҡ{name}\n"
               f"еҸҜиғҪеҺҹеӣ пјҡ\n"
               f"  вҖў е§“еҗҚжү“йҢҜпјҲ2-6 еҖӢдёӯж–Үеӯ—пјү\n"
               f"  вҖў е®ўжҲ¶йӮ„жІ’е»әз«Ӣ\n"
               f"  вҖў е®ўжҲ¶е·ІзөҗжЎҲ вҶ’ е…Ҳжү“гҖҢ@AI {name} йҮҚе•ҹгҖҚ")
    return None


def _check_active_or_warn(target, reply_token, action_label: str, customer_name: str = ""):
    """з ҙеЈһжҖ§жҢҮд»ӨеүҚжӘўжҹҘ target жҳҜеҗҰзӮә ACTIVEпјӣйқһ ACTIVE еүҮиӯҰе‘ҠдёҰеӣһ False"""
    if not target:
        return False
    status = target["status"] if "status" in target.keys() else None
    if status == "ACTIVE":
        return True
    status_label = {"CLOSED": "е·ІзөҗжЎҲ", "PENALTY": "йҒ•зҙ„йҮ‘зөҗжЎҲ",
                    "ABANDONED": "е·Іж”ҫжЈ„", "REJECTED": "е…Ёж•ёе©үжӢ’",
                    "PENDING": "е°ҡжңӘе•ҹз”Ё"}.get(status, f"зӢҖж…Ӣ {status}")
    name = customer_name or (target["customer_name"] if "customer_name" in target.keys() else "жӯӨе®ўжҲ¶")
    reply_text(reply_token,
               f"вҡ пёҸ {name} {status_label}пјҢз„Ўжі•еҹ·иЎҢгҖҢ{action_label}гҖҚ\n"
               f"еҰӮйңҖж“ҚдҪңи«Ӣе…Ҳжү“гҖҢ@AI {name} йҮҚе•ҹгҖҚи®“е®ўжҲ¶еӣһеҲ°йҖІиЎҢдёӯ")
    return False


# еҸ°зҒЈиә«еҲҶиӯүеӯ—жҜҚе°ҚжҮүеҖјпјҲйҰ–зўјиҪүжҸӣпјү
_ID_LETTER_MAP = {
    'A': 10, 'B': 11, 'C': 12, 'D': 13, 'E': 14, 'F': 15, 'G': 16, 'H': 17,
    'I': 34, 'J': 18, 'K': 19, 'L': 20, 'M': 21, 'N': 22, 'O': 35, 'P': 23,
    'Q': 24, 'R': 25, 'S': 26, 'T': 27, 'U': 28, 'V': 29, 'W': 32, 'X': 30,
    'Y': 31, 'Z': 33,
}


def validate_tw_id_checksum(id_no: str) -> bool:
    """еҸ°зҒЈиә«еҲҶиӯүж Ўй©—дҪҚгҖӮеұ…з•ҷиӯүз¬¬ 2 зўјзӮәеӯ—жҜҚеүҮеғ…й©—ж јејҸгҖҒи·ійҒҺ checksumгҖӮ"""
    if not id_no or len(id_no) != 10:
        return False
    id_no = id_no.upper()
    first = id_no[0]
    if first not in _ID_LETTER_MAP:
        return False
    if not id_no[1].isdigit():
        return id_no[1] in _ID_LETTER_MAP and id_no[2:].isdigit()
    if not id_no[1:].isdigit():
        return False
    first_val = _ID_LETTER_MAP[first]
    digits = [first_val // 10, first_val % 10] + [int(d) for d in id_no[1:]]
    weights = [1, 9, 8, 7, 6, 5, 4, 3, 2, 1, 1]
    total = sum(d * w for d, w in zip(digits, weights))
    return total % 10 == 0


_PRIVATE_LOAN_SECTIONS = {"йҠҖиЎҢ", "йӣ¶еҚЎ", "з•¶иҲ–", "з•¶иҲ–е°ҲжЎҲ", "д»Јжӣё",
                           "е•Ҷе“ҒиІё", "й„үж°‘", "жҲҝең°", "ж–°й‘«", "ж…ўй»һд»ҳ", "еҲҶжңҹи¶Ј", "йҠҖи§’"}


def _is_private_loan_company(co: str) -> bool:
    """еҲӨж–·жҳҜеҗҰж°‘й–“ж–№жЎҲпјҲдёҚйңҖе‘ҠзҹҘйҮ‘йЎҚпјүпјҡзӣҙжҺҘеҗҚзЁұгҖҒaliasгҖҒsection йғҪеҲӨ"""
    if co in _PRIVATE_LOAN_SECTIONS:
        return True
    aliased = COMPANY_ALIAS.get(co)
    if aliased and aliased in _PRIVATE_LOAN_SECTIONS:
        return True
    return normalize_section(co) in _PRIVATE_LOAN_SECTIONS


