def _process_help_to_html(text: str) -> str:
    """жҠҠ _HELP_X еҺҹе§Ӣеӯ—дёІиҪүжҲҗ HTML зүҮж®өпјҲиҮӘеӢ•иҫЁиӯҳ @AI жҢҮд»ӨгҖҒзҜ„жң¬еҚҖеЎҠдёҰеҠ иӨҮиЈҪеҠҹиғҪпјүгҖӮ"""
    import html as _h
    import re as _re
    lines = text.split("\n")
    out = []
    i = 0
    n = len(lines)
    while i < n:
        line = lines[i]
        m_block = _re.match(r'^  (зҜ„жң¬|жү№ж¬ЎзөҗжЎҲ|жү№ж¬Ўе©үжӢ’)пјҡ\s*$', line)
        if m_block:
            out.append(_h.escape(line))
            block_lines = []
            j = i + 1
            while j < n and lines[j].startswith("    "):
                block_lines.append(lines[j][4:])
                j += 1
            copy_text = "\n".join(block_lines).rstrip()
            attr_copy = _h.escape(copy_text, quote=True).replace("\n", "&#10;")
            out.append(
                '    <span class="copy-block" data-copy="'
                + attr_copy
                + '" onclick="copyBlock(this)">'
                + _h.escape(copy_text)
                + '</span>'
            )
            i = j
            continue
        if "@AI" in line:
            esc = _h.escape(line)
            esc = _re.sub(
                r'(@AI[^\n]+)',
                r'<span class="copyable" onclick="copyInline(this)">\1</span>',
                esc,
            )
            out.append(esc)
        else:
            m_ex = _re.match(r'^(  дҫӢпјҡ)(.+)$', line)
            if m_ex:
                out.append(
                    _h.escape(m_ex.group(1))
                    + '<span class="copyable" onclick="copyInline(this)">'
                    + _h.escape(m_ex.group(2))
                    + '</span>'
                )
            else:
                out.append(_h.escape(line))
        i += 1
    return "\n".join(out)


def _render_guide_html() -> str:
    """еҫһ _HELP_* еӢ•ж…ӢжёІжҹ“жҢҮд»ӨйҖҹжҹҘй ҒпјҲе’Ң LINEгҖҢ@AI иӘӘжҳҺгҖҚе–®дёҖдҫҶжәҗпјүгҖӮ"""
    sections = [
        ("send", "рҹ“Ё йҖҒд»¶", _HELP_SEND),
        ("approval", "вң… ж ёеҮҶ / зөҗжЎҲ", _HELP_APPROVAL),
        ("undo", "рҹ”ҷ еҒҡйҢҜж•‘жҖҘ", _HELP_UNDO),
        ("tools", "рҹӣ  е…¶д»–е·Ҙе…·", _HELP_TOOLS),
        ("newcase", "рҹҶ• й–Ӣж–°е®ўжҲ¶", _HELP_NEWCASE),
        ("pairing", "рҹӨқ е°ҚдҝқжөҒзЁӢ", _HELP_PAIRING),
        ("symbols", "рҹ“қ з¬ҰиҷҹиӘӘжҳҺ", _HELP_SYMBOLS),
    ]
    parts = []
    for sid, title, txt in sections:
        body = txt.split("\n", 1)[1] if "\n" in txt else txt
        body = body.lstrip("\n")
        parts.append(
            f'<section id="{sid}" class="section">\n'
            f'  <h2>{title}</h2>\n'
            f'  <pre class="help-raw">{_process_help_to_html(body)}</pre>\n'
            f'</section>'
        )
    return _GUIDE_SHELL.replace("__SECTIONS__", "\n".join(parts))


def _split_company_amount(item: str):
    """жҠҠгҖҢиЈ•иһҚ100иҗ¬60жңҹгҖҚжҲ–гҖҢиЈ•иһҚ 100/60гҖҚзӯүеӯ—дёІжӢҶжҲҗ (е…¬еҸё, йҮ‘йЎҚ, жңҹж•ё)гҖӮ
    з”ЁйҖ”пјҡз…§жңғ/йҖҒ/иҪүжҢҮд»ӨеҲҮгҖҢ+гҖҚеҫҢпјҢжҜҸж®өеҸҜиғҪжңүгҖҢе…¬еҸё+йҮ‘йЎҚ+жңҹж•ёгҖҚй»ҸеңЁдёҖиө·гҖӮ
    еӣһеӮіпјҡ(company, amount, period) е…ЁйғЁзӮәеӯ—дёІпјҢз„ЎеүҮ ""
    """
    if not item:
        return ("", "", "")
    item = item.strip()
    # 1) ж•ҙж®өе°ұжҳҜеҗҲжі•е…¬еҸёеҗҚ вҶ’ зӣҙжҺҘеӣһ
    if item in COMPANY_ALIAS or item in COMPANY_LIST:
        return (item, "", "")
    # 1.5) PLAN_INFO е…§зҡ„ 3 ж®өејҸе®Ңж•ҙеҗҚзЁұпјҲдәһеӨӘж©ҹ25иҗ¬ / 21ж©ҹи»Ҡ25иҗ¬ зӯүпјү
    if item in PLAN_INFO:
        canonical = PLAN_INFO[item][0]
        return (canonical, "", "")
    # 2) еҫһеҗҲжі•е…¬еҸёеҗҚйӣҶеҗҲжүҫжңҖй•·еүҚз¶ҙпјҲйҒҝе…ҚгҖҢ21ж©ҹгҖҚиў«з•¶гҖҢ21гҖҚ+гҖҢж©ҹгҖҚеҲҮпјү
    all_names = sorted(set(list(COMPANY_LIST) + list(COMPANY_ALIAS.keys())),
                       key=len, reverse=True)
    for name in all_names:
        if item.startswith(name):
            rest = item[len(name):].strip()
            if not rest:
                return (name, "", "")
            m = re.match(r"^(\d+(?:\.\d+)?)\s*иҗ¬?\s*[/пјҸ]?\s*(\d+)?\s*жңҹ?\s*$", rest)
            if m:
                return (name, m.group(1), m.group(2) or "")
            return (name, "", "")
    # 3) жІ’е‘ҪдёӯеҗҲжі•е…¬еҸё вҶ’ еҳ—и©ҰгҖҢз¬¬дёҖеҖӢж•ёеӯ—еүҚгҖҚз•¶е…¬еҸё
    m = re.search(r"\d", item)
    if m and m.start() > 0:
        co = item[:m.start()].strip()
        rest = item[m.start():].strip()
        m2 = re.match(r"^(\d+(?:\.\d+)?)\s*иҗ¬?\s*[/пјҸ]?\s*(\d+)?\s*жңҹ?\s*$", rest)
        if m2:
            return (co, m2.group(1), m2.group(2) or "")
        return (co, "", "")
    return (item, "", "")


def _build_plan_info_hint(companies, manual_amount="", manual_period=""):
    """з”ўз”ҹгҖҢи«Ӣе‘ҠзҹҘе®ўжҲ¶йҖҒд»¶йҮ‘йЎҚгҖҚжҸҗзӨәеӯ—дёІгҖӮ
    иҰҸеүҮпјҡ
    - ж°‘й–“ж–№жЎҲпјҲйҠҖиЎҢ/з•¶иҲ–/йӣ¶еҚЎ/д»ЈжӣёзӯүпјүвҶ’ дёҚйңҖе‘ҠзҹҘйҮ‘йЎҚ
    - жңүжүӢеӢ•йҮ‘йЎҚ вҶ’ жүҖжңүе…¬еҸёйғҪеҘ—з”Ё
    - з„ЎжүӢеӢ•йҮ‘йЎҚ вҶ’ жҜҸе®¶жҹҘ PLAN_INFOпјӣз„ЎиіҮж–ҷжЁҷгҖҢйҮ‘йЎҚжңӘе®ҡгҖҚ
    - е…ЁйғЁйғҪжҳҜж°‘й–“ж–№жЎҲ вҶ’ дёҚйЎҜзӨәжҸҗйҶ’
    """
    if not companies:
        return ""
    lines = []
    amt_str = per_str = ""
    if manual_amount:
        amt_str = manual_amount if "иҗ¬" in manual_amount else f"{manual_amount}иҗ¬"
        per_str = f"/{manual_period}жңҹ" if manual_period else ""
    for co in companies:
        if _is_private_loan_company(co):
            continue  # ж°‘й–“ж–№жЎҲдёҚжҸҗйҮ‘йЎҚ
        if manual_amount:
            lines.append(f"  вҖў {co} {amt_str}{per_str}пјҲдҪ жҢҮе®ҡпјү")
        else:
            plan = PLAN_INFO.get(co)
            if plan and plan[1]:
                lines.append(f"  вҖў {co} {plan[1]}")
            else:
                lines.append(f"  вҖў {co} йҮ‘йЎҚжңӘе®ҡпјҢи«ӢжүӢеӢ•е‘ҠзҹҘ")
    if not lines:
        return ""  # е…ЁйғЁйғҪжҳҜж°‘й–“ж–№жЎҲпјҢдёҚйЎҜзӨә
    return "рҹ’¬ и«Ӣе‘ҠзҹҘе®ўжҲ¶йҖҒд»¶йҮ‘йЎҚпјҡ\n" + "\n".join(lines)


def _validate_amount_or_warn(amount_str: str, reply_token, name: str, label: str = "йҮ‘йЎҚ"):
    """йҮ‘йЎҚеҗҲзҗҶжҖ§пјҡ0 жҲ–иІ ж•ё blockпјӣ> 1000 иҗ¬иӯҰе‘Ҡ block и®“зўәиӘҚ"""
    if not amount_str:
        return True
    m = re.search(r"(\d+(?:\.\d+)?)", amount_str)
    if not m:
        return True
    amt = float(m.group(1))
    if amt <= 0:
        reply_text(reply_token, f"вқҢ {name}пјҡ{label} дёҚиғҪ = 0 жҲ–иІ ж•ёпјҲдҪ жү“зҡ„пјҡ{amount_str}пјүпјҢе·Ійҳ»ж“Ӣ")
        return False
    if amt > 1000:
        reply_text(reply_token,
                   f"вҡ пёҸ {name}пјҡ{label} и¶…йҒҺ 1000 иҗ¬пјҲдҪ жү“зҡ„пјҡ{amount_str}пјү\n"
                   f"еҰӮжһңзңҹзҡ„жҳҜйҖҷеҖӢж•ёеӯ—пјҢи«Ӣжү“пјҡ@AI {name} {label} {amount_str} зўәиӘҚ")
        return False
    return True


# йҮҚиӨҮиЁҠжҒҜеҒөжё¬пјҲ5 з§’е…§зӣёеҗҢиЁҠжҒҜиҰ–зӮәжүӢж»‘пјү
_recent_msgs: Dict[str, float] = {}
_DUP_WINDOW_SEC = 5


def is_duplicate_message(group_id: str, content: str) -> bool:
    """5 з§’е…§еҗҢзҫӨзө„ж”¶еҲ°дёҖжЁЎдёҖжЁЈиЁҠжҒҜ вҶ’ TrueпјҲcaller еҝҪз•Ҙпјү"""
    import time as _time
    now = _time.time()
    stale = [k for k, t in _recent_msgs.items() if t < now - _DUP_WINDOW_SEC]
    for k in stale:
        _recent_msgs.pop(k, None)
    key = f"{group_id}|{(content or '')[:200]}"
    if key in _recent_msgs:
        return True
    _recent_msgs[key] = now
    return False


def _refresh_company_status_after_docs(case_id: str, new_text: str):
    """зјәд»¶/е·ІиЈң жҢҮд»Өе®ҢжҲҗеҫҢгҖҒжҠҠ company_status иЈЎжңүгҖҢNA / зјә / еҫ…иЈңгҖҚзҡ„ stale section
    иҰҶеҜ«жҲҗ new_textгҖӮдҝқз•ҷе…¶д»–йҮҚиҰҒзӢҖж…ӢпјҲж ёеҮҶ / е©үжӢ’ / е·ІиЈңиіҮж–ҷ зӯүпјүдёҚеӢ•гҖӮ
    йҒҝе…Қ A зҫӨиҲҠиЁҠжҒҜж®ҳз•ҷгҖҒи®“ж—Ҙе ұеҸҚжҳ жңҖж–°еӢ•дҪңгҖӮ
    """
    try:
        conn = get_conn(); cur = conn.cursor()
        cur.execute("SELECT company_status FROM customers WHERE case_id=?", (case_id,))
        row = cur.fetchone()
        if not row:
            conn.close(); return
        cs_raw = row["company_status"] or "{}"
        try:
            cs = json.loads(cs_raw)
        except Exception:
            cs = {}
        if not cs:
            conn.close(); return
        # еҸӘеӢ•гҖҢstaleгҖҚзҡ„ sectionпјҲеҗ« NA / жңӘжҺҘ / зјә / еҫ…иЈң / и«ӢиЈңпјү
        stale_markers = ["NA", "жңӘжҺҘ", "зјә", "еҫ…иЈң", "и«ӢиЈң"]
        changed = False
        for sec in list(cs.keys()):
            old = cs[sec] or ""
            if any(m in old for m in stale_markers):
                cs[sec] = new_text
                changed = True
        if changed:
            cur.execute("UPDATE customers SET company_status=? WHERE case_id=?",
                        (json.dumps(cs, ensure_ascii=False), case_id))
            conn.commit()
        conn.close()
    except Exception:
        pass


def _resolve_push_target_for_docs(current_group_id: str, source_group_id: str) -> str:
    """зјәд»¶/е·ІиЈң жҢҮд»Өзҡ„жҺЁйҖҒзӣ®жЁҷжұәзӯ–пјҡ
    - жҘӯеӢҷзҫӨжү“ вҶ’ жҺЁе°ҚжҮүзҡ„ A зҫӨ
    - A зҫӨжү“ вҶ’ жҺЁе®ўжҲ¶жүҖеұ¬жҘӯеӢҷзҫӨ
    - е…¶д»–пјҲдёҚиӘҚиӯҳзҡ„зҫӨпјүвҶ’ дёҚжҺЁ
    """
    _a_group_ids = set(get_a_group_ids()) | {A_GROUP_ID}
    _sales_ids = set(get_sales_group_ids())
    if current_group_id in _sales_ids:
        return get_a_group_for_sales(current_group_id)
    if current_group_id in _a_group_ids:
        return source_group_id or ""
    return ""


def _resolve_target_strict(cmd: Dict, name: str, group_id: str, reply_token: str, action_label: str):
    """з ҙеЈһжҖ§жҢҮд»Өз”ЁпјҡеӨҡзӯҶеҗҢеҗҚи·іжҢүйҲ•и®“дҪҝз”ЁиҖ…йҒёгҖӮ
    - cmd иӢҘеҗ« _forced_case_idпјҲдҫҶиҮӘжҢүйҲ• callbackпјүпјҢзӣҙжҺҘеҸ–и©І case
    - жң¬зҫӨзө„ 1 зӯҶ вҶ’ еӣһи©ІзӯҶ
    - жң¬зҫӨзө„еӨҡзӯҶ вҶ’ и·іжҢүйҲ• EXEC_CMDпјҢеӣһеӮі None
    - жң¬зҫӨзө„ 0 зӯҶгҖҒе…¶д»–зҫӨзө„жңү вҶ’ еӣһжңҖиҝ‘жӣҙж–°йӮЈзӯҶпјҲйқһз ҙеЈһжҖ§е…¬еҸёжҹҘи©ўжғ…еўғпјү
    - е®Ңе…ЁжүҫдёҚеҲ° вҶ’ еӣһиҰҶйҢҜиӘӨ
    """
    forced = cmd.get("_forced_case_id") if cmd else None
    if forced:
        conn = get_conn(); cur = conn.cursor()
        cur.execute("SELECT * FROM customers WHERE case_id=?", (forced,))
        c = cur.fetchone(); conn.close()
        return c
    rows = find_active_by_name(name)
    same = [r for r in rows if r["source_group_id"] == group_id]
    if len(same) == 1:
        return same[0]
    if len(same) > 1:
        action_id = short_id()
        # еӯҳ cmd еүҜжң¬пјҲдёҚеҗ« _forced_case_idпјүеҲ° pending_action
        cmd_copy = {k: v for k, v in cmd.items() if k != "_forced_case_id"}
        save_pending_action(action_id, "select_case_for_cmd", {
            "cmd": cmd_copy, "group_id": group_id,
            "case_ids": [r["case_id"] for r in same], "label": action_label
        })
        items = []
        for r in same[:12]:
            id4 = (r["id_no"] or "")[-4:] or "з„Ў"
            co = r["current_company"] or r["company"] or "жңӘеЎ«"
            items.append(make_quick_reply_item(
                f"{co}-жң«4:{id4}", f"EXEC_CMD|{action_id}|{r['case_id']}"))
        items.append(make_quick_reply_item("еҸ–ж¶Ҳ", f"CANCEL_CMD|{action_id}"))
        reply_quick_reply(reply_token, f"вҡ пёҸ жң¬зҫӨзө„жңү {len(same)} дҪҚгҖҢ{name}гҖҚпјҢиҰҒ{action_label}е“ӘдёҖдҪҚпјҹ", items)
        return None
    if rows:
        return rows[0]
    reply_text(reply_token,
               f"вқҢ жүҫдёҚеҲ°е®ўжҲ¶пјҡ{name}\n"
               f"еҸҜиғҪеҺҹеӣ пјҡ\n"
               f"  вҖў е§“еҗҚжү“йҢҜпјҲ2-6 еҖӢдёӯж–Үеӯ—пјү\n"
               f"  вҖў е®ўжҲ¶йӮ„жІ’е»әз«Ӣ\n"
               f"  вҖў е®ўжҲ¶е·ІзөҗжЎҲ вҶ’ е…Ҳжү“гҖҢ@AI {name} йҮҚе•ҹгҖҚ")
    return None


def handle_special_command(cmd: Dict, reply_token: str, group_id: str):
    try:
        _handle_special_command_inner(cmd, reply_token, group_id)
    except Exception as e:
        import traceback
        traceback.print_exc()
        reply_text(reply_token, f"вқҢ зі»зөұиҷ•зҗҶеӨұж•—пјҢи«ӢжҲӘең–зөҰз®ЎзҗҶе“Ў\nйҢҜиӘӨд»Јзўјпјҡ{type(e).__name__}")


def _handle_special_command_inner(cmd: Dict, reply_token: str, group_id: str):
    t = cmd["type"]

    if t == "group_id":
        gname = get_group_name(group_id)
        reply_text(reply_token, f"рҹ“Ӣ жӯӨзҫӨзө„иіҮиЁҠ\nеҗҚзЁұпјҡ{gname}\nIDпјҡ{group_id}")
        return

    if t == "report":
        try:
            segs = generate_report_lines(group_id)
            # з”Ё reply дёҖж¬ЎйҖҒеӨҡеүҮпјҲдёҚж¶ҲиҖ— push й…ҚйЎҚпјүпјҢи¶…йҒҺ 5 еүҮжүҚ fallback push
            reply_text_multi(reply_token, segs[:5])
            for seg in segs[5:]:
                push_text(group_id, seg)
        except Exception as e:
            import traceback
            traceback.print_exc()
            reply_text(reply_token, f"вқҢ ж—Ҙе ұз”ўз”ҹеӨұж•—пјҢи«ӢжҲӘең–зөҰз®ЎзҗҶе“Ў\nйҢҜиӘӨд»Јзўјпјҡ{type(e).__name__}")
        return

    if t == "search":
        reply_text(reply_token, search_customer_info(cmd["name"], group_id))
        return

    if t == "format_hint":
        # йҖҡз”Ёж јејҸжҸҗзӨә handlerпјҲзөҰеёёиҰӢйҢҜиӘӨж јејҸеҸӢе–„жҸҗзӨәпјү
        hint = cmd.get("hint", "жҢҮд»Өж јејҸйҢҜпјҢи«ӢзңӢ @AI иӘӘжҳҺ")
        reply_text(reply_token, f"вҡ пёҸ {hint}")
        return

    if t == "bad_batch_format":
        action = cmd.get("action", "зөҗжЎҲ")
        reply_text(reply_token,
                   f"вҡ пёҸ жү№ж¬Ў{action}ж јејҸдёҚе°Қ\n"
                   f"иҰҒйҖҷжЁЈжү“пјҲжҜҸеҖӢе§“еҗҚжҸӣдёҖиЎҢпјүпјҡ\n"
                   f"  @AI жү№ж¬Ў{action}\n"
                   f"  й»ҺжҳҺ\n"
                   f"  зҺӢйҷҪжҳҺ")
        return

    if t == "batch_close":
        names = cmd["names"]
        results = []
        for name in names:
            rows = find_active_by_name(name)
            same = [r for r in rows if r["source_group_id"] == group_id]
            target = same[0] if same else (rows[0] if rows else None)
            if not target:
                results.append(f"  {name} вқҢ жүҫдёҚеҲ°е®ўжҲ¶")
            else:
                update_customer(target["case_id"], status="CLOSED",
                                text=f"{name} зөҗжЎҲ", from_group_id=group_id)
                push_text(target["source_group_id"], f"{name} зөҗжЎҲ")
                results.append(f"  {name} вң… е·ІзөҗжЎҲ")
        ok = sum(1 for r in results if "вң…" in r)
        fail = len(results) - ok
        header = f"рҹ“Ӣ жү№ж¬ЎзөҗжЎҲ {len(names)} зӯҶпјҲжҲҗеҠҹ {ok}"
        if fail:
            header += f"пјҢеӨұж•— {fail}"
        header += "пјү"
        reply_text(reply_token, header + "\n" + "\n".join(results))
        return

    if t == "batch_reject":
        names = cmd["names"]
        results = []
        for name in names:
            rows = find_active_by_name(name)
            same = [r for r in rows if r["source_group_id"] == group_id]
            target = same[0] if same else (rows[0] if rows else None)
            if not target:
                results.append(f"  {name} вқҢ жүҫдёҚеҲ°е®ўжҲ¶")
            else:
                route = target["route_plan"] or ""
                current = get_current_company(route)
                next_co = get_next_company(route)
                new_route = advance_route(route, "е©үжӢ’")
                update_customer(target["case_id"], route_plan=new_route,
                                current_company=next_co or current,
                                text=f"{name} {current} е©үжӢ’", from_group_id=group_id)
                push_text(target["source_group_id"], f"{name} {current} е©үжӢ’")
                if next_co:
                    results.append(f"  {name} вң… {current}е©үжӢ’ вҶ’ {next_co}")
                else:
                    results.append(f"  {name} вң… {current}е©үжӢ’пјҲз„ЎдёӢдёҖе®¶пјү")
        ok = sum(1 for r in results if "вң…" in r)
        fail = len(results) - ok
        header = f"рҹ“Ӣ жү№ж¬Ўе©үжӢ’ {len(names)} зӯҶпјҲжҲҗеҠҹ {ok}"
        if fail:
            header += f"пјҢеӨұж•— {fail}"
        header += "пјү"
        reply_text(reply_token, header + "\n" + "\n".join(results))
        return

    if t == "pending_disbursement":
        conn = get_conn(); cur = conn.cursor()
        if group_id == A_GROUP_ID:
            cur.execute("SELECT customer_name, current_company, company, approved_amount, route_plan, created_at, source_group_id FROM customers WHERE status='ACTIVE' AND report_section='еҫ…ж’Ҙж¬ҫ' ORDER BY created_at")
        else:
            cur.execute("SELECT customer_name, current_company, company, approved_amount, route_plan, created_at, source_group_id FROM customers WHERE status='ACTIVE' AND report_section='еҫ…ж’Ҙж¬ҫ' AND source_group_id=? ORDER BY created_at", (group_id,))
        rows = cur.fetchall(); conn.close()
        if not rows:
            reply_text(reply_token, "рҹ“Ӣ зӣ®еүҚжІ’жңүеҫ…ж’Ҙж¬ҫе®ўжҲ¶")
            return
        lines = [f"рҹ“Ӣ еҫ…ж’Ҙж¬ҫеҗҚе–®пјҲ{len(rows)} зӯҶпјү\n"]
        for r in rows:
            name = r["customer_name"]
            co = r["current_company"] or r["company"] or ""
            amt = r["approved_amount"] or ""
            created = (r["created_at"] or "")[:10]
            approved_list = get_all_approved(r["route_plan"] or "")
            if approved_list:
                parts = [(h.get("company") or "") + (h.get("amount") or "") for h in approved_list]
                amt_str = "/".join(parts)
            elif amt:
                amt_str = amt
            else:
                amt_str = "жңӘзҹҘйҮ‘йЎҚ"
            gname = get_group_name(r["source_group_id"]) if group_id == A_GROUP_ID else ""
            grp_tag = f"({gname})" if gname else ""
            lines.append(f"{created}-{name}{grp_tag}-ж ёеҮҶ{amt_str}")
        reply_text(reply_token, "\n".join(lines))
        return

    if t == "follow_up_list":
        # еҲ—еҮәи©ІзҫӨпјҲA зҫӨеүҮе…ЁйғЁпјүйңҖиҰҒи·ҹйҖІзҡ„е®ўжҲ¶
        # дёүйЎһпјҡ(1) зјәд»¶и¶…йҒҺ 3 еӨ© (2) еҫ…ж’Ҙж¬ҫи¶…йҒҺ 7 еӨ© (3) current еҚЎеҗҢе®¶и¶…йҒҺ 5 еӨ©
        # иө·з®—йҢЁй»һпјҡ
        # - зјәд»¶пјҡеҫһ case_logs жңҖеҫҢдёҖзӯҶгҖҢзјәд»¶пјҡгҖҚиЁҠжҒҜж—ҘпјҲ= йҖҡзҹҘж—Ҙпјүпјӣз„ЎзҙҖйҢ„ fallback updated_at
        # - еҫ…ж’Ҙж¬ҫпјҡеҫһ approved_atпјҲж ёеҮҶж—Ҙпјүпјӣз„Ў fallback created_at
        # - еҚЎй—ңпјҡеҫһ route_plan.history жңҖеҫҢдёҖзӯҶ dateпјҲ= current й–Ӣе§ӢйҖҒд»¶ж—Ҙпјүпјӣз„Ў fallback created_at
        from datetime import datetime as _dt
        _now_iso = now_iso()
        now_dt = _dt.fromisoformat(_now_iso.split(".")[0]) if "." in _now_iso else _dt.fromisoformat(_now_iso)
        conn = get_conn(); cur = conn.cursor()
        if group_id in (set(get_a_group_ids()) | {A_GROUP_ID}):
            cur.execute("SELECT * FROM customers WHERE status='ACTIVE'")
        else:
            cur.execute("SELECT * FROM customers WHERE status='ACTIVE' AND source_group_id=?", (group_id,))
        rows = cur.fetchall()

        DOC_DAYS = 3      # зјәд»¶и¶…йҒҺ N еӨ©иҰ–зӮәеҫ…и·ҹйҖІ
        DISB_DAYS = 7     # еҫ…ж’Ҙж¬ҫи¶…йҒҺ N еӨ©иҰ–зӮәеҫ…и·ҹйҖІ
        STUCK_DAYS = 5    # current е…¬еҸёжІ’жҺЁйҖІи¶…йҒҺ N еӨ©

        def _days_since(iso_str):
            if not iso_str:
                return 0
            try:
                t = iso_str.split(".")[0] if "." in iso_str else iso_str
                # еҸӘеҸ– YYYY-MM-DDTHH:MM:SS йғЁеҲҶ
                t = t[:19] if len(t) >= 19 else t
                d = _dt.fromisoformat(t)
                return (now_dt - d).days
            except Exception:
                return 0

        def _last_pending_set_date(case_id):
            """еӣһеӮі case_logs дёӯжңҖеҫҢдёҖзӯҶгҖҢзјәд»¶пјҡгҖҚиЁҠжҒҜзҡ„ created_atпјҢжІ’жңүеӣһ None"""
            try:
                cur.execute(
                    "SELECT created_at FROM case_logs WHERE case_id=? "
                    "AND message_text LIKE '%зјәд»¶пјҡ%' "
                    "ORDER BY created_at DESC LIMIT 1", (case_id,))
                row = cur.fetchone()
                return row["created_at"] if row else None
            except Exception:
                return None

        def _current_send_start_date(route_plan_str, fallback_created_at):
            """current й–Ӣе§ӢйҖҒд»¶зҡ„ж—Ҙжңҹпјҡroute_plan.history жңҖеҫҢдёҖзӯҶ dateпјӣз„ЎеүҮ created_at"""
            try:
                rd = parse_route_json(route_plan_str or "")
                hist = rd.get("history", []) or []
                if hist:
                    last = hist[-1]
                    d = last.get("date", "")
                    if d:
                        return d
            except Exception:
                pass
            return fallback_created_at

        doc_overdue = []     # зјәд»¶и¶…йҒҺ 3 еӨ©
        disb_overdue = []    # еҫ…ж’Ҙж¬ҫи¶…йҒҺ 7 еӨ©
        stuck_cases = []     # current еҚЎй—ңи¶…йҒҺ 5 еӨ©

        for r in rows:
            name = r["customer_name"]
            cur_co = r["current_company"] or r["company"] or ""

            # (1) зјәд»¶ вҶ’ еҫһ case_logs жүҫжңҖеҫҢдёҖж¬ЎгҖҢзјәд»¶пјҡгҖҚиЁӯе®ҡж—ҘпјҲйҖҡзҹҘж—Ҙпјү
            pend = (r["pending_docs"] or "").strip()
            if pend:
                anchor = _last_pending_set_date(r["case_id"]) or r["updated_at"]
                d1 = _days_since(anchor)
                if d1 >= DOC_DAYS:
                    docs_str = "/".join(x.strip() for x in pend.split(",") if x.strip())
                    doc_overdue.append((d1, name, cur_co, docs_str))

            # (2) еҫ…ж’Ҙж¬ҫ вҶ’ еҫһ approved_atпјҲж ёеҮҶж—Ҙпјү
            if (r["report_section"] or "") == "еҫ…ж’Ҙж¬ҫ":
                anchor = r["approved_at"] or r["created_at"]
                d2 = _days_since(anchor)
                if d2 >= DISB_DAYS:
                    amt = r["approved_amount"] or ""
                    disb_overdue.append((d2, name, cur_co, amt))

            # (3) еҚЎй—ң вҶ’ еҫһ current й–Ӣе§ӢйҖҒд»¶ж—ҘпјҲroute_plan.history жңҖеҫҢ dateпјү
            # еҗҢжҷӮиҰҒ updated_at д№ҹи¶…йҒҺ N еӨ©пјҲжІ’еңЁжӣҙж–°зӢҖж…ӢпјүжүҚз®—зңҹжӯЈеҚЎй—ң
            # йҒҝе…ҚгҖҢ14 еӨ©жІ’жҺЁйҖІдҪҶеӨ©еӨ©жңүиЈңд»¶еӣһе ұгҖҒA зҫӨжңүз…§жңғгҖҚзҡ„жҙ»жЎҲиў«иӘӨжЁҷ
            if cur_co and (r["report_section"] or "") not in ("еҫ…ж’Ҙж¬ҫ", "йҖҒд»¶") and not pend:
                anchor = _current_send_start_date(r["route_plan"], r["created_at"])
                d3 = _days_since(anchor)
                updated_d = _days_since(r["updated_at"])
                if d3 >= STUCK_DAYS and updated_d >= STUCK_DAYS:
                    stuck_cases.append((d3, name, cur_co))

        conn.close()

        # жҺ’еәҸпјҲеӨ©ж•ёеҖ’еәҸгҖҒжңҖд№…зҡ„жңҖдёҠпјү
        doc_overdue.sort(key=lambda x: -x[0])
        disb_overdue.sort(key=lambda x: -x[0])
        stuck_cases.sort(key=lambda x: -x[0])

        if not (doc_overdue or disb_overdue or stuck_cases):
            reply_text(reply_token, "вң… зӣ®еүҚжІ’жңүеҫ…и·ҹйҖІзҡ„е®ўжҲ¶")
            return

        gname = get_group_name(group_id) if group_id not in (set(get_a_group_ids()) | {A_GROUP_ID}) else "е…ЁйғЁ"
        lines = [f"вҡ пёҸ еҫ…и·ҹйҖІжё…е–®пјҲ{gname}пјү"]

        if doc_overdue:
            lines.append(f"\nрҹ“Ӣ зјәд»¶и¶…йҒҺ {DOC_DAYS} еӨ© ({len(doc_overdue)})")
            for days, name, co, docs in doc_overdue[:15]:
                co_short = normalize_section(co) or co
                lines.append(f"  вҖў {name}-{co_short} зјә{docs}пјҲе·І {days} еӨ©пјү")

        if disb_overdue:
            lines.append(f"\nрҹ’° еҫ…ж’Ҙж¬ҫи¶…йҒҺ {DISB_DAYS} еӨ© ({len(disb_overdue)})")
            for days, name, co, amt in disb_overdue[:15]:
                co_short = normalize_section(co) or co
                lines.append(f"  вҖў {name}-{co_short} ж ёеҮҶ{amt}пјҲе·І {days} еӨ©пјү")

        if stuck_cases:
            lines.append(f"\nрҹҗҢ еҚЎй—ңи¶…йҒҺ {STUCK_DAYS} еӨ© ({len(stuck_cases)})")
            for days, name, co in stuck_cases[:15]:
                co_short = normalize_section(co) or co
                lines.append(f"  вҖў {name}-{co_short}пјҲе·І {days} еӨ©жІ’еӢ•пјү")

        lines.append(f"\nрҹ’Ў иҷ•зҗҶпјҡиЈңд»¶иЈңе®Ңжү“гҖҢ@AI е§“еҗҚ е·ІиЈңXXгҖҚгҖҒеҚЎй—ңжү“гҖҢ@AI е§“еҗҚ иҪүдёӢдёҖе®¶гҖҚ")
        reply_text(reply_token, "\n".join(lines))
        return

    if t == "stats":
        conn = get_conn(); cur = conn.cursor()
        today = now_iso()[:10]
        month_start = today[:7] + "-01"
        is_a = group_id == A_GROUP_ID
        grp_filter = "" if is_a else " AND source_group_id=?"
        grp_param = [] if is_a else [group_id]
        # д»Ҡж—Ҙ
        cur.execute(f"SELECT COUNT(*) as c FROM customers WHERE date(created_at)=?{grp_filter}", [today] + grp_param)
        today_new = cur.fetchone()["c"]
        cur.execute(f"SELECT COUNT(*) as c FROM customers WHERE status IN ('CLOSED','PENALTY','ABANDONED','REJECTED') AND date(updated_at)=?{grp_filter}", [today] + grp_param)
        today_closed = cur.fetchone()["c"]
        # жң¬жңҲ
        cur.execute(f"SELECT COUNT(*) as c FROM customers WHERE created_at>=?{grp_filter}", [month_start] + grp_param)
        month_new = cur.fetchone()["c"]
        cur.execute(f"SELECT COUNT(*) as c FROM customers WHERE status IN ('CLOSED','PENALTY','ABANDONED','REJECTED') AND updated_at>=?{grp_filter}", [month_start] + grp_param)
        month_closed = cur.fetchone()["c"]
        # ж ёеҮҶ
        cur.execute(f"SELECT route_plan FROM customers WHERE status='ACTIVE' AND route_plan IS NOT NULL AND route_plan!=''{grp_filter}", grp_param)
        all_routes = cur.fetchall()
        today_approved = 0
        month_approved = 0
        for r in all_routes:
            approved = get_all_approved(r["route_plan"])
            if approved:
                for a in approved:
                    d = a.get("date", "")
                    if d == today:
                        today_approved += 1
                    if d >= month_start:
                        month_approved += 1
        # еҫ…ж’Ҙж¬ҫ
        cur.execute(f"SELECT COUNT(*) as c FROM customers WHERE status='ACTIVE' AND report_section='еҫ…ж’Ҙж¬ҫ'{grp_filter}", grp_param)
        total_pending = cur.fetchone()["c"]
        cur.execute(f"SELECT COUNT(*) as c FROM customers WHERE status='ACTIVE'{grp_filter}", grp_param)
        total_active = cur.fetchone()["c"]
        conn.close()
        msg = (f"рҹ“Ҡ зөұиЁҲиіҮиЁҠ\n\n"
               f"гҖҗд»Ҡж—Ҙ {today}гҖ‘\n"
               f"  ж–°йҖІд»¶пјҡ{today_new}\n"
               f"  ж ёеҮҶпјҡ{today_approved}\n"
               f"  зөҗжЎҲпјҡ{today_closed}\n\n"
               f"гҖҗжң¬жңҲгҖ‘\n"
               f"  ж–°йҖІд»¶пјҡ{month_new}\n"
               f"  ж ёеҮҶпјҡ{month_approved}\n"
               f"  зөҗжЎҲпјҡ{month_closed}\n\n"
               f"зӣ®еүҚжҙ»иәҚпјҡ{total_active}гҖҖеҫ…ж’Ҙж¬ҫпјҡ{total_pending}")
