@app.post("/admin/import-chao/confirm")
async def import_chao_confirm(request: Request):
    role = check_auth(request)
    if role != "admin":
        return HTMLResponse("з„Ўж¬Ҡйҷҗ", status_code=403)
    _base = os.path.dirname(os.path.abspath(__file__))
    jpath = os.path.join(_base, "chao_may_import.json")
    with open(jpath, encoding="utf-8") as f:
        data = json.load(f)
    SALES_GROUP_ID = CHAO_GROUP_ID
    with db_conn(commit=True) as conn:
        cur = conn.cursor()
        cur.execute("SELECT 1 FROM groups WHERE group_id=?", (SALES_GROUP_ID,))
        if not cur.fetchone():
            cur.execute(
                "INSERT INTO groups (group_id, group_name, group_type, is_active) VALUES (?, ?, ?, 1)",
                (SALES_GROUP_ID, CHAO_GROUP_NAME, "SALES_GROUP"),
            )
    created, transferred, skipped, failed = [], [], [], []
    for d in data:
        name = d["name"]
        id_no = (d.get("id_no") or "").strip()
        try:
            existing = find_active_by_id_no(id_no) if id_no else None
            # fallbackпјҡжІ’ id_no з”Ёе§“еҗҚжүҫи·ЁзҫӨеҗҢеҗҚ ACTIVEпјҲжҺ’йҷӨзӣ®жЁҷзҫӨжң¬иә«пјү
            if not existing:
                rows = find_active_by_name(name)
                non_target = [r for r in rows if r["source_group_id"] != SALES_GROUP_ID]
                if len(non_target) == 1:
                    existing = non_target[0]
                elif len(non_target) > 1:
                    failed.append(f"{name}пјҡи·ЁзҫӨжңү {len(non_target)} зӯҶеҗҢеҗҚгҖҒдәәе·ҘзўәиӘҚ")
                    continue
            if existing:
                old_gid = existing["source_group_id"]
                if old_gid == SALES_GROUP_ID:
                    skipped.append(f"{name}пјҲе·ІеңЁе„ӘеӢўзҫӨпјү")
                    continue
                old_gname = get_group_name(old_gid) or old_gid[:8]
                approved = (d.get("approved_amount") or "").strip()
                disb = (d.get("disb_date") or "").strip()
                report_sec = d.get("report_section", "") or ""
                concurrent_str = ",".join(d.get("concurrent", []))
                merge_kwargs = {"source_group_id": SALES_GROUP_ID,
                                "text": f"е·ІеҫһгҖҗ{old_gname}гҖ‘жҗ¬еҲ°гҖҗ{CHAO_GROUP_NAME}гҖ‘",
                                "from_group_id": SALES_GROUP_ID}
                if approved and not (existing["approved_amount"] or "").strip():
                    merge_kwargs["approved_amount"] = approved
                if disb and not (existing["disbursement_date"] or "").strip():
                    merge_kwargs["disbursement_date"] = disb
                if report_sec and not (existing["report_section"] or "").strip():
                    merge_kwargs["report_section"] = report_sec
                if concurrent_str and not (existing["concurrent_companies"] or "").strip():
                    merge_kwargs["concurrent_companies"] = concurrent_str
                co_import = d.get("current_company", "") or ""
                if co_import and not (existing["current_company"] or "").strip():
                    merge_kwargs["current_company"] = co_import
                update_customer(existing["case_id"], **merge_kwargs)
                transferred.append(f"{name}пјҲеҫһ {old_gname}пјү")
                continue
            co = d.get("current_company", "") or ""
            note = (d.get("report_note") or "").strip()
            text = note if note else (f"{name} {co}" if co else name)
            concurrent_str = ",".join(d.get("concurrent", []))
            report_sec = d.get("report_section", "") or ""
            approved = (d.get("approved_amount") or "").strip()
            disb = (d.get("disb_date") or "").strip()
            # approved_history: еӨҡе®¶ж ёеҮҶ schemaгҖҒе„Әе…Ҳз”ЁжӯӨ list е»ә route_plan history
            approved_history = d.get("approved_history") or []
            route_plan = ""
            if approved_history:
                history = []
                for h_entry in approved_history:
                    h_co = h_entry.get("company", "")
                    if not h_co: continue
                    h_dict = {"company": h_co, "amount": h_entry.get("amount", ""),
                              "status": h_entry.get("status", "ж ёеҮҶ")}
                    if h_entry.get("disbursed"):
                        h_dict["disbursed"] = h_entry["disbursed"]
                    history.append(h_dict)
                order = [co] + [h_entry.get("company", "") for h_entry in approved_history
                                if h_entry.get("company") and h_entry.get("company") != co]
                route_plan = make_route_json(order, 0, history)
            elif approved and co and report_sec == "еҫ…ж’Ҙж¬ҫ":
                history = []
                main_h = {"company": co, "amount": approved, "status": "еҫ…ж’Ҙж¬ҫ" if disb else "ж ёеҮҶ"}
                if disb:
                    main_h["disbursed"] = disb
                history.append(main_h)
                route_plan = make_route_json([co], 0, history)
            case_id = create_customer_record(
                name=name, id_no=id_no, company=co,
                source_group_id=SALES_GROUP_ID, text=text,
                route_plan=route_plan, current_company=co,
                report_section=report_sec,
            )
            build_date = (d.get("build_date") or "").strip()
            if build_date:
                try:
                    iso_date = build_date + "T00:00:00" if len(build_date) == 10 else build_date
                    with db_conn(commit=True) as conn:
                        cur = conn.cursor()
                        cur.execute("UPDATE customers SET created_at=? WHERE case_id=?", (iso_date, case_id))
                except Exception:
                    pass
            update_kwargs = {}
            if approved:
                update_kwargs["approved_amount"] = approved
            if disb:
                update_kwargs["disbursement_date"] = disb
            if concurrent_str:
                update_kwargs["concurrent_companies"] = concurrent_str
            if update_kwargs:
                update_customer(case_id, text=None, from_group_id=SALES_GROUP_ID, **update_kwargs)
            created.append(name)
        except Exception as e:
            failed.append(f"{name}пјҡ{e}")
    summary = f"""<div style="padding:40px;font-family:sans-serif">
      <h2>е„ӘеӢўеҢҜе…Ҙе®ҢжҲҗ</h2>
      <p>вң… ж–°е»әпјҡ{len(created)} зӯҶ вҖ” {', '.join(created[:30])}{'...' if len(created)>30 else ''}</p>
      <p>рҹ”Җ жҗ¬еҲ°е„ӘеӢўзҫӨпјҡ{len(transferred)} зӯҶ вҖ” {', '.join(transferred)}</p>
      <p>вҡ пёҸ и·ійҒҺпјҡ{len(skipped)} зӯҶ вҖ” {', '.join(skipped)}</p>
      <p>вқҢ еӨұж•—пјҡ{len(failed)} зӯҶ вҖ” {'; '.join(failed)}</p>
      <a href="/admin/groups">еӣһзҫӨзө„з®ЎзҗҶ</a> | <a href="/history">зңӢжӯ·еҸІ</a> | <a href="/report">зңӢж—Ҙе ұ</a>
    </div>"""
    return HTMLResponse(summary)


