@app.post("/admin/import-kuaile/confirm")
async def import_kuaile_confirm(request: Request):
    role = check_auth(request)
    if role != "admin":
        return HTMLResponse("з„Ўж¬Ҡйҷҗ", status_code=403)
    _base = os.path.dirname(os.path.abspath(__file__))
    jpath = os.path.join(_base, "kuaile_import.json")
    with open(jpath, encoding="utf-8") as f:
        data = json.load(f)
    SALES_GROUP_ID = KUAILE_GROUP_ID
    with db_conn(commit=True) as conn:
        cur = conn.cursor()
        cur.execute("SELECT 1 FROM groups WHERE group_id=?", (SALES_GROUP_ID,))
        if not cur.fetchone():
            cur.execute(
                "INSERT INTO groups (group_id, group_name, group_type, is_active) VALUES (?, ?, ?, 1)",
                (SALES_GROUP_ID, KUAILE_GROUP_NAME, "SALES_GROUP"),
            )
    created, transferred, skipped, failed = [], [], [], []
    for d in data:
        name = d["name"]
        id_no = (d.get("id_no") or "").strip()
        try:
            existing = find_active_by_id_no(id_no) if id_no else None
            if not existing:
                rows = find_active_by_name(name)
                non_target = [r for r in rows if r["source_group_id"] != SALES_GROUP_ID]
                if len(non_target) == 1:
                    existing = non_target[0]
                elif len(non_target) > 1:
                    failed.append(f"{name}пјҡи·ЁзҫӨжңү {len(non_target)} зӯҶеҗҢеҗҚгҖҒдәәе·ҘзўәиӘҚ")
                    continue
            if existing:
                old_gid = existing["source_group_id"]
                if old_gid == SALES_GROUP_ID:
                    skipped.append(f"{name}пјҲе·ІеңЁеҝ«жЁӮиІёзҫӨпјү")
                    continue
                old_gname = get_group_name(old_gid) or old_gid[:8]
                approved = (d.get("approved_amount") or "").strip()
                disb = (d.get("disb_date") or "").strip()
                report_sec = d.get("report_section", "") or ""
                concurrent_str = ",".join(d.get("concurrent", []))
                merge_kwargs = {"source_group_id": SALES_GROUP_ID,
                                "text": f"е·ІеҫһгҖҗ{old_gname}гҖ‘жҗ¬еҲ°гҖҗ{KUAILE_GROUP_NAME}гҖ‘",
                                "from_group_id": SALES_GROUP_ID}
                if approved and not (existing["approved_amount"] or "").strip():
                    merge_kwargs["approved_amount"] = approved
                if disb and not (existing["disbursement_date"] or "").strip():
                    merge_kwargs["disbursement_date"] = disb
                if report_sec and not (existing["report_section"] or "").strip():
                    merge_kwargs["report_section"] = report_sec
                if concurrent_str and not (existing["concurrent_companies"] or "").strip():
                    merge_kwargs["concurrent_companies"] = concurrent_str
                co_import = d.get("current_company", "") or ""
                if co_import and not (existing["current_company"] or "").strip():
                    merge_kwargs["current_company"] = co_import
                update_customer(existing["case_id"], **merge_kwargs)
                transferred.append(f"{name}пјҲеҫһ {old_gname}пјү")
                continue
            co = d.get("current_company", "") or ""
            note = (d.get("report_note") or "").strip()
            text = note if note else (f"{name} {co}" if co else name)
            concurrent_str = ",".join(d.get("concurrent", []))
            report_sec = d.get("report_section", "") or ""
            approved = (d.get("approved_amount") or "").strip()
            disb = (d.get("disb_date") or "").strip()
            route_plan = ""
            if approved and co and report_sec == "еҫ…ж’Ҙж¬ҫ":
                history = []
                main_h = {"company": co, "amount": approved, "status": "еҫ…ж’Ҙж¬ҫ" if disb else "ж ёеҮҶ"}
                if disb:
                    main_h["disbursed"] = disb
                history.append(main_h)
                order = [co] + d.get("concurrent", [])
                route_plan = make_route_json(order, 0, history)
            case_id = create_customer_record(
                name=name, id_no=id_no, company=co,
                source_group_id=SALES_GROUP_ID, text=text,
                route_plan=route_plan, current_company=co,
                report_section=report_sec,
            )
            build_date = (d.get("build_date") or "").strip()
            if build_date:
                try:
                    iso_date = build_date + "T00:00:00" if len(build_date) == 10 else build_date
                    with db_conn(commit=True) as conn:
                        _c = conn.cursor()
                        _c.execute("UPDATE customers SET created_at=? WHERE case_id=?", (iso_date, case_id))
                except Exception:
                    pass
            update_kwargs = {}
            if approved:
                update_kwargs["approved_amount"] = approved
            if disb:
                update_kwargs["disbursement_date"] = disb
            if concurrent_str:
                update_kwargs["concurrent_companies"] = concurrent_str
            pending_docs = (d.get("pending_docs") or "").strip()
            if pending_docs:
                update_kwargs["pending_docs"] = pending_docs
            cnotes = d.get("company_notes") or {}
            if cnotes:
                cs_dict = {normalize_section(k): v for k, v in cnotes.items()}
                update_kwargs["company_status"] = json.dumps(cs_dict, ensure_ascii=False)
            if update_kwargs:
                update_customer(case_id, text=None, from_group_id=SALES_GROUP_ID, **update_kwargs)
            created.append(name)
        except Exception as e:
            failed.append(f"{name}пјҡ{e}")
    summary = f"""<div style="padding:40px;font-family:sans-serif">
      <h2>еҝ«жЁӮиІёеҢҜе…Ҙе®ҢжҲҗ</h2>
      <p>вң… ж–°е»әпјҡ{len(created)} зӯҶ вҖ” {', '.join(created[:30])}{'...' if len(created)>30 else ''}</p>
      <p>рҹ”Җ жҗ¬еҲ°еҝ«жЁӮиІёзҫӨпјҡ{len(transferred)} зӯҶ вҖ” {', '.join(transferred)}</p>
      <p>вҡ пёҸ и·ійҒҺпјҡ{len(skipped)} зӯҶ вҖ” {', '.join(skipped)}</p>
      <p>вқҢ еӨұж•—пјҡ{len(failed)} зӯҶ вҖ” {'; '.join(failed)}</p>
      <a href="/admin/groups">еӣһзҫӨзө„з®ЎзҗҶ</a> | <a href="/history">зңӢжӯ·еҸІ</a> | <a href="/report">зңӢж—Ҙе ұ</a>
    </div>"""
    return HTMLResponse(summary)


@app.post("/admin/cleanup-company-paren", response_class=HTMLResponse)
def cleanup_company_paren(request: Request):
    """дёҖж¬ЎжҖ§жё…жҺү current_company иЈЎиӘӨеӯҳзҡ„гҖҢ(...)гҖҚжӢ¬иҷҹе…§е®№пјҲadmin йҷҗе®ҡпјүгҖӮ
    е°ҚйҪҠиҲҠиіҮж–ҷгҖҒйҒҝе…Қж—Ҙе ұ section жЁҷйЎҢеё¶ (зјәжүӢж©ҹеҗҲз…§) зӯү"""
    role = check_auth(request)
    if role != "admin":
        return HTMLResponse("з„Ўж¬Ҡйҷҗ", status_code=403)
    fixed = []
    with db_conn(commit=True) as conn:
        cur = conn.cursor()
        cur.execute("SELECT case_id, customer_name, current_company, source_group_id FROM customers WHERE current_company LIKE '% (%'")
        rows = cur.fetchall()
        for r in rows:
            old = r["current_company"] or ""
            new = re.sub(r"\s*\([^)]*\)\s*", "", old).strip()
            if new != old:
                cur.execute("UPDATE customers SET current_company=? WHERE case_id=?", (new, r["case_id"]))
                fixed.append(f"{r['customer_name']}: {old} вҶ’ {new}")
    body = "<br>".join(h(x) for x in fixed) or "пјҲз„ЎйңҖдҝ®жӯЈпјү"
    return HTMLResponse(f"""<!DOCTYPE html><html><head>{PAGE_CSS}</head><body>
    {make_topnav(role, "admin")}
    <div class="page"><h2>вң… жё…йҷӨ {len(fixed)} зӯҶз•°еёё current_company</h2>
    <div style="background:#fff;padding:12px;border-radius:6px;font-size:13px">{body}</div>
    <p><a href="/report">зңӢж—Ҙе ұ</a></p></div></body></html>""")


@app.get("/pdfs/{token}/{filename}")
def download_pdf(token: str, filename: str):
    """дёӢијүж”¶д»¶ PDFпјҲ24h е…§жңүж•ҲгҖҒtoken йҳІжӯўиў«зҢңз¶ІеқҖпјү"""
    # йҳІ path traversal
    safe_token = re.sub(r"[^A-Za-z0-9_\-]", "", token)[:30]
    safe_fn = re.sub(r"[^\wгҗҖ-йҝҝпӨҖ-п«ҝ\.\-_]", "_", filename)[:80]
    if not safe_token or not safe_fn:
        return HTMLResponse("з„Ўж•ҲйҖЈзөҗ", status_code=404)
    full_path = os.path.join(PDF_TMP_DIR, f"{safe_token}_{safe_fn}")
    if not os.path.isfile(full_path):
        return HTMLResponse("жӘ”жЎҲе·ІйҒҺжңҹжҲ–дёҚеӯҳеңЁпјҲ24 е°ҸжҷӮеӨұж•Ҳпјү", status_code=404)
    # й ҶжүӢжё…йҒҺжңҹжӘ”
    _cleanup_expired_pdfs()
    return FileResponse(full_path, filename=safe_fn, media_type="application/pdf")


