@app.post("/admin/restore-from-report", response_class=HTMLResponse)
async def restore_from_report_post(request: Request):
    role = check_auth(request)
    if role != "admin":
        return HTMLResponse("з„Ўж¬Ҡйҷҗ", status_code=403)
    form = await request.form()
    group_id = (form.get("group_id") or "").strip()
    text = (form.get("report_text") or "").strip()
    is_dry = (form.get("dry") or "1") != "0"
    if not group_id or not text:
        return HTMLResponse("зјә group_id жҲ– report_text", status_code=400)

    # и§Јжһҗж—Ҙе ұ
    # ж”ҜжҸҙзҡ„ section жЁҷйЎҢпјҲдёҖиЎҢе–®зҚЁпјү
    SECTION_NAMES = set(REPORT_SECTION_1 + REPORT_SECTION_2 + REPORT_SECTION_3 + ["йҖҒд»¶", "еҫ…ж’Ҙж¬ҫ", "21жұҪи»Ҡ"])
    parsed = []  # [(name, current_co, status_note, approved_amt, disb_date, report_section)]
    cur_section = ""
    debug_unparsed = []  # ж”¶йӣҶеүҚ 8 иЎҢгҖҢжҮүи©ІжҳҜе®ўжҲ¶дҪҶжІ’иў«и§ЈжһҗгҖҚзҡ„иЎҢпјҲзөҰдҪҝз”ЁиҖ…зңӢпјү
    debug_ignored = []  # ж”¶йӣҶ 8 иЎҢйқһе®ўжҲ¶/йқһ section зҡ„иЎҢпјҲdivider/headerпјү
    # section names жҺ’еәҸпјҡй•·зҡ„е…ҲжҜ”гҖҒйҒҝе…ҚгҖҢ21гҖҚжҗ¶еҲ°гҖҢ21жұҪи»ҠгҖҚеүҚйқў
    SECTION_NAMES_SORTED = sorted(SECTION_NAMES, key=lambda x: -len(x))
    for raw_line in text.splitlines():
        # з§»йҷӨ BOMгҖҒйӣ¶еҜ¬еӯ—гҖҒйҰ–е°ҫз©әзҷҪ
        line = raw_line.replace("п»ҝ", "").replace("вҖӢ", "").strip()
        if not line:
            continue
        # жҠҠеҲҶйҡ”з·ҡеүқжҺүпјҲв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ / вҖ”вҖ”вҖ”вҖ”вҖ”пјүеҫҢеҶҚеҲӨ section
        # дҫӢпјҡгҖҢв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ йӣ¶еҚЎгҖҚгҖҢв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ еҫ…ж’Ҙж¬ҫгҖҚжҮүи©ІиӘҚеҫ—жҳҜ zh еҚЎ / еҫ…ж’Ҙж¬ҫ
        line_stripped = re.sub(r"^[в”ҒвҖ”\-=\s]+", "", line).strip()
        line_stripped = re.sub(r"[в”ҒвҖ”\-=]+\s*$", "", line_stripped).strip()
        # еҚҖеЎҠжЁҷйЎҢпјҲдёҖиЎҢдёҖеҖӢ section еҗҚпјү
        matched_section = False
        # ж•ҙиЎҢе°ұжҳҜ section
        if line_stripped in SECTION_NAMES:
            cur_section = line_stripped
            matched_section = True
        else:
            # е®№йҢҜпјҡеүқжҺү emoji/еҲҶйҡ”з·ҡеҫҢ startswith
            for s in SECTION_NAMES_SORTED:
                if line_stripped == s or line_stripped.startswith(s + " ") or line_stripped == "рҹҶ•" + s or line_stripped == s + "еҚҖ":
                    cur_section = s
                    matched_section = True
                    break
        if matched_section:
            continue
        # е®ўжҲ¶иЎҢпјҡй–Ӣй ӯеҗ«ж—Ҙжңҹ MM/DD- жҲ– рҹҶ•MM/DD-пјҲе§“еҗҚ 2-8 еӯ—гҖҒе®№йҢҜ emojiпјү
        # ж”ҜжҸҙе…©зЁ®еҲҶйҡ”пјҡname- жҲ– name( пјҲйҖҒд»¶еҚҖеёёиҰӢгҖҢй»ғж–Үй§ҝ(зўәиӘҚиіҮж–ҷ)гҖҚжІ’жңү dashпјү
        m = re.match(r"^[рҹҶ•рҹ’°вҸ°\s]*(\d{1,2}/\d{1,2})-([гҗҖ-йҝҝпӨҖ-п«ҝ]{2,8})(?P<sep>[-\(])(?P<rest>.*)$", line)
        if not m:
            # debug з”ЁпјҡзңӢ parser жјҸдәҶд»Җйәј
            if re.search(r"\d{1,2}/\d{1,2}", line) and "-" in line and len(debug_unparsed) < 8:
                debug_unparsed.append(line[:80])
            elif (len(debug_ignored) < 8 and not line.startswith("рҹ“Ҡ")
                  and not line.startswith("в”Ғ") and not line.startswith("вҖ”")
                  and not line.startswith("вҸ°") and not line.startswith("(")):
                debug_ignored.append(line[:50])
            continue
        date_str = m.group(1)
        name = m.group(2)
        rest = m.group("rest").strip()
        # иӢҘжҳҜ name(...) ж јејҸпјҲйҖҒд»¶еҚҖзҡ„гҖҢзўәиӘҚиіҮж–ҷгҖҚеӮҷиЁ»йЎһпјүвҶ’ жҠҠй–Ӣй ӯжӢ¬иҷҹиЈңеӣһеҺ»
        if m.group("sep") == "(":
            rest = "(" + rest

        # еҫ…ж’Ҙж¬ҫеҚҖеЎҠпјҡи§ЈжһҗеӨҡзЁ®ж јејҸ
        # A. ж ёеҮҶ{co1} {amt1}иҗ¬(ж’Ҙж¬ҫM/D)/{co2} {amt2}иҗ¬(е°ҚдҝқM/D)   вҶҗ dual-approve
        # B. ж ёеҮҶ{co} {amt}иҗ¬(ж’Ҙж¬ҫM/D)                              вҶҗ е…¬еҸёеңЁ гҖҢж ёеҮҶгҖҚ еҫҢ
        # C. {co}-ж ёеҮҶ{amt}иҗ¬                                       вҶҗ е…¬еҸёеңЁ гҖҢ-ж ёеҮҶгҖҚ еүҚгҖҒз„Ў paren
        # D. {co}-ж ёеҮҶ{amt}иҗ¬(M/D) / {co}-ж ёеҮҶ{amt}иҗ¬(ж’Ҙж¬ҫM/D)      вҶҗ е…¬еҸёеңЁеүҚ + paren
        # E. иҪү{co}-ж ёеҮҶ{amt}иҗ¬(...)                                вҶҗ иҪүе…¬еҸёеүҚз¶ҙгҖҒйңҖеүқ
        if cur_section == "еҫ…ж’Ҙж¬ҫ":
            approvals = []  # [(co, amt, disb_date)]

            # е…Ҳи©Ұ C/D/Eпјҡе…¬еҸёеңЁгҖҢж ёеҮҶгҖҚеүҚйқў
            m_pre = re.match(r"^(?:иҪү)?([гҗҖ-йҝҝпӨҖ-п«ҝ0-9]+?)\s*-?\s*ж ёеҮҶ\s*(\d+(?:\.\d+)?)иҗ¬\s*(?:\(([^)]*)\))?", rest)
            if m_pre:
                co_pre = m_pre.group(1).strip().lstrip("иҪү").strip()
                amt_pre = m_pre.group(2) + "иҗ¬"
                paren_pre = m_pre.group(3) or ""
                disb_pre = ""
                # paren еҸҜиғҪжҳҜгҖҢж’Ҙж¬ҫ4/27гҖҚгҖҢ4/27гҖҚгҖҢе№ёзҰҸиІёгҖҚгҖҢе°Қдҝқ4/27гҖҚ
                dm = re.search(r"(\d{1,2}/\d{1,2})", paren_pre)
                if dm:
                    disb_pre = dm.group(1)
                approvals.append((co_pre, amt_pre, disb_pre))
            else:
                # A/BпјҡгҖҢж ёеҮҶ{co} {amt}иҗ¬(...)гҖҚж јејҸ
                am_full = re.search(r"ж ёеҮҶ\s*(.+)$", rest)
                if am_full:
                    tail = am_full.group(1)
                    for sm in re.finditer(r"([гҗҖ-йҝҝпӨҖ-п«ҝ0-9]+?)\s*(\d+(?:\.\d+)?)иҗ¬\s*\(([^)]+)\)", tail):
                        co_s = sm.group(1).strip().lstrip("/").strip()
                        amt_s = sm.group(2) + "иҗ¬"
                        paren = sm.group(3)
                        disb_s = ""
                        dm = re.search(r"ж’Ҙж¬ҫ(\d{1,2}/\d{1,2})", paren) or re.search(r"(\d{1,2}/\d{1,2})", paren)
                        if dm:
                            disb_s = dm.group(1)
                        approvals.append((co_s, amt_s, disb_s))
                    if not approvals:
                        sm2 = re.match(r"([гҗҖ-йҝҝпӨҖ-п«ҝ0-9]+?)\s*(\d+(?:\.\d+)?)иҗ¬", tail)
                        if sm2:
                            approvals.append((sm2.group(1).strip(), sm2.group(2) + "иҗ¬", ""))
            if approvals:
                co, amt, disb = approvals[0]
                extra_approved = []
                for ec, ea, ed in approvals[1:]:
                    extra_approved.append({"company": ec, "amount": ea, "disb_date": ed})
                parsed.append({
                    "name": name, "current_company": co, "status_note": "",
                    "approved_amount": amt, "disb_date": disb,
                    "report_section": "еҫ…ж’Ҙж¬ҫ", "build_date": date_str,
                    "extra_approved": extra_approved,
                })
                continue

        # дёҖиҲ¬ section иЎҢпјҡrest = "е…¬еҸё" жҲ– "е…¬еҸё-зӢҖж…Ӣ" жҲ– "е…¬еҸё (зјәX)" жҲ– "е…¬еҸёA/е…¬еҸёB"пјҲйҖҒд»¶еҗҢйҖҒпјү
        # е…ҲжҠҠжӢ¬иҷҹ(зјәX)жҠҪеҮәдҫҶгҖҒдёҚз®—е…¬еҸёд№ҹдёҚз®—зӢҖж…Ӣ
        pending_inline = ""
        rest_no_paren = re.sub(r"\s*\([^)]*\)\s*", "", rest).strip()
        pm = re.search(r"\(зјә([^)]+)\)", rest)
        if pm:
            pending_inline = pm.group(1).strip()
        # жӢҶ "-" еҸ–з¬¬дёҖж®өз•¶е…¬еҸёгҖҒеҫҢйқўз•¶зӢҖж…ӢпјҲз”Ёжё…жҺүжӢ¬иҷҹзҡ„еӯ—дёІпјү
        co_part = rest_no_paren
        status_note = ""
        if "-" in rest_no_paren:
            parts = rest_no_paren.split("-", 1)
            co_part = parts[0].strip()
            status_note = parts[1].strip()
        # е…¬еҸёеүҚеҺ»жҺүз©әзҷҪгҖҒдёҚиҰҒеҗ« "(...)" ж®ҳз•ҷ
        # еҗҢйҖҒж јејҸгҖҢз¬¬дёҖ/е–¬зҫҺгҖҚвҶ’ дё»е…¬еҸё=з¬¬дёҖгҖҒconcurrent=[е–¬зҫҺ]
        sub_concurrent = []
        co = ""
        if co_part:
            cos = [c.strip() for c in co_part.split("/") if c.strip()]
            # еүқгҖҢиҪүгҖҚеүҚз¶ҙпјҲгҖҢиҪүдәһеӨӘгҖҚвҶ’гҖҢдәһеӨӘгҖҚгҖҒгҖҢиҪү21гҖҚвҶ’гҖҢ21гҖҚпјү
            cos = [c[1:].strip() if c.startswith("иҪү") else c for c in cos]
            cos = [c for c in cos if c]  # еүқе®Ңз©әеӯ—дёІеҺ»жҺү
            if cos:
                co = cos[0]
                sub_concurrent = cos[1:]
        # жҺ’йҷӨгҖҢеҫ…ж’Ҙж¬ҫгҖҚгҖҢйҖҒд»¶гҖҚйҖҷзЁ®зү№ж®ҠеҚҖеЎҠеҗҚз•¶дҪңе…¬еҸё
        if cur_section in ("йҖҒд»¶",) and not co:
            co = ""
        parsed.append({
            "name": name, "current_company": co, "status_note": status_note,
            "approved_amount": "", "disb_date": "",
            "report_section": cur_section if cur_section in ("еҫ…ж’Ҙж¬ҫ", "йҖҒд»¶") else "",
            "build_date": date_str, "pending_docs": pending_inline,
            "sub_concurrent": sub_concurrent,
        })

    # жүҫжӯӨзҫӨжүҖжңү ACTIVE е®ўжҲ¶гҖҒжҢүе§“еҗҚ map
    conn = get_conn(); cur = conn.cursor()
    cur.execute("SELECT * FROM customers WHERE source_group_id=? AND status='ACTIVE'", (group_id,))
    customers_in_group = cur.fetchall(); conn.close()
    name_to_case = {}
    for c in customers_in_group:
        name_to_case.setdefault(c["customer_name"], []).append(dict(c))

    # ж•ҙзҗҶпјҡеҗҢдёҖе®ўжҲ¶еҸҜиғҪеңЁеӨҡеҖӢ section еҮәзҸҫпјҲеҗҢйҖҒпјүвҶ’ з¬¬дёҖеҖӢз•¶ currentгҖҒе…¶д»–з•¶ concurrent
    by_name = {}
    for p in parsed:
        nm = p["name"]
        if nm not in by_name:
            by_name[nm] = {
                "current_company": p["current_company"],
                "concurrent": [],
                "status_note": p["status_note"],
                "approved_amount": p["approved_amount"],
                "disb_date": p["disb_date"],
                "report_section": p["report_section"],
                "company_notes": {},
                "pending_docs": p.get("pending_docs", ""),
                "extra_approved": p.get("extra_approved", []),
            }
            if p["status_note"] and p["current_company"]:
                by_name[nm]["company_notes"][p["current_company"]] = p["status_note"]
            # еҗҢиЎҢж јејҸгҖҢз¬¬дёҖ/е–¬зҫҺгҖҚвҶ’ еҫҢйқўз•¶ concurrent
            for sc in p.get("sub_concurrent", []):
                if sc and sc != p["current_company"] and sc not in by_name[nm]["concurrent"]:
                    by_name[nm]["concurrent"].append(sc)
            # еҫ…ж’Ҙж¬ҫ dual-approveпјҡз¬¬дәҢе®¶д№ҹеҠ е…Ҙ concurrent
            for ea in p.get("extra_approved", []):
                if ea.get("company") and ea["company"] != p["current_company"]:
                    by_name[nm]["concurrent"].append(ea["company"])
        else:
            # зҙҜз©Қ pending_docs
            if p.get("pending_docs") and not by_name[nm]["pending_docs"]:
                by_name[nm]["pending_docs"] = p["pending_docs"]
            # еҫҢзәҢеҮәзҸҫзҡ„ вҶ’ еҠ еҲ° concurrent + company_notes
            if p["report_section"] == "еҫ…ж’Ҙж¬ҫ":
                # еҫ…ж’Ҙж¬ҫе„Әе…Ҳз•¶ main current
                old_co = by_name[nm]["current_company"]
                if old_co and old_co != p["current_company"]:
                    by_name[nm]["concurrent"].append(old_co)
                by_name[nm]["current_company"] = p["current_company"]
                by_name[nm]["approved_amount"] = p["approved_amount"]
                by_name[nm]["disb_date"] = p["disb_date"]
                by_name[nm]["report_section"] = "еҫ…ж’Ҙж¬ҫ"
                by_name[nm]["extra_approved"] = p.get("extra_approved", [])
                for ea in p.get("extra_approved", []):
                    if ea.get("company") and ea["company"] != p["current_company"]:
                        if ea["company"] not in by_name[nm]["concurrent"]:
                            by_name[nm]["concurrent"].append(ea["company"])
            else:
                if p["current_company"] and p["current_company"] != by_name[nm]["current_company"]:
                    if p["current_company"] not in by_name[nm]["concurrent"]:
                        by_name[nm]["concurrent"].append(p["current_company"])
            if p["status_note"] and p["current_company"]:
                by_name[nm]["company_notes"][p["current_company"]] = p["status_note"]

    # е»әиЎЁ + еҹ·иЎҢ
    rows_html = ""
    updated = 0
    not_found = []
    for nm, data in by_name.items():
        recs = name_to_case.get(nm)
        if not recs:
            not_found.append(nm)
            continue
        target = recs[0]  # еҸ–з¬¬дёҖзӯҶ
        cco = data["current_company"]
        conc = ",".join(data["concurrent"]) if data["concurrent"] else ""
        amt = data["approved_amount"]
        disb = data["disb_date"]
        sec = data["report_section"]
        notes = data["company_notes"]
        notes_json = json.dumps(notes, ensure_ascii=False) if notes else "{}"
        last_update_text = data["status_note"] or (f"{nm} {cco}" if cco else nm)
        rows_html += f'''<tr>
          <td style="padding:6px 10px;font-weight:600">{h(nm)}</td>
          <td style="padding:6px 10px">{h(cco or "-")}</td>
          <td style="padding:6px 10px">{h(conc or "-")}</td>
          <td style="padding:6px 10px">{h(amt or "-")}</td>
          <td style="padding:6px 10px">{h(disb or "-")}</td>
          <td style="padding:6px 10px">{h(sec or "-")}</td>
          <td style="padding:6px 10px;font-size:11px">{h(data["status_note"][:40] or "-")}</td>
        </tr>'''
        updated += 1
        if not is_dry:
            # еҫ…ж’Ҙж¬ҫ dual-approve вҶ’ йҮҚе»ә route_plan historyпјҲйҖҷжЁЈж—Ҙе ұз”Ё get_all_approved иғҪжӯЈзўәйЎҜзӨәе…©е®¶пјү
            new_route_plan = target.get("route_plan") or ""
            extras = data.get("extra_approved") or []
            if sec == "еҫ…ж’Ҙж¬ҫ" and (extras or amt):
                history = []
                # current е…¬еҸёд№ҹз®—дёҖзӯҶж ёеҮҶ
                if cco and amt:
                    history.append({"company": cco, "status": "ж ёеҮҶ", "amount": amt, "disbursed": disb})
                for ea in extras:
                    history.append({
                        "company": ea.get("company", ""),
                        "status": "ж ёеҮҶ",
                        "amount": ea.get("amount", ""),
                        "disbursed": ea.get("disb_date", ""),
                    })
                # дҝқз•ҷеҺҹ order/current_indexгҖҒеҸӘиҰҶеҜ« history
                try:
                    rp = parse_route_json(new_route_plan)
                except Exception:
                    rp = {"order": [], "current_index": 0, "history": []}
                rp["history"] = history
                new_route_plan = json.dumps(rp, ensure_ascii=False)
            with db_conn(commit=True) as conn:
                cur = conn.cursor()
                cur.execute("""UPDATE customers SET
                    current_company=?, concurrent_companies=?, approved_amount=?,
                    disbursement_date=?, report_section=?, company_status=?,
                    last_update=?, pending_docs=?, route_plan=?, updated_at=?
                    WHERE case_id=?""",
                    (cco, conc, amt, disb, sec, notes_json,
                     last_update_text, data.get("pending_docs", ""),
                     new_route_plan, now_iso(), target["case_id"]))

    nf_html = ""
    if not_found:
        nf_html = f'<p style="color:#b91c1c;margin-top:14px">вҡ пёҸ {len(not_found)} дҪҚж—Ҙе ұжңүдҪҶ DB жүҫдёҚеҲ°пјҡ{", ".join(not_found[:20])}{"..." if len(not_found)>20 else ""}</p>'

    debug_html = ""
    if debug_unparsed or debug_ignored:
        items = ""
        if debug_unparsed:
            items += "<p style='font-weight:600;color:#dc2626;margin:8px 0 4px'>вҡ пёҸ зңӢиө·дҫҶеғҸе®ўжҲ¶дҪҶиў«и·ійҒҺзҡ„иЎҢпјҲеүҚ 8 иЎҢпјүпјҡ</p><ul style='margin:0;padding-left:20px;font-family:monospace;font-size:12px'>"
            for u in debug_unparsed:
                items += f"<li>{h(u)}</li>"
            items += "</ul>"
        if debug_ignored:
            items += "<p style='font-weight:600;color:#6b7280;margin:8px 0 4px'>йқһе®ўжҲ¶/йқһ section зҡ„иЎҢпјҲеүҚ 8 иЎҢпјүпјҡ</p><ul style='margin:0;padding-left:20px;font-family:monospace;font-size:12px;color:#6b7280'>"
            for u in debug_ignored:
                items += f"<li>{h(u)}</li>"
            items += "</ul>"
        debug_html = f"<details style='margin-top:14px;background:#fef3c7;padding:10px;border-radius:6px'><summary style='cursor:pointer;font-weight:600'>рҹ”Қ и§Јжһҗ debug</summary>{items}</details>"

    if is_dry:
        action = f'''<form method="post" action="/admin/restore-from-report" style="margin-top:20px">
          <input type="hidden" name="group_id" value="{h(group_id)}">
          <input type="hidden" name="report_text" value="{h(text)}">
          <input type="hidden" name="dry" value="0">
          <button type="submit" onclick="return confirm('зўәе®ҡеҹ·иЎҢпјҹжңғиҰҶи“Ӣ {updated} зӯҶе®ўжҲ¶зҸҫжіҒ')"
            style="padding:10px 24px;font-size:15px;background:#b91c1c;color:#fff;border:none;border-radius:7px;cursor:pointer">
            вҡ пёҸ зўәиӘҚеҹ·иЎҢпјҲжӣҙж–° {updated} зӯҶпјү
          </button>
        </form>'''
    else:
        action = '<p style="color:#16a34a;margin-top:20px;font-weight:700">вң… еҹ·иЎҢе®ҢжҲҗ</p>'

    return HTMLResponse(f"""<!DOCTYPE html><html><head>{PAGE_CSS}<title>ж—Ҙе ұйӮ„еҺҹй җиҰҪ</title></head><body>
    {make_topnav(role, "restore-report")}
    <div class="page">
      <h2>ж—Ҙе ұйӮ„еҺҹ вҖ” {"й җиҰҪ" if is_dry else "е·Іеҹ·иЎҢ"}</h2>
      <p>и§ЈжһҗеҲ° {len(by_name)} дҪҚе®ўжҲ¶ / е°Үжӣҙж–° {updated} зӯҶ / жүҫдёҚеҲ° {len(not_found)} зӯҶ</p>
      <table style="width:100%;border-collapse:collapse;background:#fff;border:1px solid #e5e7eb;font-size:13px">
        <thead style="background:#f9fafb"><tr>
          <th style="padding:8px;text-align:left">е§“еҗҚ</th>
          <th style="padding:8px;text-align:left">current</th>
          <th style="padding:8px;text-align:left">concurrent</th>
          <th style="padding:8px;text-align:left">approved</th>
          <th style="padding:8px;text-align:left">ж’Ҙж¬ҫж—Ҙ</th>
          <th style="padding:8px;text-align:left">section</th>
          <th style="padding:8px;text-align:left">зӢҖж…Ӣ</th>
        </tr></thead>
        <tbody>{rows_html}</tbody>
      </table>
      {nf_html}
      {debug_html}
      {action}
      <p style="margin-top:14px"><a href="/admin/restore-from-report">еӣһиІјж–°ж—Ҙе ұ</a></p>
    </div></body></html>""")


@app.get("/admin/bulk-rollback", response_class=HTMLResponse)
def bulk_rollback(request: Request, group_id: str = "", minutes: str = "30",
                   before: str = "", dry: str = "1"):
    """жү№ж¬ЎйӮ„еҺҹжҢҮе®ҡзҫӨеңЁ cutoff д№ӢеҫҢиў«жӣҙж–°зҡ„е®ўжҲ¶еҲ°гҖҢcutoff д№ӢеүҚгҖҚзҡ„еҝ«з…§гҖӮ

    з”Ёжі•пјҲй җиҰҪпјүпјҡ
      /admin/bulk-rollback?group_id=...&minutes=20  # йӮ„еҺҹжңҖиҝ‘ 20 еҲҶйҗҳ
      /admin/bulk-rollback?group_id=...&before=19:41  # йӮ„еҺҹ 19:41 д№ӢеҫҢпјҲд»ҠеӨ©пјү
    еҹ·иЎҢпјҡеҠ  &dry=0
    """
    role = check_auth(request)
    if role != "admin":
        from fastapi.responses import RedirectResponse
        return RedirectResponse("/login")
    if not group_id:
        return HTMLResponse("<div style='padding:40px'>зјә group_id еҸғж•ё</div>")
    try:
        mins = int(minutes)
    except Exception:
        mins = 30
    is_dry = (dry != "0")
    from datetime import datetime as _dt, timedelta as _td
    # before еҸғж•ёпјҡжҢҮе®ҡйӮ„еҺҹзҡ„ cutoff жҷӮй–“пјҲHH:MMгҖҒд»ҠеӨ©пјүвҶ’ жҜ” minutes е„Әе…Ҳ
    if before and ":" in before:
        try:
            hh, mm = before.split(":")
            tw_now = _dt.now() + _td(hours=8)
            cutoff_dt = tw_now.replace(hour=int(hh), minute=int(mm), second=0, microsecond=0)
        except Exception:
            cutoff_dt = _dt.now() + _td(hours=8) - _td(minutes=mins)
    else:
        cutoff_dt = _dt.now() + _td(hours=8) - _td(minutes=mins)
    # DB зҡ„ updated_at ж јејҸжҳҜ "YYYY-MM-DD HH:MM:SS"пјҲз©әж јеҲҶйҡ”гҖҒдёҚжҳҜ Tпјү
    cutoff_iso = cutoff_dt.strftime("%Y-%m-%d %H:%M:%S")
    gname = get_group_name(group_id) or group_id[:8]

    rows_html = ""
    rolled = 0
    skipped = 0
    debug_info = ""
    with db_conn(commit=not is_dry) as conn:
        cur = conn.cursor()
        # жүҫжӯӨзҫӨжңҖиҝ‘ N еҲҶйҗҳжңүжӣҙж–°зҡ„е®ўжҲ¶
        cur.execute("""SELECT * FROM customers
                       WHERE source_group_id=? AND updated_at >= ?""", (group_id, cutoff_iso))
        affected = cur.fetchall()
        # debugпјҡжҠ“жң¬зҫӨжңҖиҝ‘ 5 зӯҶжӣҙж–°зңӢжҷӮй–“ж јејҸе°ҚдёҚе°Қ
        cur.execute("""SELECT customer_name, updated_at FROM customers
                       WHERE source_group_id=? ORDER BY updated_at DESC LIMIT 5""", (group_id,))
        recent_5 = cur.fetchall()
        debug_info = f"<pre style='background:#f3f4f6;padding:10px;font-size:12px'>"
        debug_info += f"дјәжңҚеҷЁжҷӮй–“ _dt.now() = {_dt.now()}\n"
        debug_info += f"еҠ  8 е°ҸжҷӮ (TW) cutoff = {cutoff_iso}\n"
        debug_info += f"now_iso() = {now_iso()}\n"
        debug_info += f"---\nжң¬зҫӨжңҖиҝ‘ 5 зӯҶжӣҙж–°пјҡ\n"
        for r in recent_5:
            debug_info += f"  {r['customer_name']}: {r['updated_at']}\n"
        debug_info += "</pre>"
        for c in affected:
            case_id = c["case_id"]
            name = c["customer_name"]
            # жүҫ cutoff д№ӢеүҚжңҖиҝ‘дёҖзӯҶ case_log еҗ« snapshot_json
            cur.execute("""SELECT snapshot_json FROM case_logs
                           WHERE case_id=? AND created_at < ? AND snapshot_json != ''
                           ORDER BY created_at DESC LIMIT 1""", (case_id, cutoff_iso))
            log = cur.fetchone()
            if not log or not log["snapshot_json"]:
                rows_html += f'<tr><td>{h(name)}</td><td colspan="5" style="color:#b91c1c">вқҢ жүҫдёҚеҲ° {mins} еҲҶйҗҳеүҚзҡ„ snapshot</td></tr>'
                skipped += 1
                continue
            try:
                snap = json.loads(log["snapshot_json"])
            except Exception:
                skipped += 1
                continue
            # еҲ—еҮәдё»иҰҒж¬„дҪҚи®ҠеҢ–
            cur_co_now = c["current_company"] or ""
            cur_co_old = snap.get("current_company") or ""
            sec_now = c["report_section"] or ""
            sec_old = snap.get("report_section") or ""
            amt_now = c["approved_amount"] or ""
            amt_old = snap.get("approved_amount") or ""
            rows_html += f'''<tr>
              <td style="padding:6px 10px;font-weight:600">{h(name)}</td>
              <td style="padding:6px 10px;font-size:11px">{h(cur_co_now)} вҶ’ {h(cur_co_old)}</td>
              <td style="padding:6px 10px;font-size:11px">{h(sec_now)} вҶ’ {h(sec_old)}</td>
              <td style="padding:6px 10px;font-size:11px">{h(amt_now)} вҶ’ {h(amt_old)}</td>
              <td style="padding:6px 10px;font-size:10px;color:#6b7280">{h(c["updated_at"])}</td>
            </tr>'''
            rolled += 1
            if not is_dry:
                # йӮ„еҺҹеҝ«з…§ж¬„дҪҚпјҲдёҖж¬Ўжӣҙж–°жүҖжңүж¬„дҪҚпјү
                _fields = ["current_company", "company", "route_plan", "concurrent_companies",
                           "report_section", "approved_amount", "approved_at",
                           "disbursement_date", "company_status", "last_update",
                           "status", "pending_docs", "notify_amount", "notify_period"]
                set_pieces = []
                vals = []
                for f in _fields:
                    if f in snap:
                        set_pieces.append(f"{f}=?")
                        vals.append(snap[f])
                if set_pieces:
                    set_pieces.append("updated_at=?")
                    vals.append(now_iso())
                    vals.append(case_id)
                    cur.execute(f"UPDATE customers SET {', '.join(set_pieces)} WHERE case_id=?", vals)

    action_btn = ""
    if is_dry:
        action_btn = f'''<form method="get" action="/admin/bulk-rollback" style="margin-top:20px">
          <input type="hidden" name="group_id" value="{h(group_id)}">
          <input type="hidden" name="minutes" value="{mins}">
          <input type="hidden" name="dry" value="0">
          <button type="submit" onclick="return confirm('зўәе®ҡйӮ„еҺҹ {rolled} зӯҶпјҹжӯӨж“ҚдҪңз„Ўжі• undo')"
            style="padding:10px 24px;font-size:15px;background:#b91c1c;color:#fff;border:none;border-radius:7px;cursor:pointer">
            вҡ пёҸ зўәиӘҚйӮ„еҺҹ {rolled} зӯҶ
          </button>
        </form>'''
    else:
        action_btn = '<p style="color:#16a34a;margin-top:20px;font-weight:700">вң… йӮ„еҺҹеҹ·иЎҢе®ҢжҲҗ</p>'

    return HTMLResponse(f"""<!DOCTYPE html><html><head>{PAGE_CSS}<title>жү№ж¬ЎйӮ„еҺҹ</title></head><body>
    {make_topnav(role, "admin")}
    <div class="page">
      <h2>жү№ж¬ЎйӮ„еҺҹ вҖ” {h(gname)}пјҲжңҖиҝ‘ {mins} еҲҶйҗҳе…§пјү</h2>
      <p style="color:#6b7280;font-size:13px">{"рҹҹЎ й җиҰҪжЁЎејҸпјҲdry=1гҖҒжңӘеҜҰйҡӣдҝ®ж”№пјү" if is_dry else "рҹ”ҙ е·Іеҹ·иЎҢ"}</p>
      <p>еҪұйҹҝ {len(affected)} зӯҶ / йӮ„еҺҹ {rolled} зӯҶ / и·ійҒҺ {skipped} зӯҶ</p>
      {debug_info}
      <table style="width:100%;border-collapse:collapse;background:#fff;border:1px solid #e5e7eb;font-size:13px">
        <thead style="background:#f9fafb"><tr>
          <th style="padding:8px;text-align:left">е§“еҗҚ</th>
          <th style="padding:8px;text-align:left">current_companyпјҲзҸҫвҶ’йӮ„еҺҹпјү</th>
          <th style="padding:8px;text-align:left">section</th>
          <th style="padding:8px;text-align:left">approved_amount</th>
          <th style="padding:8px;text-align:left">жңҖеҫҢжӣҙж–°</th>
        </tr></thead>
        <tbody>{rows_html}</tbody>
      </table>
      {action_btn}
    </div></body></html>""")


@app.get("/admin/inspect-customer", response_class=HTMLResponse)
def inspect_customer(request: Request, names: str = ""):
    """жҹҘжҢҮе®ҡе®ўжҲ¶зҸҫеңЁеңЁе“ӘеҖӢзҫӨзө„пјҲж•‘жҸҙз”ЁпјүгҖӮ
    з”Ёжі•пјҡ/admin/inspect-customer?names=йҚҫжҳҺзҺү,жһ—еҝ—йҙ»,иЁұи©©йӣ… ..."""
