@app.post("/admin/reset_data")
async def reset_data(request: Request):
    """
    жё…йҷӨжүҖжңүжё¬и©ҰиіҮж–ҷпјҲcustomers + case_logs + pending_actionsпјү
    зҫӨзө„иЁӯе®ҡдҝқз•ҷдёҚеӢ•гҖӮ
    йңҖиҰҒеё¶ {"confirm": "yes"} жүҚжңғеҹ·иЎҢпјҢйҒҝе…ҚиӘӨи§ёгҖӮ
    """
    role = check_auth(request)
    if role != "admin":
        return JSONResponse({"status": "error", "message": "з„Ўж¬Ҡйҷҗ"}, status_code=403)
    body = await request.json()
    if body.get("confirm") != "yes":
        return {"status": "error", "message": 'и«Ӣеё¶ {"confirm": "yes"} жүҚжңғеҹ·иЎҢжё…йҷӨ'}
    try:
        with db_conn(commit=True) as conn:
            cur = conn.cursor()
            cur.execute("DELETE FROM customers")
            cur.execute("DELETE FROM case_logs")
            cur.execute("DELETE FROM pending_actions")
            cur.execute("DELETE FROM sqlite_sequence WHERE name IN ('customers','case_logs','pending_actions')")
        return {"status": "ok", "message": "вң… е·Іжё…йҷӨжүҖжңүжЎҲд»¶иіҮж–ҷпјҢзҫӨзө„иЁӯе®ҡдҝқз•ҷ"}
    except Exception as e:
        return {"status": "error", "message": str(e)}


