VALID_GROUP_TYPES = {"SALES_GROUP", "ADMIN_GROUP", "A_GROUP", "UNASSIGNED"}

@app.post("/admin/add_group")
async def add_group(request: Request):
    """ж–°еўһзҫӨзө„ APIпјҲBug 3 дҝ®еҫ©пјҡйЎһеһӢ whitelist + йҳІиҰҶи“Ӣпјү

    Body: {group_id, group_name, group_type: SALES_GROUP/ADMIN_GROUP/A_GROUP}

    иЎҢзӮәпјҡ
    - иӢҘ group_id е·ІеӯҳеңЁ вҶ’ ж”№з”Ё UPDATE еҸӘжӣҙж–° name/type/linkedпјҢ**дҝқз•ҷ password_hash**
    - иӢҘдёҚеӯҳеңЁ вҶ’ INSERT ж–°зҫӨзө„
    - йЎһеһӢеҝ…й ҲеңЁ whitelist е…§пјҢеҗҰеүҮжӢ’зө•
    """
    role = check_auth(request)
    if role != "admin":
        return JSONResponse({"status": "error", "message": "з„Ўж¬Ҡйҷҗ"}, status_code=403)
    body = await request.json()
    gid = body.get("group_id", "").strip()
    gname = body.get("group_name", "").strip()
    gtype = body.get("group_type", "SALES_GROUP").strip()
    if not gid or not gname:
        return {"status": "error", "message": "group_id е’Ң group_name еҝ…еЎ«"}
    # Bug 3-1: йЎһеһӢ whitelist й©—иӯү
    if gtype not in VALID_GROUP_TYPES:
        return {"status": "error",
                "message": f"з„Ўж•Ҳзҡ„зҫӨзө„йЎһеһӢпјҡ{gtype}пјҲйңҖзӮә SALES_GROUP/ADMIN_GROUP/A_GROUPпјү"}
    linked = body.get("linked_sales_group_id", "").strip()
    linked_a = body.get("linked_a_group_id", "").strip()
    try:
        with db_conn(commit=True) as conn:
            cur = conn.cursor()
            # Bug 3-2: е…ҲжӘўжҹҘжҳҜеҗҰе·ІеӯҳеңЁ
            cur.execute("SELECT 1 FROM groups WHERE group_id=?", (gid,))
            existing = cur.fetchone()
            if existing:
                # е·ІеӯҳеңЁ вҶ’ UPDATE дёҚеӢ• password_hash е’Ң created_at
                cur.execute("""UPDATE groups
                    SET group_name=?, group_type=?, is_active=1, linked_sales_group_id=?, linked_a_group_id=?
                    WHERE group_id=?""",
                    (gname, gtype, linked or None, linked_a or None, gid))
                msg = f"е·Іжӣҙж–°зҫӨзө„пјҡ{gname}пјҲ{gtype}пјүвҖ” еҜҶзўјдҝқз•ҷдёҚеӢ•"
            else:
                # ж–°еўһ
                cur.execute("""INSERT INTO groups
                    (group_id,group_name,group_type,is_active,linked_sales_group_id,linked_a_group_id,created_at)
                    VALUES (?,?,?,1,?,?,?)""",
                    (gid, gname, gtype, linked or None, linked_a or None, now_iso()))
                msg = f"е·Іж–°еўһзҫӨзө„пјҡ{gname}пјҲ{gtype}пјүвҖ” и«ӢеҲ°гҖҢеҜҶзўјз®ЎзҗҶгҖҚиЁӯе®ҡеҜҶзўј"
            if linked:
                msg += f"пјҢе°ҚжҮүжҘӯеӢҷзҫӨпјҡ{get_group_name(linked)}"
            if linked_a:
                msg += f"пјҢе°ҚжҮү A зҫӨпјҡ{get_group_name(linked_a)}"
            return {"status": "ok", "message": msg}
    except Exception as e:
        return {"status": "error", "message": str(e)}



