import hashlib as _hl

def hash_pw(password: str) -> str:
    """еҜҶзўјйӣңж№Ҡ вҖ” дҪҝз”Ё PBKDF2-SHA256пјҢ20 иҗ¬ж¬Ў iterationпјҲBug 1 дҝ®еҫ©пјү"""
    import os as _os
    salt = _os.urandom(16).hex()
    dk = _hl.pbkdf2_hmac("sha256", password.encode(), bytes.fromhex(salt), 200_000)
    return f"pbkdf2$200000${salt}${dk.hex()}"

def verify_pw(password: str, stored: str) -> bool:
    """й©—иӯүеҜҶзўј вҖ” ж”ҜжҸҙж–°ж јејҸ PBKDF2 + иҲҠж јејҸ SHA-256пјҲеҗ‘еҫҢзӣёе®№пјү

    иҲҠеҜҶзўјиғҪз№јзәҢзҷ»е…ҘпјҢдҪҶ Web з«Ҝе»әиӯ°дёӢж¬Ўзҷ»е…ҘжҲҗеҠҹеҫҢйҮҚж–° hash еҚҮзҙҡгҖӮ
    дҪҝз”Ё hmac.compare_digest йҳІжҷӮеәҸж”»ж“ҠгҖӮ
    """
    if not stored:
        return False
    try:
        import hmac as _hmac
        # ж–°ж јејҸпјҡpbkdf2$iterations$salt$hash
        if stored.startswith("pbkdf2$"):
            _, iters, salt, hashed = stored.split("$", 3)
            dk = _hl.pbkdf2_hmac("sha256", password.encode(), bytes.fromhex(salt), int(iters))
            return _hmac.compare_digest(dk.hex(), hashed)
        # иҲҠж јејҸпјҡsalt:hashпјҲеҗ‘еҫҢзӣёе®№пјү
        if ":" in stored:
            salt, hashed = stored.split(":", 1)
            calc = _hl.sha256((salt + password).encode()).hexdigest()
            return _hmac.compare_digest(calc, hashed)
    except Exception:
        return False
    return False

def needs_pw_upgrade(stored: str) -> bool:
    """жӘўжҹҘеҜҶзўјжҳҜеҗҰзӮәиҲҠж јејҸпјҢйңҖиҰҒеҚҮзҙҡеҲ° PBKDF2"""
    return bool(stored) and not stored.startswith("pbkdf2$")

