def _ensure_sessions_table():
    """зўәдҝқ sessions иЎЁеӯҳеңЁпјҲзӣёе®№иҲҠзүҲ DBпјү"""
    try:
        conn = get_conn(); cur = conn.cursor()
        cur.execute("""CREATE TABLE IF NOT EXISTS sessions (
            token TEXT PRIMARY KEY NOT NULL,
            role TEXT NOT NULL,
            group_id TEXT DEFAULT '',
            created_at TEXT NOT NULL,
            expires_at TEXT NOT NULL
        )""")
        conn.commit(); conn.close()
    except Exception:
        pass


def _create_session(role: str, group_id: str = "") -> str:
    """з”ўз”ҹйҡЁж©ҹ session token дёҰеӯҳе…Ҙ DB"""
    from datetime import timedelta
    _ensure_sessions_table()
    token = secrets.token_urlsafe(32)
    now = now_iso()
    expires = (now_tw() + timedelta(days=7)).strftime("%Y-%m-%d %H:%M:%S")
    try:
        conn = get_conn(); cur = conn.cursor()
        cur.execute("INSERT INTO sessions (token,role,group_id,created_at,expires_at) VALUES (?,?,?,?,?)",
            (token, role, group_id, now, expires))
        conn.commit(); conn.close()
    except Exception as e:
        print(f"Session create error: {e}")
    return token


def _is_session_expired(expires_at_str) -> bool:
    """Bug 10: з”Ё datetime жҜ”ијғжҷӮй–“пјҢдёҚз”Ёеӯ—дёІжҜ”ијғ

    NULL/ж јејҸйҢҜиӘӨ вҶ’ иҰ–зӮәйҒҺжңҹпјҲе®үе…Ёй җиЁӯпјү
    """
    if not expires_at_str:
        return True
    try:
        expires = datetime.strptime(expires_at_str, "%Y-%m-%d %H:%M:%S")
        return expires < now_tw()
    except (ValueError, TypeError):
        return True


def _lookup_session(token: str) -> Optional[Dict]:
    """жҹҘжүҫ sessionпјҢеӣһеӮі {role, group_id} жҲ– None

    Bug 10/18 дҝ®еҫ©пјҡз”Ё datetime жҜ”ијғ + db_conn context manager йҳІйҖЈз·ҡжҙ©жјҸ
    """
    if not token:
        return None
    try:
        _ensure_sessions_table()
        with db_conn() as conn:
            cur = conn.cursor()
            cur.execute("SELECT role, group_id, expires_at FROM sessions WHERE token=?", (token,))
            row = cur.fetchone()
        if not row:
            return None
        # Bug 10: з”Ё datetime жҜ”ијғ
        if _is_session_expired(row["expires_at"]):
            # Bug 18: з”Ё db_conn зўәдҝқдҫӢеӨ–жҷӮйҖЈз·ҡжңғй—ң
            with db_conn(commit=True) as conn:
                cur = conn.cursor()
                cur.execute("DELETE FROM sessions WHERE token=?", (token,))
            return None
        return {"role": row["role"], "group_id": row["group_id"]}
    except Exception as e:
        print(f"Session lookup error: {e}")
        return None


def _delete_session(token: str):
    """зҷ»еҮәжҷӮеҲӘйҷӨ sessionпјҲBug 18: з”Ё db_conn йҳІйҖЈз·ҡжҙ©жјҸпјү"""
    if not token:
        return
    try:
        with db_conn(commit=True) as conn:
            cur = conn.cursor()
            cur.execute("DELETE FROM sessions WHERE token=?", (token,))
    except Exception as e:
        print(f"Session delete error: {e}")


