@app.post("/admin/delete_group")
async def delete_group(request: Request):
    role = check_auth(request)
    if role != "admin":
        return JSONResponse({"status":"error","message":"з„Ўж¬Ҡйҷҗ"}, status_code=403)
    data = await request.json()
    gid = (data.get("group_id") or "").strip()
    if not gid:
        return JSONResponse({"status":"error","message":"group_id еҝ…еЎ«"})
    try:
        conn = get_conn(); cur = conn.cursor()
        # е…ҲжӘўжҹҘжҳҜеҗҰжңүе®ўжҲ¶дҪҝз”ЁжӯӨзҫӨзө„пјҲжҸҗзӨәз”ЁгҖҒд»Қе…ҒиЁұеҲӘйҷӨпјү
        cur.execute("SELECT COUNT(*) AS n FROM customers WHERE source_group_id=?", (gid,))
        cust_cnt = cur.fetchone()["n"]
        cur.execute("DELETE FROM groups WHERE group_id=?", (gid,))
        conn.commit(); conn.close()
        msg = "е·ІеҲӘйҷӨ"
        if cust_cnt:
            msg += f"пјҲжіЁж„Ҹпјҡд»Қжңү {cust_cnt} зӯҶе®ўжҲ¶иіҮж–ҷеұ¬ж–јжӯӨзҫӨзө„пјү"
        return JSONResponse({"status":"ok","message":msg})
    except Exception as e:
        return JSONResponse({"status":"error","message":str(e)})


@app.post("/admin/update_group")
async def update_group(request: Request):
    role = check_auth(request)
    if role != "admin":
        return JSONResponse({"status":"error","message":"з„Ўж¬Ҡйҷҗ"}, status_code=403)
    data = await request.json()
    gid = data.get("group_id","").strip()
    gname = data.get("group_name","").strip()
    is_active = data.get("is_active", 1)
    linked_a = (data.get("linked_a_group_id","") or "").strip()
    if not gid or not gname:
        return JSONResponse({"status":"error","message":"зҫӨзө„IDе’ҢеҗҚзЁұеҝ…еЎ«"})
    try:
        conn = get_conn(); cur = conn.cursor()
        cur.execute("UPDATE groups SET group_name=?, is_active=?, linked_a_group_id=? WHERE group_id=?",
            (gname, is_active, linked_a or None, gid))
        conn.commit(); conn.close()
        return JSONResponse({"status":"ok","message":f"е·Іжӣҙж–°пјҡ{gname}"})
    except Exception as e:
        return JSONResponse({"status":"error","message":str(e)})


@app.get("/admin/locked-accounts")
async def get_locked_accounts(request: Request):
    role = check_auth(request)
    if role != "admin":
        return JSONResponse({"ok": False, "locked": []})
    conn = get_conn(); cur = conn.cursor()
    cur.execute("SELECT identifier, attempts, locked_until FROM login_attempts WHERE locked_until > ? ORDER BY locked_until DESC",
        (now_iso(),))
    rows = cur.fetchall(); conn.close()
    locked = [{"identifier": r["identifier"], "attempts": r["attempts"],
               "locked_until": r["locked_until"][11:16] if r["locked_until"] else ""} for r in rows]
    return JSONResponse({"ok": True, "locked": locked})


@app.post("/admin/unlock-account")
async def unlock_account(request: Request):
    role = check_auth(request)
    if role != "admin":
        return JSONResponse({"ok": False, "message": "з„Ўж¬Ҡйҷҗ"})
    data = await request.json()
    identifier = data.get("identifier","").strip()
    if not identifier:
        return JSONResponse({"ok": False, "message": "identifier еҝ…еЎ«"})
    conn = get_conn(); cur = conn.cursor()
    cur.execute("DELETE FROM login_attempts WHERE identifier=?", (identifier,))
    conn.commit(); conn.close()
    return JSONResponse({"ok": True, "message": f"е·Іи§ЈйҺ–пјҡ{identifier}"})


