    if not role: return RedirectResponse("/login")
    form = await request.form()
    f = dict(form)
    name = f.get("cname","").strip()
    id_no = f.get("idno","").strip().upper()
    phone = f.get("phone","").strip().replace("-","").replace(" ","")
    email = f.get("email","").strip()
