@app.get("/customer-pdf-batch", response_class=HTMLResponse)
def customer_pdf_batch(request: Request, ids: str = ""):
    from fastapi.responses import RedirectResponse
    role = check_auth(request)
    if not role: return RedirectResponse("/login")
    id_list = [i.strip() for i in (ids or "").split(",") if i.strip()]
    if not id_list:
        return RedirectResponse("/pending-customers")
    conn = get_conn(); cur = conn.cursor()
    placeholders = ",".join(["?"] * len(id_list))
    cur.execute(f"SELECT * FROM customers WHERE case_id IN ({placeholders})", id_list)
    rows = cur.fetchall(); conn.close()
    # дҫқдҪҝз”ЁиҖ…йҒёеҸ–й ҶеәҸжҺ’еәҸ
    row_map = {dict(r)["case_id"]: dict(r) for r in rows}
    ordered = [row_map[i] for i in id_list if i in row_map]
    if not ordered:
        return RedirectResponse("/pending-customers")

    bodies = []
    for idx, r in enumerate(ordered):
        if idx > 0:
            bodies.append('<div style="page-break-before:always;"></div>')
        bodies.append(_build_customer_pdf_body(r))
    body_html = "".join(bodies)

    # з¬¬дёҖзӯҶе®ўжҲ¶е§“еҗҚз•¶жӘ”еҗҚ
    first_name = (ordered[0].get("customer_name") or "е®ўжҲ¶иіҮж–ҷ").strip()
    if len(ordered) > 1:
        pdf_filename = f"{first_name}зӯү{len(ordered)}зӯҶе®ўжҲ¶иіҮж–ҷ.pdf"
    else:
        pdf_filename = f"{first_name}_е®ўжҲ¶иіҮж–ҷ.pdf"

    return f"""<!DOCTYPE html><html lang="zh-TW"><head><meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>е®ўжҲ¶иіҮж–ҷжү№ж¬ЎеҲ—еҚ°пјҲ{len(ordered)} зӯҶпјү</title>
{_PDF_STYLE}
<script src="https://cdnjs.cloudflare.com/ajax/libs/html2pdf.js/0.10.1/html2pdf.bundle.min.js"></script>
</head><body>
<div class="no-print" style="text-align:center;margin-bottom:16px;">
  <button id="pdf-btn" onclick="downloadPDF()" style="background:#4e7055;color:#fff;border:none;padding:10px 28px;border-radius:6px;font-size:14px;cursor:pointer;font-weight:600;">дёӢијү PDFпјҲе…ұ {len(ordered)} зӯҶпјү</button>
  <button onclick="window.close()" style="background:#6a5e4e;color:#fff;border:none;padding:10px 28px;border-radius:6px;font-size:14px;cursor:pointer;font-weight:600;margin-left:8px;">й—ңй–ү</button>
</div>
<div id="pdf-wrap">
<div id="pdf-content">
{body_html}
</div>
</div>
<script>
function downloadPDF() {{
  var btn = document.getElementById('pdf-btn');
  var originalText = btn.innerText;
  if (typeof html2pdf === 'undefined') {{
    window.print();
    return;
  }}
  btn.disabled = true;
  btn.innerText = 'з”ўз”ҹдёӯпјҢи«ӢзЁҚеҖҷвҖҰ';
  btn.style.opacity = '0.6';
  btn.style.cursor = 'wait';
  var element = document.getElementById('pdf-content');
  var opt = {{
    margin: 0,
    filename: {json.dumps(pdf_filename, ensure_ascii=False)},
    image: {{ type: 'jpeg', quality: 0.95 }},
    html2canvas: {{
      scale: 2, useCORS: true, letterRendering: true, backgroundColor: '#ffffff',
      scrollX: 0, scrollY: -window.scrollY,
      onclone: function(doc) {{
        var el = doc.getElementById('pdf-content');
        if (el) {{
          el.style.margin = '0';
          el.style.position = 'static';
          el.style.left = '0';
          el.style.transform = 'none';
        }}
        doc.body.style.padding = '0';
        doc.body.style.margin = '0';
        doc.body.style.background = '#fff';
        doc.documentElement.style.margin = '0';
        doc.documentElement.style.padding = '0';
      }}
    }},
    jsPDF: {{ unit: 'mm', format: 'a4', orientation: 'portrait' }},
    pagebreak: {{ mode: ['css', 'legacy'] }}
  }};
  var ua = navigator.userAgent || '';
  var isMobile = /iPhone|iPad|iPod|Android|Line/i.test(ua);
  var resetBtn = function() {{
    btn.disabled = false;
    btn.innerText = originalText;
    btn.style.opacity = '1';
    btn.style.cursor = 'pointer';
  }};
  var worker = html2pdf().from(element).set(opt);
  if (isMobile) {{
    worker.toPdf().get('pdf').then(function(pdf) {{
      var blob = pdf.output('blob');
      var url = URL.createObjectURL(blob);
      var opened = window.open(url, '_blank');
      if (!opened) {{ window.location.href = url; }}
      resetBtn();
    }}).catch(function(err) {{
      console.error('PDF з”ўз”ҹеӨұж•—пјҡ', err);
      alert('PDF з”ўз”ҹеӨұж•—пјҡ' + (err && err.message ? err.message : err));
      resetBtn();
    }});
  }} else {{
    worker.save().then(resetBtn).catch(function(err) {{
      console.error('PDF з”ўз”ҹеӨұж•—пјҡ', err);
      alert('PDF з”ўз”ҹеӨұж•—пјҢж”№з”ЁзҖҸиҰҪеҷЁеҲ—еҚ°еҠҹиғҪ');
      window.print();
      resetBtn();
    }});
  }}
}}
</script>
</body></html>"""


