@app.get("/admin/templates", response_class=HTMLResponse)
def admin_templates_page(request: Request):
    role = check_auth(request)
    if role not in ("admin", "adminB"):
        from fastapi.responses import RedirectResponse
        return RedirectResponse("/login", status_code=303)

    qs = str(request.url.query or "")
    flash = ""
    if "ok=1" in qs:
        flash = '<div style="background:#dcfce7;color:#15803d;padding:10px 14px;border-radius:6px;font-size:13px;margin-bottom:16px;">вң… зҜ„жң¬е·ІдёҠеӮідёҰеҘ—з”ЁгҖӮдёӢж¬ЎдёӢијүз”іи«ӢжӣёжңғдҪҝз”Ёж–°зҜ„жң¬гҖӮ</div>'
    elif "reset=1" in qs:
        flash = '<div style="background:#e0f2fe;color:#075985;padding:10px 14px;border-radius:6px;font-size:13px;margin-bottom:16px;">вҶ©пёҸ е·ІйӮ„еҺҹзӮәзі»зөұе…§е»әзҜ„жң¬гҖӮ</div>'
    elif "err=" in qs:
        _em = re.search(r"err=([^&]+)", qs)
        _msg = _em.group(1) if _em else "дёҠеӮіеӨұж•—"
        try:
            from urllib.parse import unquote
            _msg = unquote(_msg)
        except Exception:
            pass
        flash = f'<div style="background:#fef2f2;color:#dc2626;padding:10px 14px;border-radius:6px;font-size:13px;margin-bottom:16px;">вқҢ {h(_msg)}</div>'

    _base = os.path.dirname(os.path.abspath(__file__))
    rows_html = []
    # иЁҳйҢ„е·ІйЎҜзӨәйҒҺзҡ„жӘ”еҗҚпјҲдәһеӨӘж©ҹи»Ҡ15иҗ¬/25иҗ¬е…ұз”ЁдёҖд»Ҫе…§е»әпјүпјҢйҒҝе…ҚйҮҚиӨҮиӘӘжҳҺ
    for plan_name, builtin_file in APPLICATION_PLAN_LIST:
        custom_path = get_custom_template_path(plan_name)
        has_custom = os.path.isfile(custom_path)
        builtin_path = os.path.join(_base, "з”іи«Ӣжӣё", builtin_file)
        builtin_exists = os.path.isfile(builtin_path)

        mapping_path = get_template_mapping_path(plan_name)
        has_mapping = os.path.isfile(mapping_path)
        inherited_src = "" if has_mapping else get_inherited_mapping_source(plan_name)
        if has_mapping:
            mapping_badge = '<span style="background:#dcfce7;color:#15803d;padding:1px 8px;border-radius:8px;font-size:11px;margin-left:4px;">е·ІиЁӯе®ҡжҳ е°„</span>'
        elif inherited_src:
            mapping_badge = f'<span style="background:#fef3c7;color:#92400e;padding:1px 8px;border-radius:8px;font-size:11px;margin-left:4px;">з№јжүҝгҖҢ{h(inherited_src)}гҖҚ</span>'
        else:
            mapping_badge = '<span style="background:#f3f4f6;color:#6b7280;padding:1px 8px;border-radius:8px;font-size:11px;margin-left:4px;">жңӘиЁӯе®ҡжҳ е°„</span>'

        if has_custom:
            st = os.stat(custom_path)
            status_badge = '<span style="background:#dcfce7;color:#15803d;padding:2px 10px;border-radius:10px;font-size:12px;font-weight:500;">в—Ҹ иҮӘиЁӮзҜ„жң¬</span>' + mapping_badge
            size_kb = max(1, st.st_size // 1024)
            updated = datetime.fromtimestamp(st.st_mtime).strftime("%Y-%m-%d %H:%M")
